insert into public.qas
  (doctor_id, type, category, status, published,
   question, answer, keywords,
   post_year, post_slug, external_url, pubmed_ref,
   created_at, updated_at)
values
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$팔꿈치 무릎 색소침착에도 멜라토닝크림을 발라도 되나요?$AAQ$, $AAA$팔꿈치나 무릎, 복숭아뼈 부위의 색소침착에는 **멜라토닝크림이 효과가 없습니다.** 이 부위는 잦은 마찰 때문에 피부가 두꺼워져서 생기는 형태의 색소침착이라, 색소 자체를 좋아지게 하는 연고는 거의 효과가 없기 때문입니다.

이런 부위에는 유리아크림이나 투앤티크림처럼 **각질 탈락의 주기를 빠르게 해주는 레티노이드·유리아 성분 연고**를 권해 드려요. 각질을 빨리 떨어뜨려서 피부가 좀 더 부드럽고 하얗게 밝아지는 효과를 기대할 수 있습니다. 사용 방법은 짜서 바르고 싶은 부위에 충분히 펴 발라주시면 되고, 마치 새살이 돋아나 밝아지는 듯한 변화가 나타납니다. 다만 두꺼워진 피부 자체가 바뀌는 데는 시간이 필요하니 꾸준히 발라주시는 게 중요해요.$AAA$, array['팔꿈치색소침착', '무릎색소침착', '유리아크림', '투앤티크림', '각질연고']::text[], 2024, 'NXJcg3O86GA-1', 'https://youtu.be/NXJcg3O86GA?t=154s', null, '2024-07-02 00:00:00+00'::timestamptz, '2024-07-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$멜라토닝크림은 어떻게 바르고 부작용은 없나요?$AAQ$, $AAA$멜라토닝크림은 **하루 한 번 저녁에만 바르는 것이 안전합니다.** 안에 들어있는 하이드로퀴논 성분이 자외선과 만나면 오히려 색소침착이 생기는 부작용이 나타날 수 있기 때문에 사용 시간이 중요해요.

사용 방법은 저녁에 씻고 스킨케어를 마친 뒤 가장 마지막에 신경 쓰이는 색소침착 부위에만 톡톡 발라주시면 됩니다. 하루 한 번만 바르는 게 권장량이고, 다음 날 외출 전에는 **자외선 차단제를 반드시 함께 발라주는 것이 핵심**입니다. 한 번 발라서 하루만에 좋아지지는 않지만, 안 바르는 것보다는 분명히 도움이 됩니다. 갈색·검정색에 가까운 여드름 자국이나 상처 후 색소침착에 잘 맞고, 피부과 토닝 시술을 받기 전에 먼저 시도해 볼 만한 옵션이에요.$AAA$, array['멜라토닝크림', '하이드로퀴논', '색소침착', '사용법', '자외선차단']::text[], 2024, 'NXJcg3O86GA-2', 'https://youtu.be/NXJcg3O86GA?t=99s', null, '2024-07-02 00:00:00+00'::timestamptz, '2024-07-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아토피로 인한 목 색소침착에는 뭘 발라야 하나요?$AAQ$, $AAA$아토피 피부염 때문에 생긴 목·팔 오금·무릎 오금 부위의 색소침착에는 **보습제만 자주 발라주시는 게 가장 좋습니다.** 이 경우 멜라토닝크림이나 유리아크림을 바르면 오히려 피부가 자극되어 아토피가 악화될 수 있기 때문이에요.

보습제는 하루에 5번, 10번 자주 발라도 상관이 없어서 특히 안 좋은 부위에 **수시로 넓게 펴 발라 주시는 게 가장 권장됩니다.** 색소침착 자체를 빼는 연고보다 염증을 가라앉히고 피부 장벽을 회복시키는 게 우선이라 판단하기 때문입니다. 다만 같은 목 색소침착이라도 아토피와 무관한 경우가 있어 정확한 진단이 필요한 부분이에요. 본인이 아토피 피부염 때문에 색소침착이 생긴 게 확실하다면 연고보다 보습제를 많이 쓰시는 것을 권해 드려요.$AAA$, array['아토피색소침착', '보습제', '목색소침착', '팔오금', '피부장벽']::text[], 2024, 'NXJcg3O86GA-3', 'https://youtu.be/NXJcg3O86GA?t=222s', '{"pmid": "31690388", "doi": "10.2500/aap.2019.40.4265", "title": "Atopic dermatitis.", "journal": "Allergy Asthma Proc", "year": "2019", "authors_short": "Peters N, Peters AT", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/31690388/", "doi_url": "https://doi.org/10.2500/aap.2019.40.4265"}'::jsonb, '2024-07-02 00:00:00+00'::timestamptz, '2024-07-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 흉터의 붉은 자국에는 어떤 연고가 좋나요?$AAQ$, $AAA$여드름 흉터가 아직 붉은 기로 남아있을 때는 **노스카나겔 같은 흉터 연고가 더 도움이 됩니다.** 색깔이 어두워지기 전 단계에서는 색소를 빼는 연고보다 흉터 연고가 더 적합하기 때문이에요.

사용은 단순합니다. 여드름 자국이 붉게 남아 있는 부위에 **하루 다섯 번, 여섯 번 정도 수시로 발라주시면 좋아요.** 그렇게 관리하다가 자국이 점차 까매지면 그때부터는 멜라토닝크림으로 바꿔서 발라주시는 게 적합합니다. 또 색소침착이 너무 깊고 오래되어 홈케어로 잘 좋아지지 않을 때는 피부과의 레이저토닝을 고려할 수 있는데, 1~2회 시술로 끝나는 게 아니라 일반적으로 10번에서 20번, 30번까지도 받게 됩니다. 시술 전에 자국의 상태에 맞는 홈케어를 먼저 해보시는 것을 권해 드려요.$AAA$, array['여드름흉터', '노스카나겔', '붉은자국', '흉터연고', '레이저토닝']::text[], 2024, 'NXJcg3O86GA-4', 'https://youtu.be/NXJcg3O86GA?t=342s', '{"pmid": "30027914", "doi": "10.4103/ijdvl.IJDVL_1086_16", "title": "Optimizing Q-switched lasers for melasma and acquired dermal melanoses.", "journal": "Indian J Dermatol Venereol Leprol", "year": "2019", "authors_short": "Aurangabadkar SJ", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/30027914/", "doi_url": "https://doi.org/10.4103/ijdvl.IJDVL_1086_16"}'::jsonb, '2024-07-02 00:00:00+00'::timestamptz, '2024-07-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$등드름 가드름은 어떤 폼클렌저로 씻어야 좋아지나요?$AAQ$, $AAA$등드름과 가드름에는 **살리실릭 애시드 0.5%가 들어 있는 폼클렌저**로 씻는 것이 가장 효과적입니다. 이 성분이 들어 있는지는 폼클렌저의 전성분을 확인해 보시면 알 수 있고, 여드름성 피부용 클렌저에는 대부분 포함되어 있어요.

살리실릭 애시드는 BHA 성분으로 **모공 속 피지 청소, 모공을 막는 각질 탈락, 염증 감소까지 세 가지 작용을 한 번에 합니다.** 사용 시 한 가지 팁이 있는데, 거품을 문지르고 바로 헹구지 말고 약 5분 정도 그대로 두었다가 씻어내야 모공 속에 성분이 작용할 시간이 생겨 효과가 더 좋아져요. 만약 본인 클렌저에 이 성분이 없다면 세정력이 좋은 약알칼리성 클렌저로 씻는 것도 좋은 대안입니다. 얼굴에 쓰기엔 건조해서 안 쓰는 제품이라도 가슴이나 등에는 활용해 보시는 걸 권해 드려요.$AAA$, array['등드름', '가드름', '살리실릭애시드', 'BHA', '폼클렌저']::text[], 2024, 'SgJAZC_KNM8-1', 'https://youtu.be/SgJAZC_KNM8?t=86s', null, '2024-07-09 00:00:00+00'::timestamptz, '2024-07-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$클리어틴 같은 의약품과 화장품 클렌저는 어떻게 다른가요?$AAQ$, $AAA$**클리어틴은 살리실릭 애시드가 2%까지 들어 있는 일반의약품**이라 0.5%가 한계인 화장품·클렌저와 농도부터 다릅니다. 처방전 없이 약국에서 구매할 수 있고, 화장품으로 효과를 못 본 분들이 다음 단계로 고려해 볼 옵션이에요.

우리나라에서 화장품이나 클렌저에 들어갈 수 있는 살리실릭 애시드 최대 농도는 0.5%로 정해져 있는데, 클리어틴은 의약품 분류라 2%까지 함유합니다. 클렌저나 토너로 효과가 부족했던 분들은 클리어틴을 사서 **여드름이 나는 부위에 톡톡 찍어 바르는 점 도포 방식**으로 활용해 보세요. 다만 농도가 높은 만큼 효과가 강할 수 있어 넓게 펴 바르면 피부가 뒤집어질 수 있으니 좁은 부위에만 발라야 합니다. 화장품과 의약품은 사용 농도와 강도 차이가 있기 때문에 단계적으로 접근하시는 게 적합해요.$AAA$, array['클리어틴', '살리실릭애시드', '일반의약품', '농도차이', '여드름점도포']::text[], 2024, 'SgJAZC_KNM8-2', 'https://youtu.be/SgJAZC_KNM8?t=309s', null, '2024-07-09 00:00:00+00'::timestamptz, '2024-07-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$등드름 자국 색소침착에는 뭘 바르는 게 좋나요?$AAQ$, $AAA$등드름 염증이 가라앉은 뒤 남는 붉은 자국이나 색소침착에는 **나이아신아마이드 성분 세럼이 가장 적합합니다.** 이 성분 하나로 색소침착 완화, 염증·붉은기 진정, 피지 감소까지 한 번에 잡을 수 있어 여드름 흔적 관리에 잘 맞아요.

디오디너리 나이아신아마이드 같은 제품은 함량도 높고 용량 대비 가격이 저렴해 **넓은 등이나 앞가슴에 부담 없이 바르기 좋습니다.** 보조로 집에 레티놀이 있다면 자국 부위에 발라보세요. 레티놀은 각질을 빨리 탈락시켜서 거기에 묻어 있는 색소를 떨어뜨리는 효과가 있어 도움이 됩니다. 다만 일부러 새로 살 필요는 없고 가지고 있을 때 활용하시면 돼요. 손으로 뜯으면 자국이 빨갛게 남고 색소침착이 심하게 남기 때문에 보이는 부위에 났을 때는 여드름 패치로 보호하시는 것도 도움이 됩니다.$AAA$, array['등드름자국', '나이아신아마이드', '색소침착', '레티놀', '여드름패치']::text[], 2024, 'SgJAZC_KNM8-3', 'https://youtu.be/SgJAZC_KNM8?t=384s', null, '2024-07-09 00:00:00+00'::timestamptz, '2024-07-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$샤워 순서가 등드름과 어떤 관련이 있나요?$AAQ$, $AAA$등드름 관리에서는 **머리를 먼저 감고 몸을 나중에 씻는 순서가 중요합니다.** 헤어 제품 속 모공을 막을 수 있는 성분이 피부에 남으면 등드름과 가드름의 원인이 되기 때문이에요.

우리가 쓰는 헤어 제품들은 머릿결을 부드럽고 윤기 있게 만들어야 해서 **실리콘이나 오일 같은 성분이 들어갈 수밖에 없는 구조입니다.** 이런 성분이 등이나 가슴에 남아 있게 되면 모공을 막아 여드름을 유발해요. 그래서 머리를 먼저 감은 뒤 몸을 씻어 잔여 성분을 깨끗이 흘려 보내 주는 게 좋습니다. 헤어 제품을 쓰고 나서 등드름이 많이 난다고 느끼는 분들은 머리를 감을 때 몸을 숙여서 감아 제품이 피부에 닿지 않게 하는 게 베스트예요. 이런 홈케어를 다 했는데도 좋아지지 않으면 세균성 모낭염이나 곰팡이균 감염일 수 있어 피부과 전문의 진료를 권해 드립니다.$AAA$, array['샤워순서', '헤어제품', '실리콘', '모낭염', '등드름원인']::text[], 2024, 'SgJAZC_KNM8-4', 'https://youtu.be/SgJAZC_KNM8?t=438s', null, '2024-07-09 00:00:00+00'::timestamptz, '2024-07-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$무기자차 선크림은 폼클렌징으로만 씻어도 되나요?$AAQ$, $AAA$무기자차 선크림은 **폼클렌징으로만 씻어내선 안 되고 반드시 이중세안이 필요합니다.** 무기자차의 원료는 돌을 잘게 빻은 돌가루이고, 발림성을 위해 실리콘과 오일을 넣어 만들기 때문에 피부에 막을 형성해 잘 씻기지 않아요.

실제 50배율 확대경 실험에서도 폼클렌징만 사용한 경우엔 **각질 사이사이에 선크림 잔여물이 그대로 남아 있는 모습이 확인되었습니다.** 이 돌가루들이 제대로 제거되지 않으면 모공을 막아 피지와 땀이 배출되지 않고 피부 트러블의 원인이 될 수 있어요. 그래서 무기자차 선크림은 오일이나 밀크로 1차 세안을 해 주시고, 폼클렌징으로 2차 세안까지 꼭 진행해야 합니다. 백탁이 뜨거나 무기자차라고 적힌 제품일수록 꼼꼼히 씻어내는 게 중요해요.$AAA$, array['무기자차', '이중세안', '선크림세안', '클렌징오일', '백탁']::text[], 2024, 'Xm8HiMrS9QA-1', 'https://youtu.be/Xm8HiMrS9QA?t=93s', null, '2024-07-16 00:00:00+00'::timestamptz, '2024-07-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아이들 선크림 세안은 어떻게 해야 하나요?$AAQ$, $AAA$아이들의 경우 이중세안이 어렵기 때문에 **이지워시라고 표기된 선크림을 선택하는 게 가장 적합합니다.** 이지워시는 말 그대로 쉽게 씻을 수 있도록 만들어진 제품으로, 1차 세안만으로도 선크림이 잘 씻겨 나가요.

이지워시 제품은 선크림 성분에 수용성 코팅을 하거나 유화제를 첨가해서 만들기 때문에 **폼클렌징 한 번으로도 말끔히 지워지는 점이 가장 큰 장점**입니다. 로션 제형이라 발랐을 때 수분감이 있고 잘 발려 아이들이 사용하기에도 부담이 적어요. 다만 찾아보면 대부분 SPF가 32 정도로 낮은 편이라 실내 활동이 많거나 민감성 피부에 더 잘 맞고, 야외 활동이 많은 어린아이들에게는 자주 덧발라 주시는 것을 권해 드립니다. 5살 자녀에게도 순하고 잘 씻겨서 무리 없이 사용 중이에요.$AAA$, array['이지워시선크림', '아이선크림', 'SPF32', '수용성코팅', '유화제']::text[], 2024, 'Xm8HiMrS9QA-2', 'https://youtu.be/Xm8HiMrS9QA?t=269s', null, '2024-07-16 00:00:00+00'::timestamptz, '2024-07-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$민감성 피부도 매일 이중세안을 해야 하나요?$AAQ$, $AAA$민감성 피부는 매일 이중세안이 부담스러울 수 있어 **클렌징 밀크와 클렌징 젤 조합으로 자극을 줄이는 방법**을 권해 드려요. 클렌징 밀크로 1차 유분기를 제거하고, 클렌징 젤로 남은 잔여물을 제거하는 순서입니다.

클렌징 젤은 **자극이 적고 수분감 있게 마무리되는 특성이 있어** 피부 장벽이 약한 분도 부담 없이 사용할 수 있어요. 실제로 이 조합으로 세안했을 때도 잔여물이 말끔히 씻겨진 것이 확인됐습니다. 또 폼클렌징을 사용할 때 거품을 충분히 만들지 않은 상태로 씻으면 아무리 순한 제품이라도 피부에 자극이 갈 수 있어요. 본인 클렌징 폼을 짜낸 후 충분히 거품을 만든 상태에서 롤링하시는 것이 중요합니다. 거품 없이 사용했다가 피부염이 생긴 경험도 있으니 이 부분은 꼭 지켜 주세요.$AAA$, array['민감성피부', '클렌징밀크', '클렌징젤', '이중세안', '거품세안']::text[], 2024, 'Xm8HiMrS9QA-3', 'https://youtu.be/Xm8HiMrS9QA?t=351s', null, '2024-07-16 00:00:00+00'::timestamptz, '2024-07-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 피부에는 어떤 선크림이 잘 맞나요?$AAQ$, $AAA$여드름 피부에는 **수분감이 많은 선크림이나 이지워시 제품**이 가장 잘 맞습니다. 여드름 피부가 선크림을 바를 때 트러블이 올라오는 이유는 선크림 자체가 오일리하기 때문이에요.

유분기가 많은 선크림을 제대로 씻어내지 않으면 잔여물이 **모공을 막고 결국 여드름을 유발하는 경로로 작용합니다.** 반면 수분감이 많은 선크림은 발랐을 때 오일 성분이 적게 남아서 모공을 막을 확률이 줄어들어요. 또 이지워시 제품은 1차 세안만으로도 깨끗하게 씻기기 때문에 잔여물 걱정이 덜합니다. 평소 트러블이 잦은 분이라면 이 두 가지 방향 중 하나를 선택하시는 게 적합해요. 그리고 어떤 선크림을 쓰든 발랐다면 오일 성분이 포함된 클렌저로 1차 세안 후 폼클렌징으로 2차 세안하는 원칙은 동일하게 지켜 주시는 게 좋습니다.$AAA$, array['여드름피부선크림', '수분감선크림', '이지워시', '트러블', '모공막힘']::text[], 2024, 'Xm8HiMrS9QA-4', 'https://youtu.be/Xm8HiMrS9QA?t=380s', null, '2024-07-16 00:00:00+00'::timestamptz, '2024-07-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모공 좋아지려고 뜨거운 물·찬물 세안하면 도움이 되나요?$AAQ$, $AAA$모공을 위해 뜨거운 물로 열었다가 찬물로 조여 주는 세안은 **지금 당장 중단해야 하는 잘못된 습관입니다.** 모공을 자꾸 열었다 닫았다 하며 자극을 주면 오히려 더 도드라져 보일 수 있고, 모공을 가만히 쉬게 두는 편이 훨씬 낫습니다.

또 하나 고쳐야 할 습관은 **코팩이나 각질팩으로 묵은 피지를 물리적으로 떼어 내는 방식**입니다. 이런 방법도 모공을 자극해 더 도드라져 보이게 만들거나 늘어지게 만들 수 있어요. 모공에 쌓인 묵은 각질이나 때는 클렌징 오일이나 클렌징 밀크 같은 기름 제형으로 살살 녹여서 제거하는 게 적합합니다. 세안 시에는 물로 바로 헹구지 말고 물을 묻혀 롤링하며 유화 과정을 거친 뒤, 물로 헹구고 마지막에 클렌징 폼으로 한 번 더 씻어내야 합니다. 이 순서가 모공 관리의 기본이에요.$AAA$, array['모공세안', '뜨거운물찬물', '코팩', '유화과정', '클렌징오일']::text[], 2024, 'hIFc2zY_vNs-1', 'https://youtu.be/hIFc2zY_vNs?t=84s', null, '2024-07-23 00:00:00+00'::timestamptz, '2024-07-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피지가 많은 모공과 노화 세로 모공은 어떻게 다른가요?$AAQ$, $AAA$**피지 모공은 분비가 왕성해 생기고, 세로 모공은 탄력이 떨어져 늘어지면서 생기는 점이 본질적인 차이**입니다. 원인이 다르기 때문에 케어 방향도 달라져야 해요.

피지 분비가 왕성한 지성 피부 타입은 얼굴이 기름지거나 여드름이 많고 귤 껍질처럼 모공이 큰 특징이 있습니다. 이런 분들에게는 **피지 분비를 말려 주는 효서 세안제와 살리실산 토너로 필링하는 케어**가 도움이 됩니다. 반면 세로 모공은 노화로 인해 탄력이 떨어지면서 모공이 밑으로 늘어진 형태인데, 어릴 때는 거의 보이지 않다가 나이가 들면서 슬슬 나타나는 케이스가 많아요. 이런 노화성 모공에는 비타민C 제품 같은 것이 효과가 있고, 모공 발달 자체가 많은 분들은 레티놀 제품을 매일 써주시는 것도 좋습니다. 내 모공이 어떤 타입인지 먼저 파악한 뒤 그에 맞는 성분을 고르시는 게 핵심이에요.$AAA$, array['피지모공', '세로모공', '노화모공', '살리실산', '레티놀']::text[], 2024, 'hIFc2zY_vNs-2', 'https://youtu.be/hIFc2zY_vNs?t=169s', null, '2024-07-23 00:00:00+00'::timestamptz, '2024-07-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$노화 세로 모공에는 어떤 시술이 효과가 있나요?$AAQ$, $AAA$노화로 늘어진 세로 모공에는 **얕은 팁으로 시술하는 울쎄라가 가장 효과적입니다.** 깊은 팁은 근막을 자극해 리프팅을 하지만, 얕은 팁으로 모공 주변에 집중 시술하면 모공이 좁아지면서 리프팅되는 변화를 만들어 줘요.

울쎄라는 보통 시술 후 1~2달은 지나야 효과가 나타나는데, **모공 부분은 1~2주만 지나도 바로 효과가 나타나는 속도감이 있는 점**이 특징입니다. 슈링크라는 비슷한 장비도 팁만 잘 사용하면 좋은 효과를 낼 수 있어요. 다만 피지 분비가 왕성한 타입의 모공에는 골드PTT나 니들RF처럼 피지 분비를 줄이는 시술이 잘 맞고, 늘어진 세로 모공에는 이런 시술은 별로 도움이 되지 않습니다. 모공은 시술만으로 완전히 없앨 수 없는 구조물이라 홈케어와 병행하는 것이 적합하며, 효과가 크지 않을 것 같은 분들께는 시술 대신 홈케어만 권하기도 합니다.$AAA$, array['세로모공', '울쎄라모공팁', '슈링크', '골드PTT', '니들RF']::text[], 2024, 'hIFc2zY_vNs-3', 'https://youtu.be/hIFc2zY_vNs?t=372s', null, '2024-07-23 00:00:00+00'::timestamptz, '2024-07-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여름과 겨울 모공 홈케어 루틴은 어떻게 다르게 해야 하나요?$AAQ$, $AAA$여름과 겨울은 피지 분비량이 달라서 **계절별로 사용하는 성분을 바꿔 주는 것이 적합합니다.** 여름엔 살리실산 토너와 비타민C 위주로, 겨울엔 레티놀 제품 위주로 가는 게 기본 방향이에요.

여름철에는 T존이 번들거리고 기름이 많이 끼기 때문에 **살리실산이 들어있는 토너를 T존 위주로 바르고, CE페룰릭을 양 볼 위주로 도포한 뒤 가벼운 로션을 덧바르는 루틴**을 사용 중입니다. 또 너무 꾸덕한 크림류는 차라리 바르지 말고 스킨이나 토너만 바르는 게 나을 때도 있어요. 겨울철에는 피지 분비가 적고 건조해지기 때문에 비타민C 앰플 사용은 줄이고 투앤티크림 같은 레티놀 제품으로 전환하시는 게 좋습니다. 다만 이런 성분들은 약간의 자극감을 줄 수 있어 여러 제품을 한꺼번에 섞어 바르지 말고, 잘 모를 땐 하루에 한 가지만 쓰거나 번갈아 사용하는 편이 안전합니다.$AAA$, array['여름모공케어', '겨울모공케어', 'CE페룰릭', '투앤티크림', '계절별루틴']::text[], 2024, 'hIFc2zY_vNs-4', 'https://youtu.be/hIFc2zY_vNs?t=257s', null, '2024-07-23 00:00:00+00'::timestamptz, '2024-07-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$데오드란트와 약국 땀억제제는 어떻게 다른가요?$AAQ$, $AAA$**데오드란트의 원래 용도는 땀 억제가 아닌 땀 냄새 제거이고, 약국템은 본격적으로 땀을 막는 제품인 점이 본질적인 차이**입니다. 두 제품 모두 알루미늄 화합물을 쓰지만 억제하는 정도의 차이가 커요.

데오드란트에는 땀 냄새를 잡기 위해 **항균 작용을 하는 트리클로산과 향료가 들어가는 경우가 많습니다.** 요즘 제품에는 땀을 줄이는 성분도 대부분 들어 있지만, 땀이 많은 분의 겨터파크를 막기에는 효과가 부족할 수 있어요. 반면 약국템은 염화알루미늄이 주요 성분으로, 땀과 만나 침전물을 만들어 땀샘을 직접 막아주는 원리입니다. 실제 실험에서도 데오드란트를 바른 쪽보다 드리클로 같은 약국템을 바른 쪽이 확실히 땀 억제가 더 잘 된 모습이 확인됐어요. 땀이 많지 않고 냄새가 신경 쓰이면 데오드란트, 겨터파크가 열릴 정도면 약국템을 사용하시는 게 적합합니다.$AAA$, array['데오드란트', '드리클로', '염화알루미늄', '트리클로산', '땀억제']::text[], 2024, 'RT1T05Ns1AY-1', 'https://youtu.be/RT1T05Ns1AY?t=192s', null, '2024-07-30 00:00:00+00'::timestamptz, '2024-07-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$데오드란트 사용 후 색소침착이 생길 수 있나요?$AAQ$, $AAA$데오드란트의 향료가 알레르기 접촉 피부염을 일으키고, **긁고 난 자리에 거뭇거뭇한 색소침착이 남을 수 있습니다.** 화장품 중에서도 데오드란트가 향료로 인한 알레르기 접촉 피부염을 가장 많이 일으킨다는 보고가 있어요.

또한 데오드란트의 항균 성분인 **트리클로산은 갑상선이나 생식 호르몬의 불균형을 일으킬 수 있다는 가능성이 제기된 성분**이라 사용을 점점 줄이는 추세입니다. 그래서 향료와 트리클로산이 들어 있지 않은 제품을 고르는 게 안전한데, 크리스탈 데오드란트 스틱형은 암모늄알룸 단일 성분으로 되어 있어 무난합니다. 다만 알루미늄 화합물이 기본이라 자극이 있을 수 있고 클렌징이 제대로 안 되면 문제가 생길 수 있어요. 외출하고 돌아오면 꼭 바로 씻어내 주셔야 합니다. 간지럽거나 따가웠던 경험이 있다면 성분을 다시 확인해 보시는 게 좋아요.$AAA$, array['데오드란트색소침착', '트리클로산', '향료알레르기', '암모늄알룸', '접촉피부염']::text[], 2024, 'RT1T05Ns1AY-2', 'https://youtu.be/RT1T05Ns1AY?t=169s', null, '2024-07-30 00:00:00+00'::timestamptz, '2024-07-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$약국 땀억제제 사용 시 주의사항이 있나요?$AAQ$, $AAA$약국 땀억제제는 **반드시 물기를 잘 말리고 자기 전에 발라야 하며, 상처나 제모 직후엔 사용을 피해야 합니다.** 염화알루미늄 성분이 물과 만나면 염산을 생성하기 때문에 사용 조건이 중요해요.

첫째, 샤워 후 물기를 잘 닦지 않고 바르면 **피부가 너무 따갑고 화끈거리는 자극이 생길 수 있고**, 성분이 잘 스며들도록 낮보다는 땀이 나지 않는 밤이나 자기 전에 바르는 게 좋습니다. 둘째, 겨드랑이에 상처가 있을 때는 다 아물 때까지 중단하고, 제모 후엔 적어도 12시간 이상의 간격을 두어야 합니다. 셋째, 아침에 일어나서 겨드랑이 부분을 잘 닦아 주세요. 성분이 남으면 옷을 변색시킬 수 있어요. 만약 약국템까지 다 써봤는데 효과가 부족하거나 자극·알러지로 사용할 수 없다면 4~6개월 효과가 지속되는 겨드랑이 보톡스 시술을 고려해 볼 수 있고, 1년에 한 번 5~6월에 받으면 여름을 뽀송하게 보낼 수 있어요.$AAA$, array['약국템주의사항', '염화알루미늄', '제모간격', '겨드랑이보톡스', '사용방법']::text[], 2024, 'RT1T05Ns1AY-3', 'https://youtu.be/RT1T05Ns1AY?t=402s', null, '2024-07-30 00:00:00+00'::timestamptz, '2024-07-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$민감한 사람은 어떤 농도 약국템부터 써야 하나요?$AAQ$, $AAA$민감하거나 처음 사용하는 분은 **염화알루미늄 12% 농도의 노스엣센스나 스웨티브센스부터 시작하는 것이 적합합니다.** 농도가 낮을수록 효과는 덜할 수 있지만 피부 자극을 줄이는 게 우선이기 때문이에요.

약국템은 농도별로 나뉘는데 **드리클로·노스엣·스웨클로·데오클렌은 염화알루미늄 20% 제품**이고, 노스엣센스·스웨티브센스는 12% 제품입니다. 20% 제품 중에서도 드리클로와 노스엣은 알코올이 들어 있어 빨리 마르지만 약간 자극이 있을 수 있고, 스웨클로와 데오클렌은 알코올이 없어 자극은 덜하지만 건조에 시간이 걸린다는 단점이 있어요. 드리클로를 썼는데 자극이 심해서 못 쓴 분이나 처음 약국템을 사용해 보는 민감한 분들은 12% 제품을 먼저 사용해 보시는 게 좋습니다. 본인 피부에 발랐을 때 문제가 생기지 않는 것이 가장 중요해요.$AAA$, array['염화알루미늄12%', '노스엣센스', '스웨티브센스', '드리클로', '민감성피부']::text[], 2024, 'RT1T05Ns1AY-4', 'https://youtu.be/RT1T05Ns1AY?t=361s', null, '2024-07-30 00:00:00+00'::timestamptz, '2024-07-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈 밑 꺼짐에 콜라겐 크림을 바르면 좋아지나요?$AAQ$, $AAA$눈 밑 꺼짐에 콜라겐 크림을 바르는 것은 **효과가 없습니다.** 눈 밑이 꺼지는 현상은 피부 안 다양한 구조물의 변화로 생기는 것이라 크림으로 잔주름은 모르겠지만 꺼짐 자체를 개선하기는 어렵기 때문이에요.

눈 밑 꺼짐은 크게 두 가지 원인으로 나눌 수 있습니다. **눈 밑을 지지하는 인대가 노화로 힘이 떨어져 지방이 불룩하게 보이는 돌출형**과, 눈 주변 뼈가 선천적으로 발달이 미약해 앞볼이 더 아래로 쑥 꺼져 보이는 형태가 있어요. 후자의 경우 눈 밑 지방과 인대는 다 잘 있는데도 그 밑이 꺼져서 다크서클이나 퀭한 인상으로 보입니다. 진료실에 "다크서클이 있어요"라고 오시는 분들 중 실제로는 눈 밑이 정상이고 그 아래 앞볼이 꺼진 경우가 많아요. 어느 쪽이든 크림으로는 구조적 변화를 만들 수 없어 시술적 접근이 필요합니다.$AAA$, array['눈밑꺼짐', '콜라겐크림', '눈밑지방', '다크서클', '앞볼꺼짐']::text[], 2024, 'PhkRbs0d8gA-1', 'https://youtu.be/PhkRbs0d8gA?t=49s', null, '2024-08-06 00:00:00+00'::timestamptz, '2024-08-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈 밑 꺼짐에 쥬베룩 볼륨 시술은 왜 추천하지 않나요?$AAQ$, $AAA$눈 밑 꺼짐에 쥬베룩 볼륨 시술을 추천하지 않는 이유는 **콜라겐이 차오르는 양을 정확히 예측할 수 없고, 눈 밑 피부가 얇아 결절이 생기면 비쳐 보이는 부작용**이 있을 수 있기 때문이에요.

첫째, 쥬베룩 볼륨은 한 번의 시술로 좋아지지 않습니다. 보통 **최소 한 달 간격으로 세 번 이상 시술해야 하고**, 그렇게 해도 어느 정도의 콜라겐이 얼마큼 차오를지 정확히 알 수 없어요. 눈 밑은 굉장히 좁은 위치에 작은 포인트만 정확히 시술해야 하는데, 콜라겐이 원하는 양보다 더 많이 또는 적게 차오르면 인상이 크게 달라집니다. 둘째, 눈 밑은 피부가 굉장히 얇아 작은 결절이 생기면 피부에 너무 많이 비쳐 보이는 부작용이 생길 수 있어요. 거의 대부분 이런 부작용이 생기지는 않지만, 한 번 생기면 굉장히 골치 아픈 부작용이라 신중하게 접근하고 있습니다.$AAA$, array['쥬베룩볼륨', '눈밑꺼짐', '결절', '콜라겐부스터', '부작용']::text[], 2024, 'PhkRbs0d8gA-2', 'https://youtu.be/PhkRbs0d8gA?t=147s', null, '2024-08-06 00:00:00+00'::timestamptz, '2024-08-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈 밑 필러는 어디에 어떻게 시술해야 하나요?$AAQ$, $AAA$눈 밑 필러는 **눈 바로 밑이 아니라 앞 광대나 앞 볼 쪽에 소량만 주입하는 것이 가장 자연스럽습니다.** 많은 분들이 눈 밑이 꺼졌으니 눈 바로 아래에 시술해야 한다고 생각하지만 사실은 다릅니다.

정확히는 눈 바로 밑이 아니라 **그보다 좀 더 아래쪽인 앞 광대나 앞 볼 쪽에 시술해야 훨씬 더 자연스럽고 예쁘게 교정**됩니다. 필러는 보통 1cc가 들어있는데, 꼭 1cc를 다 넣을 필요는 절대 없고 딱 필요한 만큼만 살짝 넣어 모양만 교정하는 게 중요해요. 너무 과한 양을 넣으면 얼굴이 어색해질 수 있어 소량 교정 후 시간을 두고 부족하면 다시 소량으로 보강하는 방식을 선호합니다. 양 자체가 적게 들어가기 때문에 필러가 이동하거나 시간이 지나 녹아 부자연스러워지는 부작용도 별로 없어요. 선천적으로 후퇴해서 발달한 형태의 눈 밑 꺼짐에는 볼륨감을 채우는 필러가 가장 좋습니다.$AAA$, array['눈밑필러', '앞광대', '앞볼', '소량교정', '필러시술']::text[], 2024, 'PhkRbs0d8gA-3', 'https://youtu.be/PhkRbs0d8gA?t=247s', null, '2024-08-06 00:00:00+00'::timestamptz, '2024-08-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈 밑 꺼짐에 울쎄라나 써마지도 도움이 되나요?$AAQ$, $AAA$**눈 밑 인대 힘이 떨어져 지방이 불룩하게 튀어나오는 돌출형에는 울쎄라나 써마지가 단연 효과가 좋습니다.** 인대에 힘을 보강할 수 있는 시술이기 때문에 이 타입에 잘 맞아요.

눈 밑 꺼짐은 원인에 따라 시술이 달라져야 합니다. **노화로 인대 힘이 약해져 지방이 불룩해진 경우엔 울쎄라·써마지로 인대를 보강**해 주는 게 적합하고, 선천적으로 발달 자체가 후퇴한 형태에는 볼륨감을 채워주는 필러가 가장 좋습니다. 그래서 "눈 밑이 꺼졌으니까 유명한 시술을 받을래", "유명한 리프팅을 할래" 식으로 접근하기보다는 실제로 본인의 상태가 어떤지를 먼저 파악해야 해요. 내 눈 밑이 진짜 꺼진 건지, 오히려 지방이 불룩한 건지, 꺼진 위치가 눈 밑이 아니라 그 아래쪽인지에 따라 그에 맞는 시술을 받으시는 것이 적합합니다.$AAA$, array['울쎄라눈밑', '써마지눈밑', '인대보강', '눈밑지방돌출', '리프팅']::text[], 2024, 'PhkRbs0d8gA-4', 'https://youtu.be/PhkRbs0d8gA?t=319s', null, '2024-08-06 00:00:00+00'::timestamptz, '2024-08-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$순수 비타민C와 비타민C 유도체는 어떻게 다른가요?$AAQ$, $AAA$**순수 비타민C는 효과가 강하지만 자극도 강하고, 비타민C 유도체는 자극이 적은 대신 효과가 약한 점이 본질적인 차이**입니다. 성분표에서 아스코빅애씨드라고 적혀 있으면 순수 비타민C, ___아스코빌이라고 적힌 게 있으면 유도체입니다.

순수 비타민C는 항산화 효과와 미백효과, 콜라겐 생성에 효과적이지만 **pH 산도가 낮아서 따가울 수 있고, 농도가 높을수록 자극이 심합니다.** 또 안정성이 낮아 빛과 열에 취약해 쉽게 산화되기 때문에 갈색병에 담겨 있어요. 비교해 보면 오늘 개봉한 제품은 하얗게, 3~4개월 전 개봉한 제품은 노랗게 산화된 모습이 보입니다. 반면 비타민C 유도체는 순수 비타민C의 단점을 보완해 빛과 열에 안정적이고 자극이 적어 민감한 피부에도 수월합니다. 다만 피부에 흡수된 후 비타민C로 전환되는 과정이 필요해 효과는 상대적으로 적을 수밖에 없어요.$AAA$, array['순수비타민C', '비타민C유도체', '아스코빅애씨드', '아스코빌', '산화']::text[], 2024, 'ub0dxrymg7o-1', 'https://youtu.be/ub0dxrymg7o?t=72s', null, '2024-08-09 00:00:00+00'::timestamptz, '2024-08-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$예민한 피부가 순수 비타민C에 적응하는 방법이 있나요?$AAQ$, $AAA$예민한 피부도 단계적으로 접근하면 순수 비타민C를 사용할 수 있습니다. **낮은 농도부터 시작하고, 크림에 한두 방울 섞어 바르며, 3일에 한 번부터 빈도를 늘리는 세 가지 방법**을 함께 활용하면 도움이 돼요.

첫째, 낮은 농도의 비타민C 앰플부터 사용해 서서히 농도를 올려야 합니다. 둘째, **마지막에 바르는 크림에 한두 방울 섞어 바르다가 사용량을 조금씩 늘려 4~5방울까지** 늘리는 방식이에요. pH가 낮을 때 흡수가 잘 되어 효과는 떨어지지만 자극을 줄일 수 있습니다. 셋째, 처음엔 3일에 한 번 저녁에만 사용하고 2~3주 정도 이상이 없으면 이틀에 한 번으로 늘려요. 또 비타민A 성분과 같이 쓰면 자극이 있을 수 있어 격일로 사용하거나 아침엔 비타민C, 저녁엔 비타민A로 나눠 쓰시는 게 적합합니다. 기미가 있는 분은 처음엔 기미 없는 부위에 먼저 발라 자극이 없는지 확인 후 얼굴 전체에 적용하세요.$AAA$, array['순수비타민C적응', '예민한피부', '농도조절', '크림혼합', '비타민A병용']::text[], 2024, 'ub0dxrymg7o-2', 'https://youtu.be/ub0dxrymg7o?t=411s', null, '2024-08-09 00:00:00+00'::timestamptz, '2024-08-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$민감성 피부에 맞는 비타민C 유도체 제품은 어떤 게 있나요?$AAQ$, $AAA$민감성 피부에는 **비타 나이아신 잡티 세럼, 주닥 히알루이드 C 수딩 앰플, 더마팩토리 나이아신 트라넥삼산 13% 세럼** 세 가지를 단계별로 활용해 볼 수 있어요. 모두 비타민C 유도체인 에칠아스코빌에텔이 포함된 제품들입니다.

비타 나이아신 잡티 세럼은 37가지 성분에 비타민C 유도체 4가지와 미백 기능성 성분이 함께 들어 있고, **30ml에 29,000원으로 부담이 적습니다.** 주닥 히알루이드 C 수딩 앰플은 28가지 성분이며 히알루론산이 여러 종류 들어 있어 건조한 피부에 잘 맞아요. 30ml에 68,000원으로 가장 비싸지만 보습감이 좋습니다. 더마팩토리 제품은 25가지 성분으로 30ml에 8,000원이라 가성비가 좋지만, **나이아신아마이드 10% 고함량 때문에 예민한 분은 따끔거리거나 붉어질 수 있는 점은 참고해 주세요.** 모든 제품이 알레르기 유발 가능성이 높은 성분을 배제했지만 개인 반응은 다를 수 있어요.$AAA$, array['비타나이아신', '주닥히알루이드C', '더마팩토리', '에칠아스코빌에텔', '민감성앰플']::text[], 2024, 'ub0dxrymg7o-3', 'https://youtu.be/ub0dxrymg7o?t=167s', null, '2024-08-09 00:00:00+00'::timestamptz, '2024-08-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C 유도체와 순수 비타민C를 함께 쓰는 루틴은 어떻게 짜야 하나요?$AAQ$, $AAA$예민한 피부의 경우 **아침에는 비타민C 유도체 앰플을, 저녁에는 격일로 순수 비타민C와 비타민A를 번갈아 쓰는 방식**이 적합합니다. 자극을 분산시키면서도 효과 성분을 꾸준히 활용할 수 있어요.

구체적으로 보면 **이틀에 한 번 정도 저녁에 순수 비타민C 앰플을 사용**하고, 그 외 저녁엔 비타민A 제품을 발라요. 매일 아침엔 자극이 적은 비타민C 유도체 앰플로 항산화와 미백 케어를 이어 갑니다. 피부 상태가 좋은 날에는 세안 직후 순수 비타민C를 바를 수 있지만, 컨디션이 안 좋은 날엔 모든 활성 성분을 중단하고 판테놀 앰플이나 세콜지가 들어간 보습제로 피부 장벽을 회복시키는 게 우선이에요. 다시 피부가 건강해진 후 원래 루틴으로 돌아갑니다. 이 방식은 효과적 측면에서는 효율성이 떨어질 수 있지만 예민한 분들이 적응할 수 있도록 도와주기 위한 방법이라는 점을 참고해 주세요.$AAA$, array['비타민C루틴', '비타민A병용', '아침저녁분리', '판테놀', '피부장벽회복']::text[], 2024, 'ub0dxrymg7o-4', 'https://youtu.be/ub0dxrymg7o?t=540s', null, '2024-08-09 00:00:00+00'::timestamptz, '2024-08-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기름이 많은 피부에 적합한 클렌징 루틴은 어떻게 되나요?$AAQ$, $AAA$기름이 많은 피부에는 아침 약산성 클렌저, 저녁 이중 세안 그리고 주 3회 효소 클렌저를 권해 드립니다. 아침에는 피부 pH와 유사한 약산성 수딩폼 워시로 부드럽게 세안하고, 메이크업을 한 저녁에는 클렌징 워터로 1차, BHA·RHA가 포함된 **약알칼리성 제품으로 2차 세안**을 합니다.

주 3회 정도는 효소 클렌저로 3차 세안까지 마무리하는데, 단백질 분해와 피지 흡착 기능이 있어 매끈한 피부결을 만들어 줍니다. 다만 **피부 장벽이 무너져 따갑고 건조하고 붉은 분은 효소 클렌저와 약알칼리성 제품 모두 금지**이며, 증상이 가라앉을 때까지 약산성 클렌저로만 세안해야 합니다. 오일 클렌저는 모공을 더 막고 잘 씻겨나가지 않아 트러블을 유발할 수 있으니 1차 세안제로는 권하지 않습니다.$AAA$, array['지성피부클렌징', '약산성클렌저', '이중세안', '효소클렌저', 'BHA클렌저']::text[], 2024, '3URwM6zw35I-1', 'https://youtu.be/3URwM6zw35I?t=154s', null, '2024-08-14 00:00:00+00'::timestamptz, '2024-08-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성 피부에 무거운 보습 크림을 발라도 되나요?$AAQ$, $AAA$지성 피부에는 건성·아토피용 무거운 크림 대신 기름은 잡고 보습은 유지하는 가벼운 제품 하나만으로 충분합니다. 모공에서 이미 기름을 계속 만들어내고 있기 때문에 무거운 제품을 바르면 모공을 막고 유분기가 더 심해질 수 있어요.

반대로 보습을 전혀 안 하면 **수분이 부족해서 오히려 유분을 더 많이 만들어내므로**, 피부 장벽을 보호할 정도의 보습은 반드시 해야 합니다. 토너로 모공 정리를 가볍게 한 뒤 기름을 잡으면서 보습감을 주는 로션 한 가지로 마무리하는 것이 핵심입니다. 가벼운 모이스처 라인은 산뜻하지만 보습이 덜 되어 허전할 수 있고, **기름은 잡되 좋은 성분이 피부 깊숙이 침투하는 보습감을 동시에 주는 제품이 적합합니다**. 트러블이 있고 예민하면서 기름까지 있는 분에게도 같은 원칙이 적용됩니다.$AAA$, array['지성피부보습', '수분부족지성', '가벼운로션', '피부장벽보습', '유분조절']::text[], 2024, '3URwM6zw35I-2', 'https://youtu.be/3URwM6zw35I?t=129s', null, '2024-08-14 00:00:00+00'::timestamptz, '2024-08-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C와 디페린 겔은 언제 어떻게 발라야 하나요?$AAQ$, $AAA$비타민C는 아침 로션 전에, 디페린 겔은 저녁 로션 후에 코·이마·나비존에 소량 바르는 것이 기본 원칙입니다. 아침에는 미백과 항노화 작용을 하는 비타민C 제품을 로션 전 단계에 바르고, 저녁에는 로션을 먼저 바른 뒤 노화를 막아주는 **디페린 겔을 소량 바릅니다**.

**디페린 겔은 처방이 필요한 전문 의약품**이라는 점을 반드시 알고 계셔야 합니다. 또 비타민C와 디페린 겔 모두 자극을 줄 수 있는 성분이라, **피부가 현재 예민해서 붉고 따갑고 건조한 분은 피부 장벽이 모두 회복된 후에 천천히 조합해서 사용**해야 합니다. 장벽이 무너진 상태에서 무리하게 더하면 자극으로 트러블이 생길 수 있으니, 회복이 우선이고 그 다음 단계적으로 도입하는 순서를 지켜주세요.$AAA$, array['비타민C도포', '디페린겔', '전문의약품', '미백항노화', '피부장벽회복']::text[], 2024, '3URwM6zw35I-3', 'https://youtu.be/3URwM6zw35I?t=425s', null, '2024-08-14 00:00:00+00'::timestamptz, '2024-08-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성 피부에 잘 맞는 선크림은 어떤 제품인가요?$AAQ$, $AAA$지성 피부에는 매트한 마무리감의 무기자차 선크림이 가장 적합합니다. 화장을 안 하면 오후에 기름이 더 올라오기 때문에 선크림으로 막을 한 번 쳐주는 것이 도움이 되는데, 문제는 대부분의 선크림이 유분기가 많아 바른 직후부터 피부가 번들거린다는 점이에요.

그래서 **매트하고 무기자차인 선크림**을 선택하는 것이 핵심입니다. 적당한 백탁 현상으로 톤이 환해지면서 일종의 막을 형성해 기름이 덜 올라오게 도와줘서, **하루 종일 뽀송뽀송한 화사함을 유지할 수 있어요**. 별도 약속이 없으면 톤업 화장 대신 이 한 제품만으로 마무리하는 것도 가능합니다. 다만 제품 자체보다 매트하고 무기자차라는 계열을 참고해 본인 피부에 맞는 제품을 고르면 됩니다.$AAA$, array['지성선크림', '무기자차', '매트선크림', '백탁현상', '유분조절선크림']::text[], 2024, '3URwM6zw35I-4', 'https://youtu.be/3URwM6zw35I?t=463s', null, '2024-08-14 00:00:00+00'::timestamptz, '2024-08-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$동안 피부를 위해 보습이 왜 그렇게 중요한가요?$AAQ$, $AAA$보습은 피부 장벽 강화와 속광 형성이라는 두 가지 효과로 동안의 핵심을 만듭니다. 단순히 촉촉함만 주는 것이 아니라, **피부 장벽을 강화시켜주는 역할**을 해서 외부 자극에 잘 베이거나 까지지 않게 도와줘요.

속광은 보습의 결과로 생기는 현상이에요. 피부 표면이 건조하면 빛이 들어왔을 때 난반사가 많이 일어나 칙칙해 보이는데, 보습이 잘 되면 난반사가 줄어 은은한 광채가 돕니다. 반지를 폴리싱하면 다시 반짝이는 것과 같은 원리예요. 그래서 **피부에서 광이 나는 사람들은 보습을 아주 잘 챙기고 있는 분들**이라고 보면 됩니다. 본인 피부에 잘 맞는 보습력 좋은 로션이나 크림을 듬뿍 발라주는 것이 동안 피부 관리의 첫 번째 키워드입니다.$AAA$, array['보습', '피부장벽', '속광', '동안피부', '난반사']::text[], 2024, '91SYaW-Z23c-1', 'https://youtu.be/91SYaW-Z23c?t=76s', null, '2024-08-20 00:00:00+00'::timestamptz, '2024-08-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$더미오케어와 LDM 시술은 어떤 효과가 있나요?$AAQ$, $AAA$더미오케어는 음이온을 활용한 시술이고 LDM은 초음파 잔떨림 시술로, 두 시술 모두 보습과 피부 진정에 효과적입니다. 더미오케어는 음이온이 나오는 시술로, 숲이나 계곡에서 느끼는 힐링 감각을 시술로 받을 수 있다고 생각하면 돼요. 한 번 받는 데 **5만원 정도이며 일주일에 한두 번 꾸준히 받기 좋습니다**.

LDM은 피부에 아주 잔떨림을 주는 초음파 치료로, **보습력을 강화하고 속건조를 해결하며 염증을 줄이고 피부 장벽을 재생시켜 줍니다**. 두 시술의 궁합이 잘 맞아서 함께 받는 것을 권하는 편입니다. 다만 효과에는 개인차가 있어 한 번에 큰 변화를 기대하기보다 꾸준히 받는 것이 중요해요. 첫 번째 키워드인 보습과 결을 같이 하는 관리라고 보면 됩니다.$AAA$, array['더미오케어', 'LDM', '초음파시술', '음이온', '속건조']::text[], 2024, '91SYaW-Z23c-2', 'https://youtu.be/91SYaW-Z23c?t=223s', null, '2024-08-20 00:00:00+00'::timestamptz, '2024-08-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$동안 피부에서 탄력은 어떻게 관리해야 하나요?$AAQ$, $AAA$동안 피부의 핵심은 탄력이며, 진피층의 콜라겐과 엘라스틴을 공략하는 시술이 가장 효과적입니다. 크림이나 홈 디바이스가 탄력에 **10정도의 도움을 준다면 시술은 100정도의 도움을 준다**고 말할 수 있어요.

탄력은 진피층에 있는 콜라겐, 엘라스틴 같은 섬유질을 공략해야 개선되기 때문에, 표면적 관리만으로는 한계가 있습니다. 본격적인 탄력 시술은 38~39살부터 받기 시작했고, 처음 받은 시술은 써마지였어요. **써마지·세르프·덴서티·텐써마 같은 고주파 시술을 위주로 받았고**, 고주파 시술은 피부를 건강하게 만드는 효과가 있습니다. 턱 라인까지 갸름하게 하고 싶다면 울쎄라 같은 초음파 시술을 병합하면 더 좋고, 즉각적인 물광 효과를 원하면 바늘 고주파와 물광 주사를 함께 하는 더블타이트도 권합니다.$AAA$, array['탄력시술', '고주파', '써마지', '울쎄라', '콜라겐엘라스틴']::text[], 2024, '91SYaW-Z23c-3', 'https://youtu.be/91SYaW-Z23c?t=346s', null, '2024-08-20 00:00:00+00'::timestamptz, '2024-08-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$동안 피부 관리는 몇 살부터 시작하는 게 좋은가요?$AAQ$, $AAA$동안 피부 관리는 30대부터 시작해도 충분히 효과를 볼 수 있고, 핵심은 꾸준함입니다. 10대·20대부터 관리하면 더 좋겠지만, **30대 또는 그 이상부터 시작해도 5년에서 10년 정도 뒤** 주변에서 가장 젊어 보이는 효과를 누릴 수 있어요.

중요한 건 노화가 365일 24시간 내내 진행되기 때문에, **세월에 대한 반항도 계속 해줘야 한다는 점**입니다. 한 번 받고 효과가 없다고 포기하면 안 되고, 효과를 한 번에 못 느끼는 게 당연한 거예요. 보습·항노화·항산화·탄력이라는 세 가지 축을 꾸준히 관리하면 자연스럽고 우아하게 나이 들 수 있습니다. 효과에는 개인차가 있지만, 시작하는 시점이 늦었다고 포기할 이유는 없습니다.$AAA$, array['동안관리시작', '30대피부관리', '노화예방', '꾸준한관리', '항노화']::text[], 2024, '91SYaW-Z23c-4', 'https://youtu.be/91SYaW-Z23c?t=444s', null, '2024-08-20 00:00:00+00'::timestamptz, '2024-08-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$사람마다 체취가 다른 이유는 무엇인가요?$AAQ$, $AAA$체취는 땀과 피부 세균이 만나 만들어지며, 사람마다 땀 성분·세균·식습관이 달라 다른 냄새가 납니다. 원래 땀 자체는 냄새가 없지만, 피부에 있는 세균이 땀을 분해하면서 그때 냄새가 발생해요.

피부에는 **에크린 땀샘과 아포크린 땀샘** 두 종류가 있어요. 에크린 땀샘은 두피부터 손끝 발끝까지 전신에 있어 더울 때 땀이 나고, 아포크린 땀샘은 겨드랑이 같은 특정 부위에만 분포해 더 진하고 탁한 땀을 분비합니다. 그래서 **아포크린 땀샘의 땀이 분해되면 더 지독한 냄새가 나고** 겨드랑이 냄새가 다른 부위와 다른 이유가 됩니다. 개인마다 분비되는 땀 성분, 보유 세균, 식습관, 생활습관, 스트레스가 모두 다르기 때문에 사람마다 체취가 달라요. 후각이 사람보다 1만 배 예민한 개는 이 차이로 사람을 구분할 수 있습니다.$AAA$, array['체취원인', '에크린땀샘', '아포크린땀샘', '겨드랑이냄새', '땀세균']::text[], 2024, '0yPA_qnzUuQ-1', 'https://youtu.be/0yPA_qnzUuQ?t=160s', null, '2024-08-22 00:00:00+00'::timestamptz, '2024-08-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$한국인이 외국인보다 체취가 약한 게 사실인가요?$AAQ$, $AAA$한국인은 체취를 결정하는 ABCC11 유전자에서 A타입 비율이 거의 100%에 가까워 유전적으로 체취가 약합니다. 몸에서 나는 냄새를 결정하는 유전자에는 A타입과 G타입이 있는데, **A타입이면 체취가 거의 안 나고 G타입이면 체취가 심합니다**.

흥미롭게도 이 유전자는 귀지 형태와도 연관됩니다. **AA타입은 귀지가 가루처럼 바스라지고 겨드랑이 체취가 덜 나며**, G타입은 귀지가 물에 젖어 끈적끈적하고 겨드랑이 냄새도 많이 나요. 논문 자료에 따르면 흑인·백인·유럽인은 G타입이 월등히 많고 몽골·중국·한국·일본 같은 아시아인은 A타입이 훨씬 많으며, **한국인은 거의 100%에 가까운 비율로 A타입 유전자를 가집니다**. 미국 커뮤니티 레딧에 "한국인들은 원래 체취가 없어"라는 제목의 글이 올라올 정도이고, 안 씻어서가 아니라 유전적으로 미리 정해져 있다는 것이 핵심입니다.$AAA$, array['ABCC11유전자', 'A타입G타입', '한국인체취', '귀지유전자', '겨드랑이냄새']::text[], 2024, '0yPA_qnzUuQ-2', 'https://youtu.be/0yPA_qnzUuQ?t=243s', null, '2024-08-22 00:00:00+00'::timestamptz, '2024-08-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$발 냄새와 정수리 냄새는 왜 유독 심한 건가요?$AAQ$, $AAA$발과 정수리는 땀·피지가 많고 습도와 온도가 높아 세균이 잘 번식하기 때문에 냄새가 심하게 납니다. 한국인이 체취가 약한 편이라도 발과 정수리 같은 특정 부위는 사람이라면 누구나 냄새가 날 수밖에 없어요.

발은 땀샘이 많아 땀도 많이 나는데 신발 안이 습해서 **습한 환경을 좋아하는 균들이 많이 번식**합니다. 땀도 많고 땀을 분해하는 세균도 많으니 냄새가 많이 날 수밖에 없어요. 정수리의 경우 머리카락이 덮여 있어 **온도와 습도가 높고 두피에서 피지가 많이 나오기 때문에**, 피지와 섞여 특유의 정수리 냄새가 나는 것입니다. 두 부위 모두 환경적 조건이 세균 활동을 활발하게 만든다는 공통점이 있어, 자주 씻는 것이 핵심 대처법이 됩니다.$AAA$, array['발냄새', '정수리냄새', '두피피지', '세균번식', '땀샘']::text[], 2024, '0yPA_qnzUuQ-3', 'https://youtu.be/0yPA_qnzUuQ?t=378s', null, '2024-08-22 00:00:00+00'::timestamptz, '2024-08-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$체취를 줄일 수 있는 방법은 무엇이 있나요?$AAQ$, $AAA$체취 관리는 위생, 제모, 옷 관리, 식습관, 스트레스 관리 다섯 가지를 같이 챙기는 것이 효과적입니다. 첫째는 **규칙적인 샤워**로 분비물을 잘 씻어내는 것이고, 둘째는 아포크린 땀샘이 많은 겨드랑이 관리예요.

겨드랑이는 씻는 것만으로 부족하면 **털이 있는 경우 제모로 땀과 세균 번식을 줄일 수 있고**, 데오드란트를 사용하는 것도 방법입니다. 셋째 옷을 자주 갈아입어 피지와 땀이 묻은 옷에서 나는 냄새를 차단하고, 넷째 **마늘·양파·술처럼 냄새가 강한 음식은 줄이고 녹차·파슬리·과일을 자주 먹어** 체취를 완화합니다. 물을 많이 마셔 노폐물을 빨리 배출하는 것도 도움이 되고, 다섯째 스트레스도 체취를 심하게 만들기 때문에 적당히 관리해야 합니다. 체취가 심하면 사람들에게 불쾌감을 줄 수 있으니 일상에서 조금만 신경 쓰면 충분히 관리할 수 있어요.$AAA$, array['체취관리', '겨드랑이제모', '데오드란트', '식습관', '스트레스관리']::text[], 2024, '0yPA_qnzUuQ-4', 'https://youtu.be/0yPA_qnzUuQ?t=506s', null, '2024-08-22 00:00:00+00'::timestamptz, '2024-08-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름은 직접 짜도 되나요?$AAQ$, $AAA$여드름은 짜는 게 좋지만, 농이 노랗게 올라온 잘 익은 여드름만 집에서 멸균 도구로 짜야 합니다. 만졌을 때 아프든 안 아프든 **농이 노랗게 올라와 있으면 짜셔도 됩니다**.

집에서 짤 때는 약국에서 일회용 알코올 스왑과 멸균 면봉을 사서, 손을 깨끗이 씻고 알코올 스왑으로 여드름 주위를 닦은 뒤 **멸균 면봉 두 개로 눌러서 짜는 방식**을 권합니다. 짜고 난 후에는 감염을 막기 위해 여드름 패치를 붙이거나 여드름 연고를 발라주세요. 모든 여드름은 멸균 상태에서 숙련된 관리사가 짜는 것이 베스트이며, 손이나 도구의 세균, 사후 관리 소홀로 인한 세균 감염 위험이 있기 때문에 셀프 압출은 상황이 여의치 않을 때만 권합니다. 여드름은 불 끄는 것과 같아서 빨리 진압해야 후유증이 남지 않습니다.$AAA$, array['여드름압출', '내손내짜', '멸균면봉', '알코올스왑', '농여드름']::text[], 2024, 'Asc74WD0VRM-1', 'https://youtu.be/Asc74WD0VRM?t=176s', null, '2024-08-28 00:00:00+00'::timestamptz, '2024-08-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름을 예방하려면 어떤 음식을 피해야 하나요?$AAQ$, $AAA$여드름을 덜 나게 하려면 혈당지수가 높은 정제 탄수화물·당류·달달한 술을 멀리하는 것이 핵심입니다. 흰빵, 흰쌀밥, 국수, 정제 탄수화물, 케이크, 쿠키, 사탕, 초콜릿 같은 **설탕이 많이 들어간 디저트류는 혈당을 빠르게 올려** 여드름을 유발합니다.

술 중에서도 맥주·하이볼·막걸리는 혈당지수가 높지만, **와인·소주·보드카·위스키는 혈당을 덜 올려 그나마 도움이 됩니다**. 단 안주는 자제하고 적당히 드셔야 해요. 음료도 액상과당이나 설탕이 많이 들어간 것은 당이 바로 흡수되어 혈당을 올리므로, 탄산음료 대신 제로 음료를 드시는 게 좋습니다. **혈당이 빠르게 상승하면 인슐린과 IGF-1이 분비 증가되고**, 이것이 피지 분비와 안드로겐 호르몬 분비를 늘려 결국 여드름을 일으키는 메커니즘이에요. 음식만 먹어도 여드름이 나는 분은 먹은 음식의 혈당지수를 한 번 확인해 보시는 것을 권합니다.$AAA$, array['여드름음식', '혈당지수', '정제탄수화물', 'IGF1', '제로음료']::text[], 2024, 'Asc74WD0VRM-2', 'https://youtu.be/Asc74WD0VRM?t=326s', null, '2024-08-28 00:00:00+00'::timestamptz, '2024-08-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$깊은 여드름은 어떻게 치료해야 흉터가 안 남나요?$AAQ$, $AAA$깊은 여드름은 짜지 말고 병원에서 즉시 염증을 가라앉히는 것이 흉터 예방의 핵심입니다. 살짝만 건드려도 아픈 깊은 여드름은 압출이 어렵고, 잘못 건드리면 **더 큰 염증으로 이어져 100% 흉터가 됩니다**.

흉터 연구 논문에 따르면 염증이 아무리 심해도 빨리 해결하면 흉터가 남지 않고, 염증이 심하지 않더라도 빨리 해결하지 않으면 흉터가 많이 남는다고 보고됩니다. 그래서 **염증을 어떻게든 빨리 해결하는 것이 여드름 치료에서 가장 중요한 원칙**이에요. 병원에서는 염증 주사로 염증을 바로 가라앉히고, 메디컬 스킨케어 스케일링으로 모공을 막은 각질을 정돈해 피지 분비를 원활하게 만듭니다. 피부가 예민하고 민감한 분은 스케일링 대신 **소노라임·LDM 같은 고밀도 초음파 관리가 적합**해서, 잔떨림으로 피부 장벽 재생을 유도하고 염증도 가라앉힙니다.$AAA$, array['깊은여드름', '여드름흉터예방', '염증주사', '메디컬스킨케어', '고밀도초음파']::text[], 2024, 'Asc74WD0VRM-3', 'https://youtu.be/Asc74WD0VRM?t=499s', null, '2024-08-28 00:00:00+00'::timestamptz, '2024-08-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 예방을 위한 생활습관은 어떻게 챙겨야 하나요?$AAQ$, $AAA$성인형 여드름 예방은 충분한 수면·스트레스 관리·올바른 세안·식습관 네 가지를 같이 챙겨야 합니다. 성인형 여드름은 **생활 습관과 연관이 있는 경우가 많아 본인이 조절할 수 있는 부분이 많습니다**.

충분한 수면이 굉장히 중요하고, 스트레스를 줄여주는 것도 필수예요. 세안과 클렌징을 잘하는 것도 기본이며, **BHA 성분이 들어간 클렌저는 면포를 녹이고 피지 분비를 줄여줘** 여드름 완화에 크게 도움이 됩니다. 가벼운 여드름은 약국 연고를 발라 관리할 수 있고, 클렌저 선택과 연고 사용을 상황에 맞게 조합하면 집에서도 충분히 예방 가능합니다. 모든 관리를 한 번에 완벽히 하기보다 자신이 부족한 부분부터 하나씩 챙기는 것이 효과적이며, 효과에는 개인차가 있으니 꾸준히 유지하는 것이 핵심입니다.$AAA$, array['성인여드름예방', '생활습관', 'BHA클렌저', '충분한수면', '스트레스관리']::text[], 2024, 'Asc74WD0VRM-4', 'https://youtu.be/Asc74WD0VRM?t=329s', null, '2024-08-28 00:00:00+00'::timestamptz, '2024-08-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$화상 직후 얼음으로 식혀도 되나요?$AAQ$, $AAA$화상에 얼음을 직접 대거나 얼음물에 담그는 것은 절대 금기이며, 흐르는 시원한 물로 식혀야 합니다. 얼음은 **온도가 너무 낮아 피부로 통하는 혈류가 줄고 이미 손상된 조직을 더 악화시킬 수 있어요**.

올바른 방법은 얼음 대신 **흐르는 물에 화상 부위를 10분 정도 대거나** 시원한 물에 담그거나 시원한 물을 적신 수건을 이용하는 것입니다. 하루에 여러 번 시원한 물로 쿨링을 하고, 이후 연고와 보습제, 재생크림으로 처치를 이어갑니다. 손처럼 많이 사용하는 부위를 다쳤거나 물집이 잡혔다면 접착력이 약한 습윤밴드로 살짝 감싸 보호하고, 너무 쓰리고 아프면 상비 소염진통제를 복용하는 것도 도움이 됩니다. 화상 처치는 시간 싸움이라 초기부터 적극 대응하는 것이 회복과 흉터 예방의 핵심입니다.$AAA$, array['화상응급처치', '흐르는물쿨링', '얼음금지', '습윤밴드', '화상연고']::text[], 2024, 'czgFuSmFBJM-1', 'https://youtu.be/czgFuSmFBJM?t=140s', null, '2024-09-03 00:00:00+00'::timestamptz, '2024-09-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$집에서 할 수 있는 화상 드레싱 방법은 무엇인가요?$AAQ$, $AAA$집에서는 멸균 거즈와 생리식염수를 이용한 드레싱이 피부과에서도 사용하는 효과적인 방법입니다. 약국에서 멸균 거즈와 멸균 생리식염수를 사서 거즈에 식염수를 충분히 적신 뒤 **물기를 살짝 짜내고 화상 부위에 얹어주세요**.

이렇게 하면 쿨링과 수분 공급, 진물 흡수와 진정 효과가 한 번에 일어납니다. 10분 정도 얹었다가 떼어내고 면봉으로 연고를 발라주는 순서로 진행해요. 연고는 항생제와 스테로이드가 함께 들어 있는 **쎄레스톤지·더마스톤지·복합 마데카솔**이나, 박테로신·에스로반 같은 항생제 단독 연고와 스테로이드 연고를 따로 섞어 발라도 됩니다. 여기에 **인간상피세포 성장인자인 이지에프 새살 연고를 마지막에 뿌리듯 도포**하면 세포 재생을 돕습니다. 마무리는 진물이 적으면 듀오덤, 많으면 메디폼 같은 폼 제형 습윤밴드를 붙이는 게 좋습니다.$AAA$, array['생리식염수드레싱', '멸균거즈', '복합마데카솔', '이지에프새살연고', '습윤밴드']::text[], 2024, 'czgFuSmFBJM-2', 'https://youtu.be/czgFuSmFBJM?t=271s', null, '2024-09-03 00:00:00+00'::timestamptz, '2024-09-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$화상 후 생긴 물집은 터뜨려도 되나요?$AAQ$, $AAA$화상 물집은 저절로 터지지 않는 한 일부러 터뜨리거나 뜯지 말아야 합니다. 물집의 막은 **균 감염으로부터 피부를 보호해주는 일종의 천연 장벽 역할**을 하기 때문에 가급적 그대로 두는 것이 좋아요.

물집이 너무 부풀어 있어서 불편하다면 자가 처리보다 병원에 내원해 드레싱을 받는 것이 안전합니다. **물집이 생겼다는 건 화상 깊이가 깊다는 의미라서**, 셀프 드레싱보다 병원에서 처방약을 받는 쪽이 회복이 더 빠릅니다. 1도와 표재성 2도 화상은 보통 1~2주 이내에 잘 아물고 흉터도 거의 남지 않지만, 심재성 2도 이상부터는 피부 이식이나 여러 차례의 수술이 필요할 수 있어 자가 판단보다 전문의 진료를 받는 것이 안전합니다.$AAA$, array['화상물집', '수포터뜨리기', '천연장벽', '심재성2도', '병원드레싱']::text[], 2024, 'czgFuSmFBJM-3', 'https://youtu.be/czgFuSmFBJM?t=449s', null, '2024-09-03 00:00:00+00'::timestamptz, '2024-09-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$화상 흉터와 색소침착은 얼마나 가나요?$AAQ$, $AAA$1~2도 화상은 텍스처 변화 흉터는 남지 않지만 붉은기·갈색 색소침착이 몇 달 이상 갈 수 있습니다. 1도 화상이나 표재성 2도 화상은 보통 1~2주 이내에 아물고 흉터는 거의 남지 않아요. 다만 상처가 아물고 바로 원상태로 돌아가는 것은 아니고, **붉은기나 갈색 색소침착이 남을 수 있습니다**.

다행히 영구적 착색은 아니고 시간이 지나면 서서히 좋아지지만, 경우에 따라 회복까지 **몇 달 이상 걸릴 수도 있어요**. 회복 후에는 굳이 밴드로 덮을 필요 없이 비판텐 같은 재생크림을 수시로 바르고, **메디터치·스카겔·레노실·스트라타메드 같은 실리콘 성분 흉터 연고**를 사용해 텍스처와 색소 회복을 도울 수 있습니다. 노스카나 연고는 알란토인·판테놀·헤파린·비타민B·E가 들어 있어 색소를 옅게 만드는 데 도움이 되고요. 자국 연고는 두어 달 이상 발라야 효과를 보고, 더 빨리 좋아지게 하려면 토닝 레이저로 색을, V빔으로 붉은 자국을 개선할 수 있습니다.$AAA$, array['화상색소침착', '실리콘흉터연고', '노스카나', '토닝레이저', 'V빔']::text[], 2024, 'czgFuSmFBJM-4', 'https://youtu.be/czgFuSmFBJM?t=462s', null, '2024-09-03 00:00:00+00'::timestamptz, '2024-09-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$고주파 시술은 어떤 원리로 효과가 나타나나요?$AAQ$, $AAA$고주파 시술은 피부에 전기를 흘려 발생한 열로 오래된 콜라겐을 망가뜨리고 새 콜라겐 생성을 유도하는 시술입니다. 피부에 전기를 흘려주면 열이 발생하고, **그 열로 오래된 콜라겐과 엘라스틴이 망가집니다**.

그러면 우리 몸은 오래된 섬유들이 망가졌다고 인식해 서서히 새로운 콜라겐을 만들어내고, **새 콜라겐이 그 자리를 대치하며 탄력이 늘어나는 원리**입니다. 흐물흐물해진 풍선에 다림질로 쫙 펴는 정도는 아니지만 약한 주름을 펴는 스팀다리미 정도로 비유할 수 있어요. 그 결과 탄력·잔주름·모공·피부결·피부톤까지 전체적으로 개선됩니다. 얼굴이 붉은 분은 고주파 시술 후 붉은기가 완화되는 경우가 많은데, 피부가 탄탄하고 건강해지기 때문이에요. 최소 1년에 한 번, 1~2년 꾸준히 받으면 주변 나이대보다 어려 보인다는 소리를 들을 수 있습니다.$AAA$, array['고주파원리', '콜라겐재생', '엘라스틴', '탄력시술기전', '써마지원리']::text[], 2024, 'wusUx3hPsi8-1', 'https://youtu.be/wusUx3hPsi8?t=165s', null, '2024-09-05 00:00:00+00'::timestamptz, '2024-09-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지 효과를 제대로 보려면 어떻게 받아야 하나요?$AAQ$, $AAA$써마지 효과를 제대로 보려면 샷수를 충분히 하거나 다른 시술을 병합해야 합니다. 일단 시술 효과가 나타나려면 **피부 온도를 40~42도 이상까지 올려야 하는데**, 우리 체온이 36.5도라 비싼 써마지 샷을 단순 온도 상승에만 쓰는 건 아깝습니다.

그래서 써마지 팁 대신 **온도를 미리 올려줄 수 있는 시술을 함께 받는 전략**을 권합니다. 티타늄 리프팅이나 오푸스 같은 시술을 먼저 받은 뒤 써마지나 다른 고주파를 이어서 받는 방식이에요. 600샷을 받고도 효과를 모르겠다는 분이 있는 이유는 샷수 한 발 한 발의 효율이 떨어졌기 때문일 수 있습니다. **써마지보다 통증은 줄면서 효과가 좋은 세르프·덴서티 하이 같은 장비**로 대체하는 방법도 있어요. 한 샷이라도 소중하게 활용하는 것이 비용 대비 만족도를 높이는 핵심입니다.$AAA$, array['써마지샷수', '티타늄리프팅', '오푸스', '세르프', '덴서티하이']::text[], 2024, 'wusUx3hPsi8-2', 'https://youtu.be/wusUx3hPsi8?t=337s', null, '2024-09-05 00:00:00+00'::timestamptz, '2024-09-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$노화는 몇 살에 갑자기 찾아오나요?$AAQ$, $AAA$노화는 30대 초반에 한 번 급격히 찾아오는 시기가 있다는 것이 논문으로 확인된 사실입니다. 실제로 **노화와 관련된 단백질 발현이 32~34살쯤 한 번 피크를 찍습니다**.

그 이후 60대와 70대에 또 한 번씩 크게 오는데, 30대 초반을 지나는 분들은 대부분 **훅 처진 느낌이 든다거나 꺾이는 느낌이 든다고 표현**하시곤 해요. 그게 아니더라도 요즘 들어 부쩍 잔주름이 생겼다거나 피부가 푸석푸석해졌다고 느끼는 분도 많습니다. 이 또한 논문이 뒷받침하는 현상이고, 흐물흐물해진 피부는 30대부터 한 번 꺾인 시점부터 회복이 쉽지 않습니다. 그래서 이 시기에 고주파 같은 시술로 미리 대응하는 'Prejuvenation' 개념이 강조되고, 노화를 예측해 미리 예방하는 접근이 효과적입니다.$AAA$, array['32살노화', '노화피크', '단백질발현', '30대초반', 'prejuvenation']::text[], 2024, 'wusUx3hPsi8-3', 'https://youtu.be/wusUx3hPsi8?t=60s', null, '2024-09-05 00:00:00+00'::timestamptz, '2024-09-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지와 함께 받으면 좋은 시술은 무엇인가요?$AAQ$, $AAA$써마지 효과를 극대화하려면 스킨부스터와 처짐 정도에 맞는 리프팅 시술을 병합하는 것이 좋습니다. 고주파 시술로 콜라겐이 새로 만들어질 때 **더 많이, 더 좋게 만들어질 환경을 만들어주는 게 핵심**이에요.

이를 위해 **쥬베룩이나 리쥬란 같은 스킨부스터를 함께 받으면** 콜라겐 생성 환경이 좋아집니다. 볼살이나 턱살이 축 늘어진 분, 처짐이 심한 분은 SMAS라고 불리는 근막을 리프팅하는 울쎄라가 적합하고, 근육 자체를 강화하려면 엠페이스 시술도 있어요. 입문자의 경우 통증이 두렵다면 써마지보다 통증이 적고 효과가 좋은 세르프나 덴서티 하이 같은 대체 장비도 선택 가능합니다. 비용은 어떤 시술을 받든 커피 한 잔씩 아낄 정도로 접근 가능하며, 1년 365일 일어나는 노화를 막기 위해 꾸준히 받는 게 가장 중요합니다.$AAA$, array['써마지병합', '쥬베룩리쥬란', '울쎄라SMAS', '엠페이스', '스킨부스터']::text[], 2024, 'wusUx3hPsi8-4', 'https://youtu.be/wusUx3hPsi8?t=408s', null, '2024-09-05 00:00:00+00'::timestamptz, '2024-09-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미 연고는 복합과 단일 중 어떤 게 더 좋나요?$AAQ$, $AAA$효과만 따지면 복합 연고가 더 좋고, 피부 자극이 걱정되면 단일 연고를 사용해도 됩니다. 복합 연고에는 미백 성분인 **하이드로퀴논, 노화된 진피를 되돌리는 레티노이드, 자극감을 줄이는 스테로이드** 세 가지가 섞여 있어요.

트리루스트라·멜라논·프리엔티 크림이 대표적인 복합 전문의약품이고, 단일 성분은 하이드로퀴논 단독의 도미나·멜라토닝 크림이나 레티노이드 단독의 투앤티 크림이 있습니다. **단일 성분은 함량이 낮으면 처방 없이 일반의약품으로 살 수 있어요**. 복합은 미백 성분들이 적절히 자극이 최소화되도록 잘 배합되어 있어, 피부가 현재 민감한 상태가 아니라면 복합 성분을 먼저 시도하는 것이 좋습니다. 그게 어려우면 단일 성분으로 시작해도 효과를 볼 수 있어요.$AAA$, array['기미연고', '복합연고', '하이드로퀴논', '레티노이드', '전문의약품']::text[], 2024, 'bP849fW-8nA-1', 'https://youtu.be/bP849fW-8nA?t=45s', null, '2024-09-10 00:00:00+00'::timestamptz, '2024-09-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미 연고는 어떻게 발라야 자극이 덜한가요?$AAQ$, $AAA$기미 연고는 저녁에만, 보습제를 먼저 바른 위에 완두콩만큼 펴 바르는 방식으로 시작해야 자극이 덜합니다. 기미 연고는 피부에 자극감을 주고 햇빛에 민감해질 수 있어 **저녁에만 발라야 합니다**.

처음에는 맨 얼굴에 바로 바르지 말고, **보습제를 먼저 발라 막을 만든 위에 완두콩 정도의 연고를 펴 바릅니다**. 피부에 안 맞으면 며칠 후 얼굴이 붉어지고 각질이 일어나며 가렵거나 따갑게 됩니다. 한 달 정도 도포해도 불편함이 없으면 그때부터 맨 얼굴의 기미 부위에 바로 발라도 됩니다. 만약 적응이 어려우면 전문의와 상의해 **더 낮은 농도의 연고로 바꾸거나 단일 성분으로 변경하거나 아예 중단할 수도 있어요**. 자외선 차단을 평소에 잘 안 하면 자극이 더 심해지니 선크림은 필수입니다.$AAA$, array['기미연고도포법', '저녁사용', '보습제먼저', '완두콩분량', '자극증상']::text[], 2024, 'bP849fW-8nA-2', 'https://youtu.be/bP849fW-8nA?t=126s', null, '2024-09-10 00:00:00+00'::timestamptz, '2024-09-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$하이드로퀴논 연고는 얼마나 오래 발라도 되나요?$AAQ$, $AAA$하이드로퀴논은 매일 3~4개월만 도포하고 이후 횟수를 줄이거나 다른 성분으로 바꿔야 합니다. 이 성분을 어느 정도 높은 농도로 오래 바르면 **드물지만 외인성 갈색증이라는 색소침착이 보고되고 있어요**.

따라서 효과가 좋다고 몇 년 동안 계속 쓰는 것은 안 되며, **매일 3~4개월 도포 후 주 2~3회로 횟수를 줄이고 2~3달 더 유지한 뒤 중단**하는 방식이 권장됩니다. 또는 그 성분이 들어 있는 제품은 끊고 **레티노이드나 다른 종류의 미백 기능성 화장품으로 전환**하는 것이 좋아요. 진료에서는 보통 멜라논이나 프리앤티 같은 복합 연고를 먼저 3~4개월 매일 쓰게 한 뒤, 효과를 본 후에는 투앤티 크림이나 아크리프 같은 레티노이드 단독 제품으로 바꾸도록 안내합니다. 레티노이드 계열은 자극감만 없다면 오래 발라도 상관없습니다.$AAA$, array['하이드로퀴논기간', '외인성갈색증', '레티노이드전환', '투앤티크림', '아크리프']::text[], 2024, 'bP849fW-8nA-3', 'https://youtu.be/bP849fW-8nA?t=187s', null, '2024-09-10 00:00:00+00'::timestamptz, '2024-09-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$토닝 레이저를 받았는데 기미가 더 심해진 이유는?$AAQ$, $AAA$토닝 레이저로 기미가 심해지는 건 시술 강도가 강하거나 자외선·호르몬·피부 컨디션 같은 환경 요인 때문입니다. 시술 강도가 강하면 피부에 자극을 주고 **염증이 생기면서 기미가 활성화되어 심해지는 경우**가 있어요.

강도가 강하지 않았어도 해가 강한 시즌이거나 현재 피부가 붉고 염증이 있는 예민한 상태, 호르몬 문제 같은 다른 컨디션도 결과에 영향을 줍니다. 그래서 **시술 시점의 주위 환경, 개인의 생활 패턴, 현재 피부 컨디션을 고려해 종류와 세기를 조절**해야 합니다. 어떤 경우에는 레이저 없이 먹는 약과 관리만으로 치료하는 게 더 효과적일 때도 있어요. 시술 후에는 피부 진정과 자외선 차단 두 가지를 강조하며, **셀프 필링·스크럽을 매일 하면 자극이 되어 색소침착이 다시 생길 수 있어** 과한 홈케어는 피해야 합니다.$AAA$, array['토닝레이저부작용', '기미악화', '시술강도', '자외선차단', '셀프필링']::text[], 2024, 'bP849fW-8nA-4', 'https://youtu.be/bP849fW-8nA?t=440s', null, '2024-09-10 00:00:00+00'::timestamptz, '2024-09-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$오이팩은 피부에 어떤 효과가 있나요?$AAQ$, $AAA$오이팩은 진정·쿨링 효과와 미백 효과가 좋은 천연팩입니다. 오이는 수분 함량이 많아 피부를 시원하게 가라앉히고, 비타민C가 풍부해 피부를 늙지 않게 하는 효과가 있다고 알려져 있어요. 특히 오이팩을 하고 나서 미백 효과가 있었다는 데이터도 있습니다.

다만 수분 함량이 높다고 해서 피부가 그걸 다 흡수하지는 않기 때문에 **보습 효과는 생각보다 떨어지는 편**입니다. 사용법은 오이를 강판에 갈아 즙을 내고 마스크 시트나 얇은 화장솜에 충분히 적셔 얼굴에 올리면 됩니다. 천연 물질이라 변질될 수 있으니 만든 즉시 한 번만 쓰는 게 좋고, 알러지가 있을 수 있어 팔 안쪽에 먼저 발라보고 사용하세요. **염증을 가라앉히거나 피부를 밝아지게 하고 싶을 때, 지성·민감성·홍조·여드름 피부에도 큰 문제 없이 활용할 수 있습니다.**$AAA$, array['오이팩', '천연팩', '미백효과', '진정쿨링', '여드름피부']::text[], 2024, 'C6AsJjf8HM0-1', 'https://youtu.be/C6AsJjf8HM0?t=92s', null, '2024-09-13 00:00:00+00'::timestamptz, '2024-09-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$알로에 천연팩은 어떻게 만들어 쓰나요?$AAQ$, $AAA$알로에 천연팩은 시판 알로에 겔을 화장솜에 적셔 얼굴에 올리는 방식으로 간단하게 만들 수 있습니다. 먼저 얼굴 전체에 알로에 겔을 펴 바르고, 물에 적셔 살짝 짠 화장솜을 그 위에 붙인 뒤 **10분-15분 정도** 두면 됩니다. 떼어내고 남은 잔여물은 톡톡 두드려 흡수시킨 후 평소 스킨케어 루틴으로 마무리하세요.

제품 고를 때는 알로에 함유량 99%로 가장 높은 걸 고르고, 전성분표에 "알로에 잎 추출물"보다 "알로에베라잎즙"이라 적힌 게 순도가 높습니다. 추출물은 물이 섞인 형태인 반면 알로에베라잎즙은 잎을 실제로 즙을 낸 거예요. 또 **에탄올이나 트리에탄올아민 같은 알코올 성분은 시원한 느낌은 주지만 피부 수분을 날려 오히려 건조하게** 만들 수 있어, 알코올이 없는 제품을 고르는 게 중요한 꿀팁입니다.$AAA$, array['알로에팩', '천연팩만들기', '알로에베라잎즙', '에탄올', '성분선택']::text[], 2024, 'C6AsJjf8HM0-2', 'https://youtu.be/C6AsJjf8HM0?t=263s', null, '2024-09-13 00:00:00+00'::timestamptz, '2024-09-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$꿀팩은 어떤 피부에 잘 맞나요?$AAQ$, $AAA$꿀팩은 건성 피부, 잔주름·푸석함이 있는 분들에게 특히 잘 맞는 천연팩입니다. 꿀은 끈적한 제형으로 피부에 발리면 보습막을 형성해 보습 효과가 좋고, 콜라겐이 생겨 피부가 탱탱해지는 느낌을 준다고 알려져 있어요. 또 각질을 빨리 탈락시켜 염증을 가라앉히고 여드름 피부에도 도움이 된다고 합니다.

다만 끈적임 때문에 얼굴 전체에 도포하기보다는 **다른 팩의 첨가물로 일부 부위에만 살짝 활용하는 게 더 좋은 방법**입니다. 잔주름이 많거나 푸석한 부위에만 꿀을 살짝 바르고 그 위에 평소 쓰던 마스크팩을 올리는 식이에요. **지성 피부보다는 건조하신 분들이 썼을 때 효과가 좋고**, 바를 때는 브러쉬나 집에 있는 숟가락으로도 충분합니다.$AAA$, array['꿀팩', '건성피부', '보습효과', '잔주름', '첨가물활용']::text[], 2024, 'C6AsJjf8HM0-3', 'https://youtu.be/C6AsJjf8HM0?t=394s', null, '2024-09-13 00:00:00+00'::timestamptz, '2024-09-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$우유팩 사용 시 상한 우유를 써도 되나요?$AAQ$, $AAA$우유팩에는 상한 우유보다 상하지 않은 우유를 쓰시는 게 안전합니다. 우유 안 젖산이 상했을 때 더 늘어나 효과가 좋다는 얘기가 있지만, **천연팩을 하면서 큰 효과를 보는 것보다 나쁜 일이 안 생기는 게 더 중요해요**. 상한 우유는 염증이나 감염을 일으킬 수 있어 권하지 않습니다.

우유는 단백질과 지방으로 보습 기능이 있고, 젖산이 각질을 제거해 피부를 매끈하고 촉촉하게 만들어 줍니다. 사용법은 우유를 살짝 데워 **피부와 비슷한 온도로 만든 뒤 화장솜에 축축하게 적셔 얼굴에 붙이고 10분-15분 두었다가** 떼어내고 세안하면 됩니다. 송혜교 씨가 우유 세안으로 유명하고 클레오파트라도 우유 목욕을 했다고 전해질 만큼 오래된 미용법이지만, 위생 면에서는 신선한 우유를 쓰는 게 원칙입니다.$AAA$, array['우유팩', '상한우유', '젖산', '감염위험', '사용법']::text[], 2024, 'C6AsJjf8HM0-4', 'https://youtu.be/C6AsJjf8HM0?t=479s', null, '2024-09-13 00:00:00+00'::timestamptz, '2024-09-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티놀은 어떤 효과가 있나요?$AAQ$, $AAA$레티놀은 주름·색소·탄력 등 피부 노화 전반을 되돌려주는 효과가 있는 안티에이징 성분입니다. 실제로 피부 노화를 예방하는 효과와, 이미 진행된 노화를 어느 정도 되돌려주는 효과가 함께 있다고 알려져 있어요. 그래서 **피부 홈케어에서 빠지면 안 되는 성분** 중 하나로 꼽힙니다.

레티놀의 뿌리는 1960년대 클리그만 교수가 여드름 치료를 위해 개발한 트레티노인입니다. 환자들이 "여드름이 사라지면서 피부 주름도 같이 없어진다"고 말한 것을 계기로 연구가 이어졌고, 1986년 빛에 의한 노화를 되돌린다는 논문이 발표됐어요. 그리고 **1995년 미국 FDA에서 트레티노인을 광노화치료제로 정식 승인**하면서 안티에이징 성분으로 인정받게 됐습니다. 다만 트레티노인은 부작용이 많아 이를 보완한 성분이 화장품용 레티놀입니다.$AAA$, array['레티놀효과', '안티에이징', '광노화', '트레티노인', 'FDA승인']::text[], 2024, 'sLsi7wWwMe4-1', 'https://youtu.be/sLsi7wWwMe4?t=46s', null, '2024-09-20 00:00:00+00'::timestamptz, '2024-09-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티놀과 트레티노인은 어떻게 다른가요?$AAQ$, $AAA$레티놀은 트레티노인과 비슷한 효과를 내면서 부작용은 적은 화장품 성분입니다. 트레티노인(레티노익 애씨드)은 1970년대 여드름 치료 연고로 출시된 의약품으로, **빨개짐·각질·찢어질 듯한 건조함 같은 부작용이 꽤 많이** 생기는 게 한계였어요.

이 문제를 해결하려는 연구 끝에 등장한 것이 레티놀입니다. 트레티노인이 약 출신이라면 레티놀은 화장품으로 개발된 비타민A 유도체로, 자극이 적어 일반 소비자가 꾸준히 쓰기에 적합해요. 다만 **레티놀도 뿌리가 같은 성분이라 농도가 높으면 자극감이 있을 수밖에 없습니다**. 트레티노인은 의약품이라 처방이 필요하지만, 레티놀은 화장품으로 다양한 농도가 출시되어 입문자부터 고급자까지 단계적으로 선택할 수 있는 게 큰 차이입니다.$AAA$, array['레티놀', '트레티노인', '차이점', '부작용비교', '농도자극']::text[], 2024, 'sLsi7wWwMe4-2', 'https://youtu.be/sLsi7wWwMe4?t=330s', null, '2024-09-20 00:00:00+00'::timestamptz, '2024-09-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티놀 초보자는 어떻게 시작해야 하나요?$AAQ$, $AAA$레티놀 초보자는 0.01% 정도의 가장 낮은 농도부터 시작하시는 게 안전합니다. 한 번도 안 써봐서 본인 피부 반응을 모르거나 예민하신 분들은 큰 부담 없이 바를 수 있는 저농도 제품으로 시작하세요. 영상에서 소개한 테라로직 레틴-A 안티링클 3D 앰플은 농도 0.01%로 레티놀 화장품 중 가장 낮은 편에 속합니다.

적응이 된 중급자는 0.1% 농도로 올라갈 수 있고, **처음에는 얼굴 전체에 다 바르지 말고 소량만 발라 2-3일에 한 번씩 사용**하며 피부 반응을 보세요. 비타민C, AHA, BHA처럼 자극을 줄 수 있는 성분과의 병용은 신중해야 하고, 레티놀을 바르면 자외선에 민감해지므로 낮에는 꼭 자외선 차단제를 발라야 합니다. **얼굴뿐 아니라 목에도 같이 발라 주는 것이 주름 관리에 도움이 됩니다**.$AAA$, array['레티놀초보자', '저농도', '사용빈도', '병용성분', '자외선차단']::text[], 2024, 'sLsi7wWwMe4-3', 'https://youtu.be/sLsi7wWwMe4?t=408s', null, '2024-09-20 00:00:00+00'::timestamptz, '2024-09-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티놀 고농도 제품 쓸 때 주의할 점은 뭔가요?$AAQ$, $AAA$레티놀 0.5% 고농도 제품은 이전에 낮은 농도에 적응한 분만 신중하게 써야 합니다. 농도가 갑자기 높아지면 피부가 뒤집어질 우려가 있기 때문에, 처음 양 조절을 할 때는 본인이 평소 쓰는 크림에 한두 방울을 떨어뜨려 함께 바르는 방법을 권합니다.

영상에서 소개한 고급자용 제품은 베이스가 스쿠알란인데, **스쿠알란은 피지를 구성하는 기름 성분 중 하나로 피지처럼 기름막을 쳐서 수분이 날아가지 않게 잡아주는 역할**을 합니다. 자극이 될 수 있는 레티놀을 보호하기 위한 베이스 선택이지만, 기름 성분이라 다소 번들거릴 수 있어요. **한두 번 바른다고 효과가 바로 나오지 않으므로 본인에게 맞는 제품을 오랜 시간 꾸준히 바르는 것이 가장 중요**합니다.$AAA$, array['고농도레티놀', '스쿠알란', '크림혼합', '번들거림', '꾸준한사용']::text[], 2024, 'sLsi7wWwMe4-4', 'https://youtu.be/sLsi7wWwMe4?t=523s', null, '2024-09-20 00:00:00+00'::timestamptz, '2024-09-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리쥬란은 어떤 시술인가요?$AAQ$, $AAA$리쥬란은 연어 생식세포에서 추출한 PN 성분을 피부에 주사하는 스킨부스터 시술입니다. 파마리서치가 2015년 처음 출시한 시술로, PN(폴리뉴클레오타이드)이 염증을 가라앉히고 피부를 재생시키며 보습감·수분감, 탄력·볼륨감까지 좋아지게 하는 효과가 있다고 알려져 있어요.

PN의 원형은 이탈리아 마스텔리 회사가 만든 송어 유래 PDRN입니다. **파마리서치 정상수 회장이 강원도 강릉이 연어 산란지인 점에 착안해 연어 생식세포에서 PDRN을 추출하는 데 성공**한 뒤, **DNA 사슬 체인을 약 10배 더 긴 형태로 합성한 PN을 개발해 리쥬란을 만든 것**입니다. 연 매출 170억대였던 파마리서치는 2022년 2천억 대, 2024년 3천억 대 매출이 예상될 정도로 성장했고, 킴 카다시안·제니퍼 로페즈가 받았다는 기사로 해외에서도 핫한 시술이 됐어요.$AAA$, array['리쥬란', 'PN성분', '스킨부스터', '파마리서치', '연어PDRN']::text[], 2024, 'YOOzqL3xgDI-1', 'https://youtu.be/YOOzqL3xgDI?t=120s', null, '2024-09-24 00:00:00+00'::timestamptz, '2024-09-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리쥬란은 어떤 사람에게 효과가 좋나요?$AAQ$, $AAA$리쥬란은 피부가 민감하고 트러블이 많거나 여드름·홍조·속건조가 있는 분에게 효과가 좋습니다. PN 성분의 항염 작용과 피부 재생 기능이 핵심이라, 실제로 안면홍조로 몇 년간 레이저와 약물 치료를 반복했던 환자가 리쥬란 한 번으로 "지금까지 했던 모든 시술보다 좋았다"고 반응했던 사례도 있어요.

반대로 **피부가 튼튼하거나 두껍거나 별로 건조하지 않은 분은 효과를 잘 못 느낄 수 있습니다**. 리쥬란이 효과가 없었다는 분들은 약 자체의 한계라기보다 효과가 나올 만한 피부 상태가 아니었을 가능성이 큰 거예요. 원래 피부가 좋은 분들은 "속건조가 좋아졌다, 광이 난다, 모공이 좋아졌다" 정도의 반응을, **민감성·여드름·홍조·속건조 피부에서는 피부 자체의 문제를 해결해 주는 수준의 반응**을 보이는 시술입니다.$AAA$, array['리쥬란적응증', '민감성피부', '홍조여드름', '속건조', '효과차이']::text[], 2024, 'YOOzqL3xgDI-2', 'https://youtu.be/YOOzqL3xgDI?t=347s', null, '2024-09-24 00:00:00+00'::timestamptz, '2024-09-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리쥬란 시술은 많이 아픈가요?$AAQ$, $AAA$리쥬란 시술의 가장 큰 단점은 통증이지만 최근에는 바늘 없는 장비로 많이 완화됐습니다. PN은 PDRN보다 10배 더 긴 DNA 사슬 체인을 가지고 있어 알갱이가 크고 점성도 큽니다. PDRN은 물처럼 뚝뚝 떨어지는 반면 PN은 천천히 떨어질 정도로 점도가 있어, 이렇게 큰 분자를 피부에 주사하면 통증이 생길 수밖에 없어요.

다행히 최근에는 **바늘 없이 주사할 수 있는 인젝터 장비가 많이 나와 통증을 이전의 3분의 1 정도로 확 줄여 줍니다**. 영상에서도 "많은 분들이 별로 통증 없이 리쥬란 시술을 받을 수 있게 됐다"고 좋아하신다고 언급돼 있어요. 물론 주사 시술이라 출혈이나 바늘 자국이 어느 정도 생길 수는 있지만, **시술 자체로 효과를 못 느꼈다는 분이 거의 없을 정도로 만족도가 높은 시술**입니다.$AAA$, array['리쥬란통증', 'PN점성', '무바늘인젝터', '통증감소', '출혈자국']::text[], 2024, 'YOOzqL3xgDI-3', 'https://youtu.be/YOOzqL3xgDI?t=503s', null, '2024-09-24 00:00:00+00'::timestamptz, '2024-09-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리쥬란과 콘쥬란은 어떻게 다른가요?$AAQ$, $AAA$리쥬란은 피부 재생을, 콘쥬란은 관절 재생을 돕는 PN 기반 시술로 사용 부위가 다릅니다. 둘 다 파마리서치가 만든 폴리뉴클레오타이드 제품이지만, 리쥬란은 피부과에서 스킨부스터로 사용되는 반면 **콘쥬란은 정형외과에서 관절이 불편한 분들에게 실제로 많이 사용**되고 있어요.

매출 규모로 보면 콘쥬란의 매출액이 올해에만 500억 대로 알려져 있고, 콘쥬란과 리쥬란 모두 세계로 수출되고 있어 매출이 더 늘어날 것으로 예상됩니다. **PN 성분 자체가 염증을 좋아지게 하고 손상된 조직을 재생시키는 데 효과적**이라는 공통점이 있어, 피부에 적용하면 보습감·탄력·홍조 개선에, 관절에 적용하면 관절 재생에 도움이 되는 방식으로 같은 원리가 부위별로 활용되는 것이 특징입니다.$AAA$, array['리쥬란콘쥬란', 'PN시술비교', '관절재생', '정형외과활용', '수출시장']::text[], 2024, 'YOOzqL3xgDI-4', 'https://youtu.be/YOOzqL3xgDI?t=252s', null, '2024-09-24 00:00:00+00'::timestamptz, '2024-09-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모델링팩은 일반 시트마스크와 어떻게 다른가요?$AAQ$, $AAA$모델링팩은 피부 회복·장벽 기능 복구를 돕는 기능성 팩이고, 시트마스크는 좋은 성분 흡수에 초점이 있는 팩입니다. 시트마스크는 피부에 흡수시키고 싶은 좋은 물질들을 시트에 담아 **10분에서 20분 정도** 올려 놓고 흡수시키는 게 목적이에요.

반면 모델링팩은 피부과 시술 후 빨개지거나 상처가 있는 자극받은 상태의 피부에 발라, **피부가 빨리 회복되고 장벽 기능이 다시 돌아올 수 있게 도와주는 기능**을 합니다. 가루를 물에 섞어 꾸덕한 제형으로 바르고 굳혀서 떼어내는 방식이라 얼굴형에 맞게 전체적으로 밀착되는 게 큰 장점이에요. **두 팩은 목적이 다르므로 평소 보습이 필요하면 시트마스크, 자극받은 피부 진정·회복이 필요하면 모델링팩이 적합한 선택**입니다.$AAA$, array['모델링팩', '시트마스크', '차이점', '장벽회복', '피부진정']::text[], 2024, 'PsaihUrTPOA-1', 'https://youtu.be/PsaihUrTPOA?t=63s', null, '2024-09-26 00:00:00+00'::timestamptz, '2024-09-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모델링팩의 주요 성분은 뭔가요?$AAQ$, $AAA$모델링팩의 주요 성분은 규조토와 칼슘 알지네이트 두 가지입니다. 규조토는 발매트로 익숙한 천연 광물로 수분 흡수 능력이 굉장히 좋고, 수분뿐 아니라 노폐물·피지·각질을 흡수하는 능력도 강해 **여드름·민감성·지성 피부에 효과적**이에요.

칼슘 알지네이트는 메디폼·듀오덤 같은 드레싱 제제에 많이 포함되는 성분으로, 피부에 상처가 나거나 진물이 날 때, 염증이 생겼을 때 **피부 장벽이 다시 회복될 수 있게 도와주는 역할**을 합니다. 모델링팩이 피부과 시술 후 진정용으로 자주 쓰이는 건 바로 이 두 성분 조합 때문이에요. 사용할 때 앰플 한 스포이드 정도를 같이 넣어 섞으면 제형이 부드럽고 쫀쫀해져 보습력이 올라가고, 떼어낼 때 잔여물 없이 깔끔하게 떨어집니다.$AAA$, array['규조토', '칼슘알지네이트', '드레싱제제', '장벽회복', '앰플활용']::text[], 2024, 'PsaihUrTPOA-2', 'https://youtu.be/PsaihUrTPOA?t=445s', null, '2024-09-26 00:00:00+00'::timestamptz, '2024-09-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$집에서 모델링팩을 잘 바르는 방법은 뭔가요?$AAQ$, $AAA$병원 기준 물과 파우더 비율은 1대 1.5 정도로 섞고 한 사람당 두 스쿱 정도를 사용하면 됩니다. 처음에 가루가 완전히 없어질 때까지 꾸덕하게 섞다가 좀 풀어졌을 때 물을 더 넣는 방식이고, 얼굴 크기나 묽기 선호도에 따라 조정하시면 돼요.

팁이 몇 가지 있는데, **팩을 섞을 때 앰플류를 한 스포이드 정도 같이 넣으면 제형이 쫀쫀해지고 보습력이 올라가며 떼어낼 때 잔여물이 적습니다**. 모델링팩 자체가 흡수에 도움이 되니 **팩 바르기 전에 앰플을 살짝 뿌려 두면 압박 효과로 흡수가 더 잘 됩니다**. 바를 때는 스패츌러 윗부분으로 동그랗게 떠서 큰 면적부터 작은 면적 순으로 올리고, 눈 주변은 들어가지 않게 조심하세요. 10분 정도 두었다가 떼고, 잔여물은 토너 묻힌 화장솜으로 닦으면 됩니다.$AAA$, array['모델링팩사용법', '물파우더비율', '앰플첨가', '바르는순서', '잔여물제거']::text[], 2024, 'PsaihUrTPOA-3', 'https://youtu.be/PsaihUrTPOA?t=301s', null, '2024-09-26 00:00:00+00'::timestamptz, '2024-09-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$다이소 2천원 모델링팩, 살만한가요?$AAQ$, $AAA$다이소 2천원 모델링팩은 입문자와 휴가용으로 충분히 가성비가 있는 제품입니다. 영상에서 시연한 두 제품 중 린제이 마스크팩은 민트향과 화한 쿨링감이 강하고, 메디필 모델링 팩은 고무볼 대용 용기와 스패츌러가 포함돼 섞기 편하지만 뜯기가 좀 어렵다는 단점이 있어요.

자주 사용하실 분이라면 쿠팡 등에서 고무볼·스패츌러 세트를 따로 구매해 쓰시는 게 더 좋습니다. **휴가 갈 때 한 번 정도 쓸 거라면 그냥 제품 그대로 사용해도 충분**해요. 특히 **모델링팩 입문자가 처음 써 보기에는 2천원이라는 가성비를 고려할 때 이보다 좋은 제품이 없다**고 할 만큼 무난합니다. 물론 피부과에서 전문가가 발라주는 것보다 효과가 좋을 수는 없지만, 시간과 비용을 아끼면서 홈에스테틱으로 활용하기에는 어느 정도 효과를 기대할 수 있습니다.$AAA$, array['다이소모델링팩', '가성비', '린제이메디필', '홈에스테틱', '입문자']::text[], 2024, 'PsaihUrTPOA-4', 'https://youtu.be/PsaihUrTPOA?t=242s', null, '2024-09-26 00:00:00+00'::timestamptz, '2024-09-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$문신 제거에 잘 지워지는 색과 안 지워지는 색은 뭔가요?$AAQ$, $AAA$문신 잉크 색에 따라 제거 난이도가 다르고 검정색이 가장 잘 지워집니다. 검정색은 입자의 크기가 작은 편이라 비교적 빨리 지워지고, 보라색이나 남색 같은 경우에도 비교적 잘 지워지는 편이에요.

반면 **잘 안 지워지는 색은 빨간색과 노란색**입니다. 한소희 씨처럼 팔 문신을 깨끗하게 지운 사례가 가능한 이유는 검정색 색소만 사용했고 실선과 그라데이션 위주 도안이라 잉크 양이 적었기 때문이에요. 또 **하얀 피부일수록 문신과 색 대비가 커서 레이저가 더 잘 반응하고 시술 후 색소침착도 덜 오는 편**입니다. 마지막으로 문신을 한 지 오래된 경우 색소 입자가 분해되기 쉬워 더 빨리 지워지는 경향이 있어, 같은 도안이라도 시간이 흐른 쪽이 유리할 수 있습니다.$AAA$, array['문신제거', '잉크색깔', '검정색', '빨간색노란색', '피부톤']::text[], 2024, 'TDZ_GV4CvQU-1', 'https://youtu.be/TDZ_GV4CvQU?t=349s', null, '2024-10-04 00:00:00+00'::timestamptz, '2024-10-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$문신 제거 시술은 많이 아픈가요?$AAQ$, $AAA$문신 제거는 문신을 하는 것보다 훨씬 아프지만 마취로 충분히 조절됩니다. 기본적으로 마취 크림으로 마취를 하고, 부위가 작을 때는 주사 마취를 같이 진행해요. **부위가 넓다 싶으면 비수면 마취나 수면 마취까지 동반**하기도 합니다.

다행히 **문신 제거는 치료 회차가 쌓일수록 통증이 덜해져 다들 초반보다 덜 아파하시는 경향**이 있어, 요즘에는 통증 때문에 못 지우는 걱정은 많이 안 하셔도 됩니다. 다만 한 번에 끝나지 않고 여러 번 시술이 필요해 비용이 많이 들어요. 한소희 씨도 2천만 원이 들었다고 알려진 만큼, 문신의 크기·색깔·잉크 양에 따라 정확한 비용은 병원 상담을 통해 확인하는 게 좋습니다. 시간·비용·통증이 모두 소요되니 충분히 고민 후 결정하세요.$AAA$, array['문신제거통증', '마취크림', '수면마취', '회차통증', '비용']::text[], 2024, 'TDZ_GV4CvQU-2', 'https://youtu.be/TDZ_GV4CvQU?t=405s', null, '2024-10-04 00:00:00+00'::timestamptz, '2024-10-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$문신은 한 번에 다 지워질 수 있나요?$AAQ$, $AAA$문신은 한 번에 다 지워지지 않고 잉크 양에 따라 여러 차례 시술이 필요합니다. 영상에서 소개된 사례인 17살 여학생의 경우 남자친구 이름을 영어로 팔뚝에 새긴 문신을 지우러 왔는데, 잉크량이 적은 편이어서 **6-7번 정도면 다 지울 것 같다**고 언급됐어요.

문신이 잘 지워질지 아닐지는 사실 문신을 새기는 순간에 어느 정도 결정됩니다. **어떤 색의 잉크를 썼는지, 얼마만큼의 색소가 들어갔는지에 따라 제거 가능성이 달라지는 것**이 핵심이에요. 또 피코레이저 같은 장비가 발달하면서 검정색 위주의 단순한 도안은 비교적 깨끗하게 지울 수 있게 됐습니다. 다만 잉크의 종류·양·시술자의 깊이에 따라 결과가 달라지므로 정확한 회차는 시술 전 상담에서 평가받는 것이 좋습니다.$AAA$, array['문신제거회차', '피코레이저', '잉크양', '도안복잡도', '예상횟수']::text[], 2024, 'TDZ_GV4CvQU-3', 'https://youtu.be/TDZ_GV4CvQU?t=290s', null, '2024-10-04 00:00:00+00'::timestamptz, '2024-10-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$문신 제거 결정 전에 고려할 점은 뭔가요?$AAQ$, $AAA$문신 제거는 시간·비용·통증이 모두 소요되므로 충분히 고민하고 결정하는 것이 좋습니다. 한 번에 끝나는 시술이 아니라 여러 회차에 걸쳐 진행되고, 회차마다 비용이 누적되며 마취가 필요한 통증도 동반돼요.

다만 너무 겁먹을 필요는 없습니다. **검정색 단일 색소, 적은 잉크 양, 하얀 피부, 시간이 오래된 문신 같은 조건이 맞으면 생각보다 빠르게 제거되는 경우도 있습니다**. 17살 여학생 사례처럼 잉크량이 적으면 6-7회 정도로 제거가 가능하기도 해요. 또 **회차가 쌓일수록 통증이 줄어 초반보다 덜 아파하시는 분이 많으니** 통증 부담도 시간이 지나면 완화됩니다. 정확한 비용·횟수·통증 정도는 문신의 크기·색깔·잉크 양에 따라 달라지므로, 병원에 내원해 상담을 받고 결정하시는 게 좋습니다.$AAA$, array['문신제거결정', '시간비용통증', '고려사항', '상담필요', '유리한조건']::text[], 2024, 'TDZ_GV4CvQU-4', 'https://youtu.be/TDZ_GV4CvQU?t=448s', null, '2024-10-04 00:00:00+00'::timestamptz, '2024-10-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$위고비는 어느 정도 체중 감량 효과가 있나요?$AAQ$, $AAA$위고비는 약 17개월 투약 시 평균 약 15% 정도의 체중 감량 효과가 있는 비만 치료제입니다. 임상시험 결과 68주 동안 사용했을 때 100kg이었던 사람이 85kg로, 70kg이었던 사람이 60kg로 줄어든다는 의미예요. 약으로만 10kg 넘게 감량할 수 있는 셈입니다.

이는 기존 비만치료제 삭센다의 체중 감량 효과가 7-8%였던 것에 비해 약 2배 가까이 높은 수치입니다. **삭센다는 매일 주사가 필요했지만 위고비는 일주일에 한 번 주사로 같은 효과를 내**, 편의성도 크게 좋아졌어요. 펜 형태의 주사기로 복부나 허벅지 같은 살이 많은 부위에 본인이 직접 놓는데, 바늘이 굉장히 가늘어 통증이 거의 없다고 합니다. **이 효과와 편의성 덕분에 일론 머스크, 킴 카다시안 등이 사용해 화제가 된 혁명적 비만 치료제**로 자리잡았습니다.$AAA$, array['위고비효과', '체중감량', '삭센다비교', '주1회주사', '임상결과']::text[], 2024, '7H8g6bbY_ZE-1', 'https://youtu.be/7H8g6bbY_ZE?t=60s', null, '2024-10-08 00:00:00+00'::timestamptz, '2024-10-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$위고비는 어떻게 체중을 줄이는 건가요?$AAQ$, $AAA$위고비는 식욕을 줄이고 위 배출을 늦춰 자연스럽게 칼로리 섭취를 줄이는 방식으로 체중을 감량시킵니다. 위고비의 주성분은 세마글루타이드로, 우리 몸에서 음식을 먹으면 분비되는 **GLP-1 호르몬과 유사한 작용을 하는 성분**이에요.

GLP-1은 인슐린 분비를 촉진하고 위장관 운동을 조절하며 뇌의 포만감 중추를 자극해 포만감을 느끼게 하는 호르몬입니다. 위고비도 비슷하게 작용해 **뇌에 작용해 식욕을 덜 느끼게 하고, 음식이 위에 머무르는 시간을 길게 해 배가 부른 상태를 오래 유지하며 혈당도 조절**해요. 이런 복합 작용 덕분에 고통스럽지 않게 자연스럽게 칼로리 섭취가 줄고 결과적으로 체중이 감소합니다. 단순 감량을 넘어 혈압·콜레스테롤 수치가 낮아지고 당뇨 전 단계 환자가 정상 혈당으로 돌아오는 사례도 임상에서 확인됐습니다.$AAA$, array['세마글루타이드', 'GLP1유사체', '식욕억제', '위배출지연', '혈당조절']::text[], 2024, '7H8g6bbY_ZE-2', 'https://youtu.be/7H8g6bbY_ZE?t=153s', null, '2024-10-08 00:00:00+00'::timestamptz, '2024-10-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$위고비는 어떤 부작용이 있나요?$AAQ$, $AAA$위고비의 가장 흔한 부작용은 구역감·구토·설사·변비 같은 위장관 증상입니다. 두통과 피로도 나타날 수 있는데, 다행히 **이런 증상들은 대부분 일시적이라 2-3일 정도 지나면 호전되는 경우가 많다**고 합니다.

다만 주의해야 할 부작용도 있어요. 당뇨병 환자에게는 저혈당과 당뇨병성 망막병증이 나타날 수 있고, **췌장염·위염·담석증 같은 부작용을 유발할 수 있어 주의가 필요**합니다. 또 이 약을 절대 쓸 수 없는 분도 있는데, 췌장염·갑상선 수질암·다발성 내분비종양증의 병력 또는 가족력이 있는 경우 금기이며 임산부와 수유부도 금기입니다. 약을 중단했을 때 요요현상도 가능한데, **위고비로 감량 후 약을 끊고 1년 지났을 때 환자의 3분의 2가 원래 체중으로 돌아갔다**는 연구 결과가 있어 운동·식습관 개선이 반드시 병행돼야 합니다.$AAA$, array['위고비부작용', '위장관증상', '금기대상', '요요현상', '췌장염위험']::text[], 2024, '7H8g6bbY_ZE-3', 'https://youtu.be/7H8g6bbY_ZE?t=263s', null, '2024-10-08 00:00:00+00'::timestamptz, '2024-10-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$위고비 한국 가격은 얼마인가요?$AAQ$, $AAA$위고비 한 달치 비용은 한국에서 약 80만-100만원 정도로 예상되고 있습니다. 위고비는 건강보험 적용 대상이 아니기 때문에 약제 전액이 본인 부담이며, 처방하는 곳에 따라 차이가 있을 수 있어요. **국내 위고비 유통사 안내에 따르면 10월 15일부터 병원·의원·약국에서 주문을 받고 10월 하순부터 실제 처방이 시작될 예정**입니다.

기존 삭센다 비용이 한 달에 30-50만원 정도였던 것과 비교하면 꽤 비싼 편이지만, **미국의 경우 한 달치 위고비 가격이 약 180만원 정도이기 때문에 상대적으로는 저렴**한 편입니다. 다만 절대 금액은 여전히 부담스러운 수준이에요. 효과가 좋다고 알려진 만큼 수요가 높을 것으로 보이고, 내년 출시 예정인 마운자로는 체중 감량 효과가 약 22%로 더 강력하다고 알려져 비만 치료제 시장 경쟁이 본격화될 전망입니다.$AAA$, array['위고비가격', '한달비용', '비급여', '삭센다대비', '출시일정']::text[], 2024, '7H8g6bbY_ZE-4', 'https://youtu.be/7H8g6bbY_ZE?t=220s', null, '2024-10-08 00:00:00+00'::timestamptz, '2024-10-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$인종에 따라 피부 노화 속도가 어떻게 다른가요?$AAQ$, $AAA$피부색이 가장 밝은 백인은 유색인종에 비해 평균 노화 속도가 10-20년 정도 빠릅니다. 같은 나이라도 인종에 따라 피부 노화 차이가 생각보다 크다는 의미예요.

구체적인 연구를 보면 프랑스 여성과 중국 여성을 비교한 연구에서 **프랑스 여성이 중국 여성보다 주름이 약 15년 정도 빨리 생긴다**고 보고됐어요. 백인과 흑인 비교 연구에서는 **백인은 30대 초반부터 눈에 띄는 주름이 생기는 반면 흑인은 50세 정도가 돼야 비슷한 주름이 생긴다**는 결과가 있습니다. 영상 속 사례로 카멀라 해리스와 팀 월즈가 1964년생 동갑인데 50대와 70대처럼 보일 정도로 차이가 나고, 71세의 오프라 윈프리가 60대 초중반처럼 보이는 것이 이런 차이를 보여주는 대표적인 예입니다.$AAA$, array['인종별피부노화', '주름발생시기', '백인흑인', '프랑스중국비교', '유색인종']::text[], 2024, 'hmnFl2hQ55Q-1', 'https://youtu.be/hmnFl2hQ55Q?t=190s', null, '2024-10-10 00:00:00+00'::timestamptz, '2024-10-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부색이 짙으면 왜 노화가 늦게 오나요?$AAQ$, $AAA$피부색이 짙은 사람은 멜라닌이 자연 자외선 차단제 역할을 하고 진피가 더 두꺼워 노화가 느립니다. 유색인종 피부의 멜라닌 색소는 백인보다 양과 농도가 훨씬 진해, 천연적으로 평생 자외선 차단제를 바르고 있는 것과 비슷한 효과를 내요.

흑인의 피부에는 백인에 비해 멜라닌이 약 두 배 정도 많고, **이를 SPF 수치로 환산하면 흑인은 약 13.4 정도의 자연 SPF를, 동아시아인은 약 3-4 정도의 자연 SPF**를 가지고 있다고 합니다. 또 **유색인종은 진피가 더 두껍고 단단해 주름이 덜 생기는 구조적 장점**도 있어요. 두껍고 탄탄한 돼지껍데기가 얇고 흐물흐물한 것보다 주름이 덜 생기는 것과 같은 원리입니다. 다만 피부가 두꺼우면 중력에 의한 처짐이 심하고, 멜라닌이 활발해 색소침착도 더 잘 생기는 단점이 있어 장단점이 함께 있습니다.$AAA$, array['멜라닌자외선차단', '진피두께', 'SPF수치', '처짐색소침착', '유색인종특성']::text[], 2024, 'hmnFl2hQ55Q-2', 'https://youtu.be/hmnFl2hQ55Q?t=257s', null, '2024-10-10 00:00:00+00'::timestamptz, '2024-10-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부색이 하얀 게 젊어 보이는 게 맞나요?$AAQ$, $AAA$무조건 하얀 것보다 피부 톤이 고른 것이 젊어 보이는 데 더 중요합니다. 우리나라는 뽀얗고 하얀 피부를 선호하는 경향이 있지만, 사실 피부가 하얀 사람이든 까만 사람이든 20대 때보다 50대 때 기미·잡티·검버섯이 더 많이 생겨요.

어릴 때 깨끗했던 피부가 나이가 들면서 얼룩덜룩해지는데, **이런 색소 변화를 제거해 주면 과거의 좋았던 피부처럼 보여 더 젊어 보이는 효과**가 생깁니다. 즉 사람들이 "하얀 피부 = 젊어 보임"이라고 느끼는 것은 톤 균일성 회복에 가까운 것이지 단순한 밝기 자체는 아니에요. 물론 **피부색이 밝으면 좀 더 맑아 보이고 환해 보이는 효과는 있지만, 균일한 톤이 동안 인상을 만드는 핵심**입니다. 색소침착 관리나 톤 정돈 케어가 단순 미백보다 더 효과적일 수 있는 이유입니다.$AAA$, array['하얀피부동안', '피부톤', '색소침착', '톤균일', '기미잡티']::text[], 2024, 'hmnFl2hQ55Q-3', 'https://youtu.be/hmnFl2hQ55Q?t=395s', null, '2024-10-10 00:00:00+00'::timestamptz, '2024-10-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$타고난 피부와 상관없이 노화를 늦추는 방법은?$AAQ$, $AAA$잘 먹고, 잘 자고, 잘 가리는 세 가지를 꾸준히 실천하면 인종에 관계없이 피부 노화를 늦출 수 있습니다. 핵심은 DNA 복구 능력을 높이는 것인데, 자외선·활성산소로 손상된 DNA를 잘 복구할수록 노화가 느려져요.

첫째, **녹차에 많이 들어 있는 폴리페놀 같은 항산화 성분이 손상된 DNA 복구에 도움**이 되니 신선식품을 많이 드세요. 둘째, 잠을 잘 때 DNA 복구 과정이 일어나기 때문에 충분한 수면이 필수입니다. 셋째, **동아시아인은 자연 SPF가 3-4 정도로 흑인의 13.4보다 낮기 때문에** 자외선 차단제를 열심히 발라 가려 줘야 해요. 또 **나이아신아마이드·레티놀·비타민C·비타민E 같은 항산화 성분이 들어간 화장품을 바르면 DNA 복구에 도움이 되어 피부 노화를 막는 데 효과적**입니다.$AAA$, array['DNA복구', '항산화성분', '수면자외선차단', '기능성화장품', '노화예방']::text[], 2024, 'hmnFl2hQ55Q-4', 'https://youtu.be/hmnFl2hQ55Q?t=505s', null, '2024-10-10 00:00:00+00'::timestamptz, '2024-10-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스트레스가 피부에 어떻게 영향을 미치나요?$AAQ$, $AAA$스트레스는 코티졸 분비를 통해 염증 반응을 일으키고 피부 장벽을 무너뜨립니다. 우리가 스트레스를 받으면 코티졸이라는 스트레스 호르몬이 뇌에서 분비되고, 이것이 피부에서 염증 물질들을 마구 내보냅니다. 거기에 피부 장벽이 무너지면서 아토피, 건선, 여드름 같은 질환으로 가는 스위치가 켜집니다.

코티졸은 또한 **콜라겐 생성까지 저하시켜** 피부 노화를 앞당깁니다. 실제로 진료실에서 차트의 나이와 얼굴이 매치되지 않는 경우, 젊을 때 마음고생을 많이 한 분들이 적지 않습니다. 만성 두드러기 환자가 스트레스 원인이 사라지면 거짓말처럼 낫는 경우도 있고, **공부하려고 자리에 앉으면 가렵다가 긁으면 더 가려워지는 현상**도 모두 스트레스 때문입니다. 환자분들은 이런 가려움을 스트레스 때문이라고 잘 인식하지 못하는 경우가 많아요.$AAA$, array['스트레스', '코티졸', '피부장벽', '콜라겐', '염증']::text[], 2024, 'LKMHCgogWao-1', 'https://youtu.be/LKMHCgogWao?t=854s', null, '2024-10-11 00:00:00+00'::timestamptz, '2024-10-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부과에서 항우울제를 처방하기도 하나요?$AAQ$, $AAA$피부과에서도 필요한 경우 항우울제를 처방하기도 합니다. 자주 있는 일은 아니지만, 환자의 마음 상태와 스트레스가 피부를 악화시킨다고 판단될 때 사용합니다. 특히 만성질환처럼 치료에 대한 반응이 잘 없을 때 도움이 됩니다.

실제로 **홍조 환자분들에게 항우울제 처방을 가끔씩** 하는데, 레이저나 먹는 약 같은 적절한 치료에도 반응이 더딘 분들에게 함께 처방하면 경과가 훨씬 좋은 경우가 있습니다. 항우울제가 피부로 분포되는 신경에서 나오는 전달물질을 차단해 염증을 감소시키기 때문이에요. 건선처럼 자존감과 대인관계에 영향을 주는 질환은 **피부과 치료만으로는 한계가 있어 정신건강의학과 면담을 권하기도** 합니다. 감정적 스트레스가 피부 질환을 더 악화시키므로 함께 접근하는 거죠.$AAA$, array['항우울제', '홍조', '건선', '피부과치료', '정신건강']::text[], 2024, 'LKMHCgogWao-2', 'https://youtu.be/LKMHCgogWao?t=204s', null, '2024-10-11 00:00:00+00'::timestamptz, '2024-10-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부를 위해 몇 시에 자는 게 좋나요?$AAQ$, $AAA$피부 건강을 위해서는 11시 전에 잠드는 것이 좋습니다. 성인이 11시 전에 잔다는 게 쉽지 않지만 정말 필요합니다. 잠만 잘 자도 피부과 오는 환자의 반이 줄 거라고 말할 정도로 수면은 중요합니다.

어릴 때 성장 호르몬이 많이 나오려면 일찍 자라고 하듯이, 일정 시간이 넘어가면 우리 몸에서 **스트레스 호르몬들이 더 많이 분비되어** 피부 장벽을 무너뜨립니다. 그 결과 피부가 푸석푸석해지고 건조해지는 느낌이 들게 되죠. 더불어 SNS 사용 시간을 줄이는 디지털 디톡스도 권합니다. 하루에 보내는 시간 중 10분, 20분이라도 SNS 보는 시간을 조금씩 줄여 나가면 됩니다. **SNS에 노출될수록 남들과 비교하게 되고 상대적 박탈감에서 오는 스트레스가 크기** 때문이에요.$AAA$, array['수면', '11시전취침', '디지털디톡스', 'SNS', '스트레스관리']::text[], 2024, 'LKMHCgogWao-3', 'https://youtu.be/LKMHCgogWao?t=458s', null, '2024-10-11 00:00:00+00'::timestamptz, '2024-10-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$건선 환자는 어떤 치료를 같이 받는 게 좋나요?$AAQ$, $AAA$건선 환자는 피부과 치료와 함께 정신건강 관리를 병행하는 것이 권장됩니다. 건선은 다른 사람이 봤을 때 혐오감을 느낄 정도로 심한 경우도 있어, 자존감이 떨어지고 대인관계 유지가 힘들어집니다. 자식과 목욕탕에 한 번 가는 게 소원이라는 분도 있을 정도예요.

이런 분들은 **피부과적인 치료만 계속 하는 것으로는 충분하지 않습니다.** 피부 질환을 가진 분들에게 오는 감정적 스트레스가 다시 그 질환을 악화시키는 악순환이 생기기 때문입니다. 그래서 필요하면 **정신건강의학과에서 면담을 받거나 기분에 변화를 줄 수 있는 약제를 복용하는** 것도 도움이 됩니다. 마음의 안정과 평화가 치료 경과에 중요한 영향을 미칩니다. SNS 디톡스, 충분한 수면, 규칙적 생활도 함께 가져가시는 게 좋아요.$AAA$, array['건선', '정신건강', '대인관계', '감정적스트레스', '복합치료']::text[], 2024, 'LKMHCgogWao-4', 'https://youtu.be/LKMHCgogWao?t=386s', null, '2024-10-11 00:00:00+00'::timestamptz, '2024-10-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$때를 미는 게 피부에 좋은가요 나쁜가요?$AAQ$, $AAA$때를 미는 것은 단기적으로 좋아 보일 수 있지만 장기적으로는 피부에 좋지 않습니다. 때를 밀면 피부가 매끈매끈해지고 약간 밝아 보이는 단기적 효과가 있는 것은 사실이에요. 죽은 세포로 쌓인 칙칙한 각질이 한꺼풀 벗겨지고 밑의 환한 피부가 드러나기 때문입니다.

하지만 **각질을 억지로 밀어내는 것 자체가 피부에 좋을 게 없어요.** 각질층은 외부 유해물질과 세균을 막고 몸 안 수분이 증발하는 것을 막아주는 보호막 역할을 합니다. 자꾸 밀어내면 이 기능이 제대로 작동하지 못해 피부 장벽이 약해지고, 수분이 빠져나가 건조해지면서 가렵고 민감해질 수 있습니다. **피부과 의사 중에 때 미는 걸 추천하는 선생님은 아마 없을 거예요.** 때 밀고 나서 벌게져 따갑다고 내원하시는 분도 적지 않습니다.$AAA$, array['때밀이', '각질제거', '피부장벽', '보호막', '건조']::text[], 2024, 'BC7TIhNz4Xw-1', 'https://youtu.be/BC7TIhNz4Xw?t=188s', null, '2024-10-16 00:00:00+00'::timestamptz, '2024-10-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$꼭 때를 밀고 싶다면 얼마나 자주 해야 하나요?$AAQ$, $AAA$꼭 때를 밀고 싶다면 1년에 2번 정도, 명절 때 정도가 적당합니다. 피부에는 사실 억지로 각질을 벗겨내지 않아도 자연적으로 각질이 탈락하는 주기가 있어요. 한 달마다 피부 아래에서 새로운 세포들이 올라와 오래된 각질이 알아서 저절로 탈락하므로 이 주기를 지켜주는 게 좋습니다.

때를 밀 때는 **너무 세게 밀지 않도록 조심해야 하고**, 거칠거칠한 이태리 타올보다는 부드러운 샤워타올이나 손을 이용해 부드럽게 씻어내는 것이 권장됩니다. 그리고 **때 밀고 나서는 보습제를 충분히 발라** 손상된 피부 장벽 회복에 도움을 주세요. 로션보다는 크림이 촉촉하니 더 좋고, 세라마이드, 콜레스테롤, 지방산 같은 성분이 포함된 제품이 피부 장벽 강화에 도움을 줄 수 있습니다.$AAA$, array['때밀이주기', '보습제', '세라마이드', '각질탈락주기', '샤워타올']::text[], 2024, 'BC7TIhNz4Xw-2', 'https://youtu.be/BC7TIhNz4Xw?t=333s', null, '2024-10-16 00:00:00+00'::timestamptz, '2024-10-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$정강이 각질이 심하게 일어나는데 어떻게 해야 하나요?$AAQ$, $AAA$정강이 각질이 심한 분들은 밀어내지 말고 보습제를 발라주는 게 좋습니다. 정강이 쪽은 다른 피부 부위보다 좀 더 건조해서 각질이 심해지는 경우가 많습니다. 피부를 물에 불려서 각질을 밀어내면 그때는 깨끗해 보이지만 며칠 지나면 또 그대로 돌아가요.

**계속 밀어내면 피부 자극만 되니까** 밀어내는 대신 보습제를 꾸준히 바르는 것이 권장됩니다. 보습제는 로션보다 크림이 더 촉촉해서 건조한 부위에 적합하고요. 또한 피부 장벽 사이사이를 채우고 있는 기름 성분인 **세라마이드, 콜레스테롤, 지방산이 포함된 제품이 피부 장벽 강화에** 도움을 줍니다. 어떤 제품을 고를지 너무 고민하지 않아도 됩니다. 집에 있는 바디로션이나 바디크림 아무거나 바르는 것이 아무것도 안 바르거나 각질을 밀어내는 것보다 10배는 더 도움이 됩니다.$AAA$, array['정강이각질', '건조피부', '바디크림', '세라마이드', '보습']::text[], 2024, 'BC7TIhNz4Xw-3', 'https://youtu.be/BC7TIhNz4Xw?t=393s', null, '2024-10-16 00:00:00+00'::timestamptz, '2024-10-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레이저 제모는 언제부터 사용되기 시작했나요?$AAQ$, $AAA$레이저 제모는 1990년대에 도입되어 1995년에 정식으로 승인되면서 본격적으로 보급되었습니다. 1990년대에 들어서 빛을 이용해 선택적으로 모낭을 파괴하는 방식의 레이저 제모가 시작되었어요. 덕분에 그전까지 아프고 오래 걸렸던 제모가 몇 분 만에 쉽게 가능해졌습니다.

레이저 제모 이전에는 1900년대 초반부터 **영구 제모 방법으로 전기 분해법이 쓰였습니다.** 1875년 안과의사 찰스 미셸이 속눈썹 안에 얇은 바늘을 넣고 전류를 흘려 속눈썹이 다시 나지 않게 한 치료법에서 시작된 방식이에요. 그러나 **털 구멍 하나하나에 바늘을 찔러 통증이 심하고 다리 제모에 5시간에서 10시간이 걸렸습니다.** 그 한계를 넘어 등장한 것이 레이저 제모이며, 1995년 승인 이후 현재 가장 많이 사용되는 제모 방법 중 하나가 되었습니다.$AAA$, array['레이저제모', '모낭파괴', '전기분해법', '제모역사', '1995년승인']::text[], 2024, '8A78c7XN-cA-1', 'https://youtu.be/8A78c7XN-cA?t=326s', null, '2024-10-17 00:00:00+00'::timestamptz, '2024-10-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$전기 분해 제모법이 뭔가요?$AAQ$, $AAA$전기 분해법은 얇은 바늘을 모공에 찔러 전류를 흘려 털이 다시 나지 않게 하는 영구 제모 방식입니다. 1875년 안과의사 찰스 미셸이 발표한 논문에서 시작되었어요. 그는 눈을 찌르는 내향성 속눈썹을 치료하려고 속눈썹 안으로 얇은 바늘을 넣고 전류를 흘렸더니 속눈썹이 더 이상 나지 않더라는 사실을 발견했습니다.

이 원리를 응용해 1900년대 초반에는 영구 제모 방법으로 전기 분해법이 사용되었습니다. 그러나 **털이 난 구멍 하나하나에 바늘을 찔러야 해서 통증이 심했고**, 부위에 따라 시간도 매우 오래 걸렸습니다. 특히 **다리를 제모하는 데 5시간에서 10시간까지 걸릴 정도였어요.** 이러한 한계 때문에 1990년대 레이저 제모가 도입되면서 점차 주요 방식이 교체되었고, 1995년 레이저 제모가 정식 승인된 뒤로는 현재 가장 많이 사용되는 제모 방법 중 하나가 됐습니다.$AAA$, array['전기분해법', '영구제모', '찰스미셸', '통증', '내향성속눈썹']::text[], 2024, '8A78c7XN-cA-2', 'https://youtu.be/8A78c7XN-cA?t=296s', null, '2024-10-17 00:00:00+00'::timestamptz, '2024-10-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$겨드랑이 제모는 언제부터 유행하게 된 거예요?$AAQ$, $AAA$여성의 겨드랑이 제모는 20세기 초인 1908년 광고를 시작으로 유행하기 시작했습니다. 1908년부터 여성들이 겨드랑이 제모를 해야 한다는 인식을 심어주는 광고가 미국 패션잡지 하퍼스 바자에 실리기 시작했어요. 광고에는 제모크림을 사용하면 겨드랑이가 깨끗해진다고 쓰여 있었습니다.

이 광고를 보고 시장 기회를 포착한 회사가 바로 질레트입니다. **1915년 이전까지 남성용 면도기만 만들던** 질레트는 여성용 면도기 마이 레이디를 출시했고, **이게 진짜 대박이 나면서 면도기 시장이 2배로 커졌어요.** 또한 당시 패션의 변화도 영향을 미쳤습니다. 치마와 소매가 짧아지면서 깔끔한 피부가 더 중요해졌고, 그러면서 다리털 제모도 함께 시작되었습니다. 이렇게 광고와 면도기 산업, 패션 변화가 맞물려 겨드랑이와 다리 제모 문화가 자리 잡게 된 거예요.$AAA$, array['겨드랑이제모', '질레트', '면도기역사', '1908년', '패션변화']::text[], 2024, '8A78c7XN-cA-3', 'https://youtu.be/8A78c7XN-cA?t=240s', null, '2024-10-17 00:00:00+00'::timestamptz, '2024-10-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$울쎄라 시술 후 붓기는 며칠이나 가나요?$AAQ$, $AAA$울쎄라 시술 후 붓기는 보통 2~3주까지 지속될 수 있습니다. 원장님의 경우 송지효 저리가라 할 정도로 2주 동안 붓기를 달고 살았고, 결국 2주 뒤에 붓기가 빠졌다고 합니다. 그래서 시술 후 **중요한 약속은 2~3주 정도 피하시는 게 좋아요.**

붓기가 심하다는 건 그만큼 깊게 들어가 근막층이나 지방층에서 염증 반응이 활발하게 일어난다는 의미입니다. **수축이나 지방세포 파괴 같은 효과의 반증이기도** 해요. 다만 안 부었다고 효과가 없는 건 아닙니다. 사람마다 얼굴 피부 두께가 다르고, 보통 붓기는 깊게 많이 들어갔을 때 생기기 때문에 깊이 시술할 필요가 없는 분은 상대적으로 붓기가 적습니다. 부으면 효과가 정말 좋겠구나로, 안 부으면 깊게 시술하지 않아도 되는구나로 이해하시면 됩니다.$AAA$, array['울쎄라붓기', '다운타임', '근막층', '염증반응', '시술후일정']::text[], 2024, 'nkBnj2I3p_Q-1', 'https://youtu.be/nkBnj2I3p_Q?t=276s', null, '2024-10-21 00:00:00+00'::timestamptz, '2024-10-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$울쎄라 후 신경 손상은 얼마나 가나요?$AAQ$, $AAA$울쎄라 후 신경 손상은 일시적이며 보통 2~3주 정도면 회복됩니다. 원장님은 시술 후 시리얼을 먹는데 입에서 우유가 새고 양칫물이 질질 새는 경험을 했고, 거울을 보니 입술이 마음대로 움직이지 않았다고 합니다. 다행히 신경 손상이 **오래 가지 않고 일시적이며**, 원장님 경우는 2주 정도 지속됐습니다.

보통 **운동 신경은 3주 정도면 거의 돌아오고** 처음에만 어색하지 결국 적응하게 됩니다. 남들은 잘 알아보지 못하고 나만 아는 정도로 조금 불편하다가 2~3주 후 신경이 회복되는 과정을 따릅니다. 다만 붓기든 신경 손상이든 2~3주 정도 지속될 수 있기 때문에 울쎄라 후 2~3주는 중요한 약속을 잡지 않는 것이 권장됩니다. 시술 전 뒤에 중요한 일정이 없는지 확인하는 이유도 이 때문이에요.$AAA$, array['신경손상', '울쎄라부작용', '운동신경회복', '일시적부작용', '시술일정']::text[], 2024, 'nkBnj2I3p_Q-2', 'https://youtu.be/nkBnj2I3p_Q?t=414s', null, '2024-10-21 00:00:00+00'::timestamptz, '2024-10-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$울쎄라는 어떤 분에게 잘 맞는 시술인가요?$AAQ$, $AAA$울쎄라는 살이 통통하면서 처짐이 있거나 얼굴 면적이 넓은 분, 안면비대칭이 있는 분에게 잘 맞는 시술입니다. 처져서 팔자주름이 짙어 보이는 분, 남녀노소 할 것 없이 **얼굴 면적이 넙데데해서 날렵하게 다듬고 싶은 분**, 그리고 안면비대칭이 심한 분께 추천된다고 합니다.

원리상 울쎄라는 초음파를 근막층에 모아 살짝 익혀 처진 피부를 끌어올리고 모공도 쪼여줍니다. 원장님 시술 후 거울을 보니 갸름해지고 모공이 덜 두드러져 보였으며, 비대칭 교정을 위해 **오른쪽은 깊은 3.0과 4.5팁으로, 왼쪽은 1.5팁으로** 시술해 한쪽 면적이 날아간 효과를 봤다고 합니다. 또한 시술 시 250~300샷을 시술하면 효과가 좋은 만큼 붓기도 동반되니, 시술 후 2~3주는 중요한 약속을 잡지 않는 것이 권장됩니다.$AAA$, array['울쎄라적응증', '안면비대칭', '팔자주름', '얼굴윤곽', '처진피부']::text[], 2024, 'nkBnj2I3p_Q-3', 'https://youtu.be/nkBnj2I3p_Q?t=458s', null, '2024-10-21 00:00:00+00'::timestamptz, '2024-10-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$울쎄라 시술은 얼마나 아픈가요?$AAQ$, $AAA$울쎄라는 안 아프다고 하면 거짓말일 정도로 통증이 있는 시술입니다. 옛날에는 마취 없이도 받았다고 하지만, 원장님조차 시술 중 너무 아파서 마취를 요청할 만큼 통증이 강합니다. **시술하는 선생님들이 통증과 싸움을 굉장히 많이 하는** 시술이에요.

그래서 통증을 완화하기 위해 여러 방법이 사용됩니다. **마취 크림을 40~50분 이상 오래 바르거나** 수면 마취를 하는 병원도 있고, 비수면 호흡 마취를 적극적으로 활용하는 병원도 있습니다. 또한 부위에 따라 사용하는 팁이 다른데, 깊은 부위는 3.0이나 4.5팁이 들어가고, 얕은 부위는 더 짧은 1.5팁이 사용됩니다. 1.5팁과 4.5팁을 비교하면 1.5팁이 훨씬 짧아요. 시술자가 부위별로 깊이를 조절하면서 통증을 관리하므로 너무 아프면 시술 중에 알리는 것이 좋습니다.$AAA$, array['울쎄라통증', '마취크림', '호흡마취', '수면마취', '팁크기']::text[], 2024, 'nkBnj2I3p_Q-4', 'https://youtu.be/nkBnj2I3p_Q?t=85s', null, '2024-10-21 00:00:00+00'::timestamptz, '2024-10-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$울쎄라, 써마지, 티타늄은 어떻게 다른가요?$AAQ$, $AAA$울쎄라, 써마지, 티타늄은 작용하는 피부층과 사용 에너지가 달라 효과가 서로 다른 시술입니다. 울쎄라는 초음파로 가장 깊은 근막층에 열을 줘 처진 피부를 끌어올리고, 써마지는 고주파로 진피층의 콜라겐을 재생시켜 탄력을 줍니다. 티타늄은 레이저로 빛을 사용해 표피, 진피, 일부 지방층까지 열을 전달합니다.

사용 원리도 다른데요. 초음파는 **돋보기로 햇빛을 모아 종이를 태우듯** 일정 깊이에 빛을 집속시켜 그 부분 온도를 확 올립니다. 고주파인 써마지는 진피 콜라겐에 열을 줘 재생을 유도하고, 티타늄은 **세 종류 빛을 한꺼번에 쏴서 여러 층에 동시에 열을 전달**합니다. 효과 발현 시점도 차이가 있어 울쎄라와 써마지는 콜라겐 재생이 일어나며 한 달 정도까지 변화가 잘 안 보이지만, 티타늄은 시술 중 한쪽 얼굴에 먼저 한 뒤 거울 보면 바로 효과가 보입니다.$AAA$, array['리프팅비교', '울쎄라', '써마지', '티타늄', '초음파고주파레이저']::text[], 2024, 'VMsll3EJg8c-1', 'https://youtu.be/VMsll3EJg8c?t=125s', null, '2024-10-23 00:00:00+00'::timestamptz, '2024-10-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$처짐이 심하면 울쎄라, 잔주름이 많으면 어떤 시술이 좋나요?$AAQ$, $AAA$처짐이 심한 분에게는 초음파 시술인 울쎄라, 잔주름이 많은 분에게는 고주파 시술인 써마지가 더 적합합니다. 손가락 두 개로 팔자주름 옆 살과 턱 밑 살을 잡았을 때 **두둑하게 많이 잡히면 처짐이 심한 분**이고, 이런 경우 처진 피부를 끌어올리는 초음파 시술인 울쎄라가 효과가 좋습니다.

반대로 잡히는 게 별로 없고 **눈가나 입가 잔주름이 많거나 모공이 늘어져 있다면** 피부 탄력이 부족한 경우입니다. 이런 분들은 초음파보다 써마지 같은 고주파 시술이 더 효과적이에요. 또한 친구 추천으로 자주 듣는 인모드는 고주파지만 방식이 좀 다릅니다. 집게 같은 판 두 개로 살을 빨아 당기면서 고주파 열을 주고 마지막에 센 에너지로 지방을 줄이는 방식이라 턱살, 볼살이 많은 분께 효과가 좋습니다. 본인 피부 상태에 맞춰 선택하는 것이 가장 좋아요.$AAA$, array['처짐', '잔주름', '리프팅선택', '인모드', '피부진단']::text[], 2024, 'VMsll3EJg8c-2', 'https://youtu.be/VMsll3EJg8c?t=290s', null, '2024-10-23 00:00:00+00'::timestamptz, '2024-10-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$티타늄 리프팅은 어떤 분에게 좋나요?$AAQ$, $AAA$티타늄은 효과가 바로 보여야 하거나 신경 손상 위험이 있는 부위 처짐이 심한 분에게 좋은 시술입니다. 가장 큰 특징은 **시술 중 한쪽 얼굴에 먼저 한 뒤 거울 보면 바로 효과가 보이는** 점이에요. 그래서 당장 내일 일정이 있거나 연예인분들이 촬영을 앞두고 있을 때도 받을 수 있습니다.

또한 심술보 부위처럼 **울쎄라는 신경 손상 위험으로 어려운 부위에 티타늄은 적용 가능**합니다. 심술보에 신경이 지나가기 때문에 울쎄라는 시술이 제한되지만 티타늄은 시술이 가능해서 이 부위 처짐이 심한 분들께 좋습니다. 실리프팅을 권유받았는데 실리프팅이 싫다는 분들께도 티타늄이 자주 추천됩니다. 오리지널 장비는 티타늄이며 비슷한 국산 장비로는 3D엔코어가 있고, 이 두 제품밖에 없다고 합니다.$AAA$, array['티타늄', '즉각효과', '심술보', '신경손상', '실리프팅대안']::text[], 2024, 'VMsll3EJg8c-3', 'https://youtu.be/VMsll3EJg8c?t=503s', null, '2024-10-23 00:00:00+00'::timestamptz, '2024-10-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$오리지널 장비와 국산 장비는 효과 차이가 있나요?$AAQ$, $AAA$오리지널 장비가 효과 입증 면에서 가장 확실하지만 국산 장비도 좋은 대안이 될 수 있습니다. 써마지와 울쎄라는 수입 오리지널 장비라서 가격이 비싸지만, 효과가 가장 많이 입증되어 있어 예산이 충분하고 확실한 브랜드를 원한다면 권할 만합니다. 원장님은 **오리지널은 오리지널이라는 생각을 갖고** 있다고 합니다.

비유하자면 **스타벅스가 맛과 질이 보장돼 브랜드를 믿고 마시는** 것과 비슷하다는 설명입니다. 다만 한국 회사 기술력이 굉장히 좋아 비슷한 원리의 장비가 많이 출시되어 있습니다. 고주파에서는 올리지오, 덴서티, 텐서마, 볼뉴머, 세르프가 있고, 다른 고주파 방식으로 오푸스, 3DEEP, 튠페이스가 있습니다. 초음파에서는 리니어지, 슈링크, 텐쎄라, 더블로가 비슷한 장비입니다. 국산 장비도 계속 업그레이드되고 시술자에 따라 좋은 효과를 낼 수 있어 좋은 대안이 됩니다.$AAA$, array['오리지널장비', '국산장비', '올리지오', '슈링크', '장비선택']::text[], 2024, 'VMsll3EJg8c-4', 'https://youtu.be/VMsll3EJg8c?t=353s', null, '2024-10-23 00:00:00+00'::timestamptz, '2024-10-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$젊어 보이면 정말 오래 사나요?$AAQ$, $AAA$젊어 보이는 사람일수록 더 오래 산다는 연구 결과가 있습니다. 쌍둥이 1800명을 대상으로 한 큰 연구에서 사람들에게 사진을 보여주고 몇 살 같아 보이냐고 물어 외모 나이를 평가한 뒤, 그 쌍둥이들이 언제 사망하는지 관찰한 결과예요. **젊어 보이는 사람일수록 더 오래 살았다는** 결과가 나왔습니다.

구체적으로는 본인의 실제 나이보다 **외모 나이가 한 살 더 많아 보일 때마다 사망 위험이 8% 정도 증가**했다고 합니다. 다만 어디까지나 통계적으로 추정되는 것이며 실제 수명은 유전적 요인, 생활 습관, 환경 등 다양한 요인의 영향을 받습니다. 또한 이란성 쌍둥이는 유전자가 다른데도 젊어 보이는 사람이 더 오래 살았다는 결과가 있어, 외모와 건강 사이의 연결이 단순한 외형 차원을 넘어선다는 점이 시사됩니다.$AAA$, array['동안', '수명', '쌍둥이연구', '외모나이', '건강지표']::text[], 2024, 'loiUGTpgum4-1', 'https://youtu.be/loiUGTpgum4?t=151s', null, '2024-10-24 00:00:00+00'::timestamptz, '2024-10-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$텔로미어가 동안과 어떤 관련이 있나요?$AAQ$, $AAA$텔로미어가 길수록 동안으로 보이며, 세포 나이가 젊다는 의미입니다. 텔로미어는 염색체 끝에 붙어 염색체를 보호하는 역할을 하는데, **노화가 진행될수록 텔로미어의 길이가 점점 짧아져요.** 즉 텔로미어 길이는 우리 몸이 얼마나 젊은지를 보여주는 지표가 됩니다.

연구에서 외관상 젊어 보이는 사람들의 염색체를 관찰해 봤더니 **실제로 텔로미어의 길이가 더 길었다는 결과가** 나왔습니다. 이는 어려 보이는 사람들이 단순히 외형만 젊은 게 아니라 세포 나이도 젊다는 의미예요. 그래서 젊어 보임은 신체 기능과 두뇌 건강을 의미하는 인지 기능, 그리고 세포 수준의 노화 세 가지와 연관돼 있다고 합니다. 단순히 피부 주름이 없고 팽팽한 것이 아니라 건강 상태, 에너지, 활력, 인지 기능이 모두 합쳐져 젊어 보이게 만드는 것입니다.$AAA$, array['텔로미어', '염색체', '세포노화', '동안', '건강지표']::text[], 2024, 'loiUGTpgum4-2', 'https://youtu.be/loiUGTpgum4?t=350s', null, '2024-10-24 00:00:00+00'::timestamptz, '2024-10-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$젊어 보이기 위해 어떤 생활습관이 좋은가요?$AAQ$, $AAA$젊어 보이려면 외모 관리뿐 아니라 운동, 수면, 스트레스 관리, 금연·절주 같은 생활습관이 중요합니다. 외모를 가꾸는 것에만 국한해서는 안 되고, 우리 몸의 전반적인 건강 상태가 외모로 나타나기 때문에 그걸 좋아지게 하는 것이 더 중요해요.

원장님은 **일주일에 필라테스 한 번, PT 한 번씩 두 번은 꼭 챙겨서 운동**하고, 어딜 가든 선크림 사수와 좋은 화장품 사용, 좋아하는 시술을 받습니다. 정신 건강을 위해 **혼자 있는 시간을 일주일에 1~2시간 정도 가지며** 책을 읽거나 끄적이는 시간을 가진다고 합니다. 워런 버핏은 식습관은 콜라 5병에 햄버거를 즐기는 등 좋지 않지만 잠자는 걸 좋아해 8시간 이상 자고, 친구들과 게임하며 시간을 보내고, 하루 5~6시간씩 책을 읽고 술과 담배를 한 번도 안 했다고 합니다. 결국 내 자신을 사랑하는 것이 자연스럽게 외모로 표현됩니다.$AAA$, array['생활습관', '운동', '수면', '금연절주', '정신건강']::text[], 2024, 'loiUGTpgum4-3', 'https://youtu.be/loiUGTpgum4?t=474s', null, '2024-10-24 00:00:00+00'::timestamptz, '2024-10-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$위험한 점은 어떻게 구별하나요?$AAQ$, $AAA$위험한 점은 ABCDE 법칙을 통해 식별할 수 있습니다. 흑색종을 진단하려면 원래 조직검사를 해야 하지만 보이는 점마다 다 할 수는 없기 때문에, 위험한 점을 가려내는 데 도움을 주는 ABCDE 법칙이 사용됩니다.

A는 Asymmetry, 점을 반으로 접었을 때 대칭되지 않고 양쪽이 다른 모양인 비대칭을 뜻해요. B는 Border, 경계가 매끈하지 않고 불규칙하거나 울퉁불퉁한 경우입니다. **C는 Color로 점 안에서 여러 가지 색을 보이는 경우**, D는 Diameter로 지름이 6mm 이상인 경우, **E는 Evolving 변화로 갑자기 크기·색·모양이 변하는 경우**를 말합니다. 손바닥, 발바닥에 점이 있다고 무조건 걱정할 필요는 없으며, ABCDE 법칙을 이용해 점을 잘 살펴보고 악성을 의심할 만한 소견이 있거나 잘 모를 때 가까운 피부과 전문의 진료를 받는 것이 권장됩니다.$AAA$, array['흑색종', 'ABCDE법칙', '위험한점', '조직검사', '점감별']::text[], 2024, 'heotGQCv6Rc-1', 'https://youtu.be/heotGQCv6Rc?t=343s', null, '2024-10-25 00:00:00+00'::timestamptz, '2024-10-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$흑색종은 얼마나 위험한 질환인가요?$AAQ$, $AAA$흑색종은 늦게 발견하면 치사율이 무려 75% 정도에 이르는 무서운 질환입니다. 흑색종은 점처럼 보이지만 사실은 피부암이며 **초기에 발견하면 대부분 완치되지만**, 늦게 발견할 경우 치명적이라는 점에서 조기 발견이 매우 중요합니다.

피부에 발생하는 3대 암은 기저세포암, 편평세포암, 흑색종이며 앞 두 가지는 햇빛을 많이 받는 부위에 주로 생기고 치사율이 낮은 편입니다. 그러나 **가장 예후가 안 좋은 흑색종은 발생 부위 양상도 달라요.** 서양에서는 흑색종도 햇빛 노출 부위에 잘 생기는 반면, **우리나라 사람을 포함한 동양인들은 손바닥, 발바닥, 발가락에 생기는 경향이** 있습니다. 손발에 가해지는 물리적 자극이나 압력이 영향을 준다고 보고 있어요. 그래서 손발에 점이 생기면 무조건 빼야 한다는 말이 나온 것이지만, ABCDE 법칙으로 살펴 의심스러우면 진료를 받으면 됩니다.$AAA$, array['흑색종', '치사율', '피부암', '동양인흑색종', '손발점']::text[], 2024, 'heotGQCv6Rc-2', 'https://youtu.be/heotGQCv6Rc?t=288s', null, '2024-10-25 00:00:00+00'::timestamptz, '2024-10-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$튀어나오거나 털이 난 점은 꼭 빼야 하나요?$AAQ$, $AAA$튀어나온 점이나 털이 난 점은 꼭 제거할 필요는 없습니다. 미용적인 이유로 제거를 원하는 분이 많지만 의학적으로 반드시 빼야 하는 점은 아닙니다. 다만 **털이 난 점은 털이 주변 털보다 굵고 빨리 자라나 불편**할 수 있어 제거를 고려하기도 합니다.

이런 점들은 주로 복합 모반이나 진피내모반인 경우가 많은데요. 일반적인 평평한 점보다 **훨씬 깊이 자리하는 점이기 때문에 레이저로 제거할 경우 한 번에 제거되지 않고 여러 번에 걸쳐서** 제거가 필요합니다. 또는 수술적 방법으로 제거하기도 합니다. 그래서 다른 점보다 제거 후 흉터가 남을 확률이 높은 편이에요. 위험한 점이 아닌 한 무조건 제거할 필요는 없지만, 제거를 결정한다면 흉터 가능성과 시술 횟수에 대해 미리 이해하고 진행하는 것이 좋습니다.$AAA$, array['복합모반', '진피내모반', '점제거', '레이저제거', '흉터']::text[], 2024, 'heotGQCv6Rc-3', 'https://youtu.be/heotGQCv6Rc?t=248s', null, '2024-10-25 00:00:00+00'::timestamptz, '2024-10-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$티타늄 리프팅은 울쎄라·써마지와 어떻게 다른가요?$AAQ$, $AAA$티타늄 리프팅은 **한 번에 세 가지 빛이 동시에 나오는** 점에서 울쎄라·써마지와 본질적으로 다른 시술입니다. 일반 리프팅 장비는 한 가지 에너지만 나와 효과도 한 가지인 반면, 티타늄은 리프팅·쫀쫀함·미백 효과가 한꺼번에 납니다.

다만 단일 에너지 장비는 특정 피부층에 더 확실한 효과를 줍니다. 울쎄라는 처진 부분을 달라붙게 하고 써마지는 피부 결을 쫀쫀하게 만들어요. 효과 지속 기간도 달라서 **울쎄라·써마지는 보통 1년에 한 번이지만 티타늄은 1년까지 가지 않는 편입니다**. 따라서 티타늄은 한 달 간격 3회 집중 시술 후 6개월~1년 단위로 관리받는 방식이 권장됩니다.$AAA$, array['티타늄리프팅', '울쎄라비교', '써마지비교', '복합효과리프팅']::text[], 2024, 'Vl4YVcggedQ-1', 'https://youtu.be/Vl4YVcggedQ?t=46s', null, '2024-10-29 00:00:00+00'::timestamptz, '2024-10-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$티타늄 리프팅은 몇 회 받아야 효과가 있나요?$AAQ$, $AAA$티타늄 리프팅은 **한 달에 한 번씩 세 번 받고**, 그 이후에는 6개월에서 1년에 한 번 정도 관리받는 방식이 일반적으로 권장됩니다. 정해진 주기가 있는 건 아니고 에너지를 어느 부위에 얼마나 썼는지에 따라 달라질 수 있습니다.

피부 상태에 따라 **3~4개월에 한 번씩 꾸준히 받으시라고 말씀드리기도 합니다**. 이를 꽃밭에 비유하면 초반 3회는 잡초 뽑고 밭 갈고 꽃 심는 단계이고, 이후는 가끔 물·비료 주는 유지 단계예요. 또 이 시술의 특징 중 하나는 효과가 1~2주 안에 빨리 나타난다는 점이라, 1~2주 뒤 중요한 일정이 있는 분들도 받기 좋습니다.$AAA$, array['티타늄리프팅', '시술횟수', '재시술주기', '효과시점']::text[], 2024, 'Vl4YVcggedQ-2', 'https://youtu.be/Vl4YVcggedQ?t=222s', null, '2024-10-29 00:00:00+00'::timestamptz, '2024-10-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$티타늄 리프팅은 누구에게 잘 맞나요?$AAQ$, $AAA$티타늄 리프팅은 **30대부터 50대 초반까지의 연령대**에 잘 맞는 시술입니다. 이 나이대에는 처짐, 어두운 톤, 푸석함 같은 여러 고민이 동시에 생기는데, 세 가지 빛으로 이를 한 번에 다룰 수 있어 적합합니다.

특히 **입 옆이 처지는 심술보 부위는 신경이 지나가 울쎄라 시술이 어려운데**, 티타늄으로는 접근이 가능합니다. 실리프팅을 꺼리시는 분들의 대안이 되기도 해요. 또 1~2주 뒤 중요한 일이 있어 빠른 효과가 필요한 분들에게도 좋은데, 효과가 1~2주 안에 나타나는 특징이 있기 때문입니다. 다만 시술 시 통증이 있을 수 있어 의사와 충분히 상담 후 받는 것이 좋습니다.$AAA$, array['티타늄리프팅', '적응증', '심술보', '연령대']::text[], 2024, 'Vl4YVcggedQ-3', 'https://youtu.be/Vl4YVcggedQ?t=263s', null, '2024-10-29 00:00:00+00'::timestamptz, '2024-10-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$티타늄 리프팅 부작용은 어떤 게 있나요?$AAQ$, $AAA$티타늄 리프팅에서 가장 흔한 부작용은 **시술 후 피부가 붉어지는 증상**입니다. 열이 들어가 일시적으로 나타나는 반응으로 금방 사라져 크게 신경 쓸 부분은 아닙니다.

두 번째는 드물지만 시술 후 며칠 붓는 분들이 있어, 시술 전 의사와 일정 조율을 해두면 좋아요. 세 번째로 아주 드물게 **화상이나 색소침착이 생길 수 있으나 시술자가 잘 조절하면 거의 발생하지 않습니다**. 레이저가 닿는 부위는 차갑게 쿨링되어 차가운 돌덩이를 댄 느낌에 가깝기 때문에 겉면 화상은 잘 생기지 않습니다. 시술 후에는 평소 쓰던 재생크림이나 보습크림을 바르면 충분합니다.$AAA$, array['티타늄리프팅', '부작용', '화상위험', '색소침착']::text[], 2024, 'Vl4YVcggedQ-4', 'https://youtu.be/Vl4YVcggedQ?t=406s', null, '2024-10-29 00:00:00+00'::timestamptz, '2024-10-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아이 볼에 난 좁쌀 같은 게 여드름 아니라면 뭔가요?$AAQ$, $AAA$아이 볼에 난 좁쌀 모양의 트러블은 **여드름이 아니라 모공각화증일 가능성이 높습니다**. 모공각화증은 모공이 각질화된 상태로, 오래된 피부세포가 정상적으로 탈락하지 못하고 모공을 막아 피부가 거칠고 오돌토돌하게 보이는 질환입니다.

주로 팔 바깥쪽, 허벅지, 엉덩이에 잘 생기지만 얼굴에도 나타날 수 있습니다. 부모님 중 한 분에게 모공각화증이 있으면 **자녀에게 발생할 확률이 50% 정도로 유전적 요인이 가장 큽니다**. 아토피, 비만, 건조한 피부, 잦은 샤워, 강한 때밀기 같은 습관도 원인이 됩니다. 보통 20세까지 심해지다가 이후 완화되는 경향이 있어, 진단 후 관리 위주로 접근하는 것이 좋습니다.$AAA$, array['모공각화증', '닭살피부', '유전질환', '어린이피부']::text[], 2024, '5noTgaqr7Nc-1', 'https://youtu.be/5noTgaqr7Nc?t=14s', null, '2024-10-31 00:00:00+00'::timestamptz, '2024-10-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모공각화증 평생 안고 살아야 하나요?$AAQ$, $AAA$모공각화증은 **20세까지 심해지다가 나이 들수록 완화되어 정상피부로 돌아가기도 합니다**. 완전히 없앨 수는 없지만 꾸준한 관리로 충분히 매끄러운 피부 상태를 유지할 수 있는 질환입니다.

근본적인 치료법은 없으나 증상 악화를 막는 것이 핵심입니다. 가습기로 적정 실내습도를 유지하고 물을 충분히 마시며, **뜨거운 물 샤워나 때밀기 같은 강한 자극은 피해야 합니다**. 손으로 긁거나 뜯으면 색소침착이 남아 더 보기 안 좋아질 수 있어요. 관리에도 잘 해결되지 않으면 피부과에서 비타민A 외용제 처방을 받거나 필링·레이저 시술을 시도할 수 있지만, 재발 가능성이 있어 일상 관리가 가장 중요합니다.$AAA$, array['모공각화증', '자연호전', '관리방법', '예후']::text[], 2024, '5noTgaqr7Nc-2', 'https://youtu.be/5noTgaqr7Nc?t=167s', null, '2024-10-31 00:00:00+00'::timestamptz, '2024-10-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모공각화증 각질 제거는 어떻게 하면 좋을까요?$AAQ$, $AAA$모공각화증의 각질 제거는 **일주일에 1~2회 정도 AHA·BHA 같은 산 성분으로 부드럽게** 하는 것이 권장됩니다. 알갱이 큰 스크럽으로 물리적으로 밀어내기보다 화학적 각질 제거가 자극이 적어요.

너무 자주 하거나 강하게 하면 **오히려 피부를 자극해 증상을 악화시킬 수 있어 횟수 조절이 중요합니다**. 각질 제거 후에는 반드시 충분한 보습이 따라야 합니다. 샤워 후 물기가 마르기 전 보습제를 바르고 하루에도 여러 번 도포해 촉촉한 상태를 유지하세요. 모공각화증 부위에는 우레아 성분 제품이 많이 활용되는데, 약국에서 살 수 있는 의약품은 우레아 20% 정도, 일반 화장품은 10%까지 함유됩니다.$AAA$, array['모공각화증', '각질제거', 'AHA BHA', '우레아']::text[], 2024, '5noTgaqr7Nc-3', 'https://youtu.be/5noTgaqr7Nc?t=224s', null, '2024-10-31 00:00:00+00'::timestamptz, '2024-10-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모공각화증에 우레아 크림 어떻게 써야 자극 없이 좋을까요?$AAQ$, $AAA$우레아 농도가 높은 크림은 민감한 피부에 자극이 될 수 있어 **처음 사용할 때는 바디크림에 섞어 바르거나 2~3일에 한 번 정도** 적응해 가는 방식이 좋습니다. 본인 피부 상태를 살피며 빈도를 조절하세요.

데일리 관리는 **유리아 성분이 들어있는 일반 화장품으로 가볍게** 이어가시면 됩니다. 우레아는 각질을 연화시키고 수분을 끌어당기는 효과가 있어 각질을 부드럽게 녹이면서 보습도 동시에 잡아줍니다. 우레아 10%가 든 제로이드 리케닉 크림이나 스킨피디아 유리아텐 같은 제품은 세라마이드·히알루론산 같은 보습 성분이 함께 들어 있어 무릎·팔꿈치 등 피부가 두꺼운 부위에 활용하기 적합합니다.$AAA$, array['모공각화증', '우레아크림', '민감피부관리', '보습제']::text[], 2024, '5noTgaqr7Nc-4', 'https://youtu.be/5noTgaqr7Nc?t=384s', null, '2024-10-31 00:00:00+00'::timestamptz, '2024-10-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$가을·겨울 피부가 사막처럼 건조한 이유는?$AAQ$, $AAA$가을·겨울 피부가 건조한 이유는 크게 **보습 부족과 각질 과다 두 가지**로 나뉩니다. 대부분이 이 둘 중 하나에 해당하며, 두 원인이 겹치는 경우도 흔합니다.

건강한 피부는 오래된 각질이 저절로 떨어지고 새 피부가 올라오는 턴오버가 일어납니다. **20대는 4주, 30대부터 점점 느려져 40대는 6~8주까지 늘어나며** 각질이 쌓이기 쉬워요. 각질이 쌓이면 피부가 칙칙하고 결이 안 좋아 보이며 잔주름이 두드러집니다. 가을·겨울엔 건조 때문에 각질끼리 뭉쳐 더 도드라져 보이기도 합니다. 보습했는데도 답답하고 각질이 뜬다면 부드럽게 각질 제거를 해주는 게 좋습니다.$AAA$, array['피부턴오버', '겨울건조', '각질', '보습부족']::text[], 2024, 'sLiwrTPMDc8-1', 'https://youtu.be/sLiwrTPMDc8?t=14s', null, '2024-11-05 00:00:00+00'::timestamptz, '2024-11-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$효소 세안제는 일반 필링과 어떻게 다른가요?$AAQ$, $AAA$효소 세안제는 **파파야·파인애플에서 추출한 파파인·브로멜라인 효소**를 주성분으로 한 세안제로, 스크럽처럼 피부를 긁지 않고 단백질 분해 효소가 각질을 살살 녹여 제거한다는 점에서 일반 필링과 다릅니다.

자극이 적으면서 효과적으로 묵은 각질을 분해해주고 **피지를 없애주며 보습 효과까지 있어 겨울철 건조 피부에 부담 없이 사용 가능합니다**. 사용할 때는 가루를 바로 피부에 올리지 말고 물과 섞어 거품을 낸 뒤 부드럽게 마사지하고 미온수로 헹궈주세요. 얼굴 중앙부는 꼼꼼히 하되 피부가 얇은 가장자리는 힘 빼고 대충 해야 접촉 피부염을 예방할 수 있어요. 건성은 1~2주에 한 번, 지성은 주 1~2회가 적당합니다.$AAA$, array['효소세안제', '각질제거', '파파인', '브로멜라인']::text[], 2024, 'sLiwrTPMDc8-2', 'https://youtu.be/sLiwrTPMDc8?t=80s', null, '2024-11-05 00:00:00+00'::timestamptz, '2024-11-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$겨울 보습제 핵심 성분 '세콜지'가 뭔가요?$AAQ$, $AAA$세콜지는 **세라마이드, 콜레스테롤, 지방산의 줄임말**로, 가을·겨울 보습제에서 꼭 챙겨야 할 세 가지 핵심 성분입니다. 이 세 가지가 모이면 마치 벽돌과 시멘트처럼 피부에 튼튼한 장벽을 만들어줍니다.

피부 장벽이 튼튼해야 수분을 잃지 않고 촉촉함을 유지하는데, **겨울엔 차갑고 건조한 바람 때문에 피부 장벽이 망가지기 쉬워** 보습제로 세콜지를 보완해야 합니다. 제로이드 인텐시브 크림에는 세콜지 외에 글리세린·스쿠알란·올리브 오일·토코페릴아세테이트가 함께 들어 있어요. 더 건조해 따가울 때는 같은 라인의 인텐시브 리치 크림을 섞어 바르면 좋고, 지성 피부는 세라마이드·글리세린·감초가 든 바이오더마 세비엄 하이드라가 산뜻한 마무리감으로 적합합니다.$AAA$, array['세콜지', '세라마이드', '콜레스테롤', '피부장벽']::text[], 2024, 'sLiwrTPMDc8-3', 'https://youtu.be/sLiwrTPMDc8?t=258s', null, '2024-11-05 00:00:00+00'::timestamptz, '2024-11-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$효소 세안제 사용 시 주의해야 할 점은?$AAQ$, $AAA$효소 세안제는 **가루 형태라 화장실에 오래 두면 습기로 눅눅해져 가루가 잘 안 나옵니다**. 작은 용량으로 자주 새것을 사 쓰는 편이 좋습니다. 또 사용 빈도와 피부 부위별 강도 조절도 중요해요.

건성 피부는 1~2주에 한 번 정도가 적당하고, 지성 피부는 겨울철 주 1~2회까지 늘려도 좋아요. **사용 중 빨개지거나 가려운 증상이 나타나면 즉시 사용을 중단하고 보습을 충분히 해주셔야 합니다**. 민감성 피부라면 자극이 거의 없고 보습에 초점이 맞춰진 주닥 효소 클렌저가 더 잘 맞을 수 있어요. 사용 후에는 세콜지가 든 보습제로 마무리해야 피부 장벽이 튼튼해지고 화장도 잘 먹습니다.$AAA$, array['효소세안제', '사용주의', '민감성피부', '각질제거빈도']::text[], 2024, 'sLiwrTPMDc8-4', 'https://youtu.be/sLiwrTPMDc8?t=192s', null, '2024-11-05 00:00:00+00'::timestamptz, '2024-11-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$바르는 보톡스라는 펩타이드 화장품, 정말 효과가 있나요?$AAQ$, $AAA$주사 없이 바르기만 해도 주름이 좋아지는 펩타이드 화장품이 실제로 존재합니다. 대표적인 게 **신-에이크 펩타이드와 아세틸헥사펩타이드-8** 두 가지로, 모두 펩타이드 종류이지만 작용 방식이 다릅니다.

신-에이크는 동남아 독사 Temple viper의 와글레린이라는 펩타이드에서 영감을 받아 스위스 화장품 회사가 개발한 성분이고, **아세틸헥사펩타이드-8은 스페인 제약회사가 보톡스 원리를 응용해 만든 성분으로 근육 수축 신호를 약간 방해하는 정도** 작용합니다. 보톡스는 신호를 완전히 차단하지만 이 성분은 일부 억제에 가까운 거죠. 두 펩타이드가 모두 든 제품은 시너지 효과를 기대할 수 있지만 깊고 굵은 주름까지 다 펴주지는 못합니다.$AAA$, array['펩타이드화장품', '신에이크', '아세틸헥사펩타이드', '바르는보톡스']::text[], 2024, 'uQEnnnxz8Us-1', 'https://youtu.be/uQEnnnxz8Us?t=39s', null, '2024-11-07 00:00:00+00'::timestamptz, '2024-11-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$펩타이드 세럼은 어떤 사람에게 효과가 좋나요?$AAQ$, $AAA$펩타이드 세럼은 **30대에서 40대 주름이 생기기 시작하는 분들에게 예방 차원에서** 권해드릴 만한 제품입니다. 깊은 주름이 되기 전 관리 목적으로 적합한 시기입니다.

두 번째로 **보톡스는 무서운데 주름 관리는 하고 싶은 분들과 보톡스로 해결 안 되는 주름이 있는 분들**에게 추천됩니다. 눈 아래 자글자글한 주름이나 눈 안쪽 잔주름, 입가 주름은 보톡스로 펴기 어려운 부위인데, 펩타이드 세럼이 이런 영역을 보완할 수 있어요. 마지막으로 보톡스 효과를 오래 유지하고 싶은 분들도 함께 쓰면 도움이 됩니다. 피부가 얇고 잔주름이 많은 분들은 한 달 정도 사용하면 차이를 느끼지만, 깊은 주름이 있는 분은 화장품만으로는 한계가 있을 수 있습니다.$AAA$, array['펩타이드세럼', '주름예방', '보톡스대체', 'P-TIOX']::text[], 2024, 'uQEnnnxz8Us-2', 'https://youtu.be/uQEnnnxz8Us?t=300s', null, '2024-11-07 00:00:00+00'::timestamptz, '2024-11-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$펩타이드 세럼 사용 시 주의할 점은?$AAQ$, $AAA$펩타이드 세럼 사용 시 가장 먼저 알아둘 점은 **모든 주름을 다 펴주는 것이 아니라는 점**입니다. 깊고 굵은 주름은 화장품 단독으로 해결되지 않으며, 사실 보톡스로도 해결 안 되는 주름이 꽤 있습니다.

또 일부 제품에 든 PHA는 매우 순한 산이지만 acid 성분이라 **피부에 상처가 있거나 장벽이 망가진 상태에서는 따가울 수 있어 주의**가 필요합니다. 피부 컨디션이 안 좋을 때는 일시적으로 따가움을 느낄 수도 있어요. 한두 번 써서 드라마틱하게 좋아지지 않으므로 꾸준한 사용이 중요합니다. 비타민C, 레티놀과 같이 써도 되지만 한꺼번에 추가하면 원인 파악이 어려우니 한 가지씩 추가하며 피부 반응을 보며 쓰셔야 합니다.$AAA$, array['펩타이드세럼', 'PHA자극', '사용주의', '기능성중복']::text[], 2024, 'uQEnnnxz8Us-3', 'https://youtu.be/uQEnnnxz8Us?t=355s', null, '2024-11-07 00:00:00+00'::timestamptz, '2024-11-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$펩타이드 세럼은 어느 단계에서 발라야 하나요?$AAQ$, $AAA$펩타이드 세럼은 **가벼운 세럼 제형이라 세안 후 기초 첫 단계에 바르는 것이 좋습니다**. 토너를 쓰는 분은 토너 후, 비타민C 세럼을 쓰는 분은 비타민C 후 이 제품을 바르고 평소 스킨케어를 이어가시면 됩니다.

아침·저녁 모두 사용해도 되며 다른 기능성 화장품과 병행 가능합니다. 다만 **여러 제품을 한꺼번에 추가하면 문제가 생겼을 때 어떤 성분 탓인지 파악이 어렵습니다**. 한 가지씩 추가하며 피부 컨디션을 살피는 게 좋아요. 효과는 사람마다 달라서 피부가 얇고 잔주름이 많은 분은 약 한 달 사용 시 차이를 느끼지만, 깊은 주름은 한 달 만에는 잘 느껴지지 않을 수 있습니다. 공통적으로 광채감 개선 후기가 많은 편입니다.$AAA$, array['펩타이드세럼', '사용단계', '스킨케어순서', '세럼순서']::text[], 2024, 'uQEnnnxz8Us-4', 'https://youtu.be/uQEnnnxz8Us?t=405s', null, '2024-11-07 00:00:00+00'::timestamptz, '2024-11-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$LDM 시술은 어떤 사람에게 좋나요?$AAQ$, $AAA$LDM은 **민감성이고 예민한 피부, 속건조와 홍조가 함께 있는 분들**에게 잘 맞는 시술입니다. 초음파를 활용해 피부 장벽을 튼튼하게 만드는 것이 주 목표여서 자극에 약한 피부에 적합합니다.

LDM은 전용 초음파 겔을 바르고 **두 가지 파장으로 각각 3분씩 총 12분 관리**를 진행합니다. 초음파가 손상된 콜라겐·엘라스틴을 자극해 댐처럼 단단한 피부 장벽을 만들면 수분이 새지 않아 속건조가 줄고, 염증 완화로 홍조도 개선됩니다. 실제로 1주 간격 4회 LDM 후 홍조와 수분 손실이 줄었다는 논문도 있습니다. 효과를 더 높이려면 코코넛 추출 천연 소재로 만든 이온토코메드 팩을 함께 활용하기도 합니다.$AAA$, array['LDM', '민감성피부', '속건조', '홍조']::text[], 2024, '3sy7L-BwCIY-1', 'https://youtu.be/3sy7L-BwCIY?t=49s', null, '2024-11-12 00:00:00+00'::timestamptz, '2024-11-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$PHA 필링은 왜 물톡스라고 부르나요?$AAQ$, $AAA$PHA 필링이 **물톡스라 불리는 이유는 시술 후 피부에 물방울이 맺힌 듯 반짝반짝 빛이 나기 때문**입니다. 보톡스를 맞은 것처럼 물광과 톤업이 동시에 일어나는 부드러운 필링 시술입니다.

비결은 **PHA(폴리하이드록시산)가 수분을 끌어당기는 성질로 피부 속에서 물주머니 역할을 하기 때문**입니다. 또 시술 후 하이드라 필름 수분막이라는 투명한 보호막이 생겨 오랫동안 촉촉함이 유지됩니다. AHA·BHA보다 자극이 적어 예민한 피부도 시도해볼 수 있고 통증도 거의 없습니다. AHA로 표면 각질을 정리한 뒤 PHA 토너·트리트먼트·마사지 크림을 거쳐 블루 벨벳 팩으로 마무리하는 방식으로 진행됩니다.$AAA$, array['PHA필링', '물톡스', '폴리하이드록시산', '물광시술']::text[], 2024, '3sy7L-BwCIY-2', 'https://youtu.be/3sy7L-BwCIY?t=157s', null, '2024-11-12 00:00:00+00'::timestamptz, '2024-11-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$코레지와 LDM은 어떤 차이가 있나요?$AAQ$, $AAA$코레지와 LDM은 사용하는 에너지와 효과 포커스가 다른 시술입니다. **LDM은 초음파로 피부 장벽 강화에, 코레지는 16개 고주파 파장으로 탄력·리프팅에 포커스**되어 있습니다.

LDM은 수분 젤을 사용하고 민감하거나 예민한 피부에 적합하며, 코레지는 크림을 사용해 세포를 자극해 탄력을 끌어올립니다. 따라서 **지성 피부에는 LDM을, 건성 피부에는 코레지를 권유드리는 편**입니다. 크림이 드물게 지성 피부에서 트러블을 일으킬 수 있기 때문이에요. 코레지는 세라믹 핸드피스로 10분, 고주파 장갑으로 10분 진행되며 통증이 거의 없고 시술 직후 피부 윤기와 턱선 정리가 눈에 보일 정도로 빠른 변화가 느껴집니다.$AAA$, array['코레지비교', 'LDM비교', '고주파리프팅', '초음파시술']::text[], 2024, '3sy7L-BwCIY-3', 'https://youtu.be/3sy7L-BwCIY?t=329s', null, '2024-11-12 00:00:00+00'::timestamptz, '2024-11-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리쥬란은 어떤 분에게 추천되는 시술인가요?$AAQ$, $AAA$리쥬란은 **20대 후반에서 30대 초반부터 진피층이 얇아지기 시작하므로 피부가 얇은 분들이 이때부터 받으면 좋은 시술**입니다. 연어에서 추출한 성분으로 미세한 잔주름과 속건조 개선에 효과적입니다.

진피층을 튼튼하게 해 콜라겐 환경이 개선되면 속건조 완화도 따라옵니다. **얼굴 전체에 2~4cc를 주사하는데, 찢어질 듯 심한 속건조면 4cc, 약간 당기는 정도면 2cc**가 적합합니다. 마취 크림을 바른 뒤 의사가 진피층에 한 땀씩 공들여 주사하는 방식이라 멍이 들 수 있고 통증이 있는 시술로 유명합니다. 통증이 걱정되면 미라젯을 사용해 주입하거나 비수면 호흡 마취를 병행하기도 합니다.$AAA$, array['리쥬란', '진피층', '속건조', '연어PDRN']::text[], 2024, '3sy7L-BwCIY-4', 'https://youtu.be/3sy7L-BwCIY?t=400s', null, '2024-11-12 00:00:00+00'::timestamptz, '2024-11-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$남성 수염 제모는 어떤 효과가 있나요?$AAQ$, $AAA$남성 수염 제모의 가장 큰 변화는 **거뭇거뭇한 수염 자국이 사라지면서 얼굴 톤이 밝아지고 동안으로 보이는 효과**입니다. 수염 자국은 얼굴에 어둡고 칙칙한 인상을 주는데, 이게 정리되면 인상이 클린해집니다.

또 **출근 준비 시간이 약 10분 줄어들고 모낭염 같은 털에서 비롯된 염증이 줄어드는 실용적 이점**도 큽니다. 입 주위 트러블로 고생하던 분들도 제모 후 증상이 거의 없어지는 경우가 흔합니다. 수염은 매일 깎아도 저녁이 되면 자국이 보이는 불편함이 있는데 제모로 이 부담이 사라지죠. 본인 만족뿐 아니라 가족이나 지인들의 만족도까지 높아 입소문이 빠른 시술 중 하나입니다.$AAA$, array['남성제모', '수염제모', '동안효과', '모낭염']::text[], 2024, 'Wvp8YqoZeHA-1', 'https://youtu.be/Wvp8YqoZeHA?t=29s', null, '2024-11-14 00:00:00+00'::timestamptz, '2024-11-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$남성 수염 제모는 몇 회 받아야 효과가 나오나요?$AAQ$, $AAA$남성 수염 제모는 **보통 4주 간격으로 진행하며, 5회 정도만 받아도 거뭇거뭇한 수염 자국이 거의 대부분 사라집니다**. 이때부터 깔끔한 인상과 톤업 효과를 스스로 느낄 수 있어요.

그 이후엔 평상시 면도 없이 제모로 유지하는 분들이 많고, **10회차쯤이면 털이 듬성듬성 솜털처럼 나고 15회 이상이면 80% 이상 털이 사라져 영구 제모 상태**로 볼 수 있습니다. 다만 털 굵기·밀도·색에 따라 횟수는 사람마다 차이가 납니다. 제모는 검은 털에만 반응하므로 40대 이후 흰 수염이 나기 시작하면 효과가 떨어집니다. 그래서 흰 수염이 나오기 전 시작하는 것이 권장됩니다.$AAA$, array['남성제모', '시술횟수', '영구제모', '재시술주기']::text[], 2024, 'Wvp8YqoZeHA-2', 'https://youtu.be/Wvp8YqoZeHA?t=256s', null, '2024-11-14 00:00:00+00'::timestamptz, '2024-11-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$남성 수염 제모 시 통증과 부작용은?$AAQ$, $AAA$남성 수염 제모는 솔직히 아픈 시술이지만 **시술 시간 자체가 1분 정도로 짧아 견딜 만한 통증**입니다. 번개 맞은 것처럼 순간적이지만 금방 끝나서 만족도가 높은 편이에요.

부작용 중 가장 흔한 건 1~2회차에 모낭염이 생기는 경우인데, 횟수가 쌓이면 오히려 모낭염 증상이 줄어들어요. **진짜 중요한 부작용은 화상으로, 피부색이 짙은 분에게 강한 에너지가 들어갈 때 발생할 수 있습니다**. 그래서 피부색과 타입에 맞춰 에너지를 조절해야 하는데, 너무 낮추면 효과가 떨어지고 너무 높이면 화상 위험이 생깁니다. 효과가 안 나는 친구들은 대부분 에너지를 너무 낮게 설정한 경우라, 숙련된 시술자의 판단이 중요합니다.$AAA$, array['남성제모', '통증', '화상부작용', '모낭염']::text[], 2024, 'Wvp8YqoZeHA-3', 'https://youtu.be/Wvp8YqoZeHA?t=383s', null, '2024-11-14 00:00:00+00'::timestamptz, '2024-11-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$남성 수염 제모는 언제까지 받을 수 있나요?$AAQ$, $AAA$남성 수염 제모는 **흰 수염이 나기 전에 시작해야 효과를 볼 수 있는 시술**입니다. 제모의 원리상 검은 털에만 반응하기 때문에, 한 번 흰 털이 생기면 그 부분엔 제모가 먹히지 않습니다.

**남성도 40대가 넘어가면 흰 수염이 슬슬 나기 시작해 그때부터는 몇 번을 해도 제모가 되지 않습니다**. 그래서 40대 남성분들이 피부과에 오시면 지금이 마지막 기회라고 적극 권유하는 거예요. 처음엔 갸우뚱하다가 한두 번 받아보고 편한 줄 몰랐다고 만족하시는 분들이 많습니다. 거울 볼 때마다 본인이 변화를 체감하고 주변에서도 알아봐 줘 사람들이 광이 난다고 한다는 후기도 흔합니다.$AAA$, array['남성제모', '흰수염', '데드라인', '40대제모']::text[], 2024, 'Wvp8YqoZeHA-4', 'https://youtu.be/Wvp8YqoZeHA?t=217s', null, '2024-11-14 00:00:00+00'::timestamptz, '2024-11-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$예쁘다는 기준은 문화권마다 어떻게 다른가요?$AAQ$, $AAA$예쁘다는 기준은 문화권마다 선호하는 얼굴이 다릅니다. **한국 같은 동아시아에서는 갸름한 V라인을, 서양에서는 광대뼈가 도드라진 입체감 있는 얼굴**을 선호합니다. 같은 얼굴도 지역에 따라 평가가 달라지는 거예요.

다만 문화권을 넘어 공통되는 기준도 존재합니다. **얼굴을 좌우반전해 본 연구에서 대칭적일수록 더 예쁘게 보인다는 결과가 있습니다**. 그러나 다른 연구에선 아름다움을 판단할 때 개인 취향이 절반 정도를 차지한다고 보고됩니다. 심지어 유전자가 동일한 일란성 쌍둥이도 이성 매력 평가 기준이 서로 다릅니다. 즉 사람마다 각자의 심미안이 있다는 의미로, 예쁨은 일률적인 잣대가 아니라 개인적이고 다층적입니다.$AAA$, array['미의기준', '얼굴대칭', '문화차이', '심미안']::text[], 2024, 't8_d6wo4c8I-1', 'https://youtu.be/t8_d6wo4c8I?t=86s', null, '2024-11-19 00:00:00+00'::timestamptz, '2024-11-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$셀카가 가장 예쁘게 나오는 이유는?$AAQ$, $AAA$셀카가 가장 예쁘게 나오는 이유는 **남의 시선을 신경 쓰지 않고 가장 편하고 자연스럽게 찍기 때문**입니다. 본인이 찍은 셀카에서 가장 매력적인 표정이 나온다는 연구가 있을 정도예요.

스스로 가장 예쁜 척, 가장 멋있는 척을 자유롭게 할 수 있는 상황이라 **자신감 있는 상태일 때 자연스러운 예쁜 표정이 나온다는 사실**과 맞닿아 있습니다. 연예인들도 외모만으로 매력이 결정되지 않아요. 아무리 잘생겨도 무대에서 쭈뼛거리면 그 매력이 살지 않고, 카메라 앞에서 당당하게 표정과 포즈를 취할 때 사람이 더 빛납니다. 결국 자신감이 사람을 매력적으로 보이게 하는 핵심 요소라는 결론으로 이어집니다.$AAA$, array['셀카', '자신감', '표정매력', '심리']::text[], 2024, 't8_d6wo4c8I-2', 'https://youtu.be/t8_d6wo4c8I?t=187s', null, '2024-11-19 00:00:00+00'::timestamptz, '2024-11-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리프팅 시술의 진짜 의미는 무엇인가요?$AAQ$, $AAA$리프팅 시술의 진짜 의미는 **몇 살 어려 보이거나 몇 cm 끌어올린 것보다 본인의 아름다움을 더 자신 있게 표출할 수 있게 되는 것**에 있습니다. 자기효능감 회복이 시술의 본질이라는 관점입니다.

중년 여성분들 중에는 열심히 살다 어느 날 거울 속 자신이 너무 나이 들어 보였다고 말씀하시는 분이 많습니다. 직장에서 젊은 사람들 사이에 위축감을 느끼는 경우도 있어요. **이런 분들이 리프팅 후 피부 탄력과 주름 개선을 말씀하실 때 톤부터 굉장히 밝아지는데, 이는 자신감 회복의 신호**입니다. 피부과 시술은 단순히 예뻐지기 위한 게 아니라 본연의 아름다움을 찾아가는 과정이며, 자신감 회복을 통해 일상에서 더 활력 있게 살아갈 수 있게 돕는 것입니다.$AAA$, array['리프팅의미', '자기효능감', '중년피부', '자신감회복']::text[], 2024, 't8_d6wo4c8I-3', 'https://youtu.be/t8_d6wo4c8I?t=304s', null, '2024-11-19 00:00:00+00'::timestamptz, '2024-11-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$멜라토닌은 영양제인가요 호르몬인가요?$AAQ$, $AAA$멜라토닌은 영양제가 아니라 우리 몸의 생체 리듬을 조절하는 **호르몬입니다**. 해가 뜨면 일어나고 밤이 되면 잠을 자게 하는 생체 시계 역할을 해요. 멜라토닌이 분비되면 뇌가 밤이라고 인식해 졸리게 됩니다.

신생아가 100일 무렵부터 낮밤을 가리는 '100일의 기적'도 멜라토닌 때문입니다. 태아 때는 엄마의 멜라토닌을 받다가 태어나면서 끊기는데, **처음 3~4개월 동안은 스스로 멜라토닌을 만들지 못해** 낮밤을 구분하지 못해요. 그러다 3~4개월이 지나면 멜라토닌을 만들기 시작하면서 낮밤을 구분하게 됩니다. 우리 몸에서 그만큼 중요한 역할을 하는 호르몬이에요.$AAA$, array['멜라토닌', '호르몬', '생체리듬', '수면', '100일의기적']::text[], 2024, 'GQBb1sYzxmo-1', 'https://youtu.be/GQBb1sYzxmo?t=43s', null, '2024-11-21 00:00:00+00'::timestamptz, '2024-11-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$멜라토닌이 기미에도 효과가 있나요?$AAQ$, $AAA$멜라토닌은 기미 개선에 도움이 된다는 연구 결과가 나오고 있습니다. 기미가 있는 사람들의 혈액 멜라토닌 수치가 기미가 없는 사람보다 낮게 측정됐고, **3달간 멜라토닌을 복용한 결과** 기미 넓이가 줄고 색깔도 옅어진 연구가 있어요.

도움이 되는 이유는 크게 두 가지입니다. 첫째, 멜라토닌이 강력한 항산화 물질이라 기미 원인 중 하나인 산화 스트레스를 줄여줘요. 둘째, **멜라닌 합성을 직접적으로 억제하는 역할도 합니다**. 다만 대규모 임상시험 결과가 아직 부족하고 장기 복용 문제점도 있을 수 있어, 기미 때문에 무조건 복용하는 것은 이르다고 봅니다.$AAA$, array['멜라토닌', '기미', '항산화', '멜라닌억제', '색소침착']::text[], 2024, 'GQBb1sYzxmo-2', 'https://youtu.be/GQBb1sYzxmo?t=162s', null, '2024-11-21 00:00:00+00'::timestamptz, '2024-11-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$멜라토닌이 피부 노화에도 효과가 있나요?$AAQ$, $AAA$멜라토닌은 피부 노화를 늦추는 데 도움이 됩니다. 활성산소가 피부에 쌓이면 콜라겐과 엘라스틴을 파괴하고 피부 세포 DNA까지 손상시키는데, **멜라토닌이 강력한 항산화 효과로** 이를 막아줘요. 비타민C나 비타민E보다도 항산화 효과가 뛰어나다는 연구 결과도 있습니다.

실제로 멜라토닌이 들어간 크림을 사용했을 때 **피부 주름이 감소하고 피부 탄력이 좋아졌다는 연구 결과가** 보고됐어요. 다만 국내에서 멜라토닌은 전문의약품으로 분류돼 의사 처방이 필요하고, 부작용 우려도 있어 영양제처럼 복용해서는 안 됩니다. 보통 멜라토닌이 줄어드는 50대 이상 수면장애 환자나 교대근무로 수면 패턴이 깨진 분들께 도움이 될 수 있어요.$AAA$, array['멜라토닌', '피부노화', '항산화', '주름', '활성산소']::text[], 2024, 'GQBb1sYzxmo-3', 'https://youtu.be/GQBb1sYzxmo?t=308s', null, '2024-11-21 00:00:00+00'::timestamptz, '2024-11-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$야간 근무가 건강에 안 좋은 이유가 무엇인가요?$AAQ$, $AAA$야간 근무는 멜라토닌 분비를 망가뜨려 건강을 크게 해칠 수 있습니다. 밤에 일하고 낮에 자면 멜라토닌 분비 리듬이 엉망이 되는데, **장기간 야간 근무자 통계에서 유방암 발생 위험이** 일반인보다 높게 나타났어요.

멜라토닌은 면역력을 높이고 암 예방 효과까지 있다는 연구 결과들이 보고됩니다. 또한 핸드폰이나 TV에서 나오는 블루라이트를 봐도 멜라토닌 분비가 줄어들어 불면증으로 이어질 수 있어요. 나이가 들수록 멜라토닌이 줄어들기 때문에 젊을 때보다 잠도 잘 안 오고 피부 노화가 가속화되는 원인이 되기도 합니다. 자기 전 전자기기 사용을 줄이는 게 중요해요.$AAA$, array['야간근무', '멜라토닌', '유방암', '면역력', '블루라이트']::text[], 2024, 'GQBb1sYzxmo-4', 'https://youtu.be/GQBb1sYzxmo?t=402s', null, '2024-11-21 00:00:00+00'::timestamptz, '2024-11-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$위고비의 체중 감량 효과는 어느 정도인가요?$AAQ$, $AAA$위고비는 일주일에 한 번 주사로 **평균 15% 체중 감량 효과를** 보이는 비만 치료제입니다. 100kg이었던 사람이 85kg으로, 70kg이었던 사람이 60kg까지 빠질 정도로 효과가 뛰어난 약이에요.

단순히 체중만 빼는 것이 아니라 비만 관련 질환도 개선시킵니다. **17,600명을 3년 이상 추적한 대규모 연구에서** 위고비를 맞은 그룹의 심근경색·뇌졸중 같은 심혈관 질환 위험이 20% 감소했어요. 심장질환 사망은 15%, 심부전 사망은 18% 더 낮았습니다. 당뇨와 만성신장질환 환자에서는 신부전 발생 위험이 24% 더 낮게 나타났어요. 그래서 다이어트 약이 아닌 비만 치료제로 분류됩니다.$AAA$, array['위고비', '체중감량', '비만치료제', '심혈관질환', '세마글루타이드']::text[], 2024, 'ZH6ZfRghZmo-1', 'https://youtu.be/ZH6ZfRghZmo?t=427s', null, '2024-11-26 00:00:00+00'::timestamptz, '2024-11-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$위고비를 맞으면 어떤 부작용이 가장 흔한가요?$AAQ$, $AAA$위고비의 가장 흔한 부작용은 소화기계 증상입니다. 위 운동을 느리게 만들어 음식이 위에 오래 머무르면서, **구역감은 약 44%, 구토는 약 20%에서** 나타나요. 꽤 높은 수치이지만 영원히 가는 증상은 아닙니다.

대부분 투약 초기 1~2달 사이에 증상이 있다가 서서히 사라져요. 그래서 부작용을 줄이기 위해 용량을 한 번에 올리지 않고 **수 개월에 걸쳐 천천히 증량합니다**. 가장 낮은 용량부터 시작해 4주간 관찰한 뒤 이상이 없으면 천천히 늘려가는 방식이에요. 갑작스러운 용량 증가는 위험할 수 있어 의사 상담이 중요하고, 심한 복통이 지속되거나 등 쪽으로 퍼지는 통증, 심한 구토가 멈추지 않을 때는 즉시 병원에 가야 합니다.$AAA$, array['위고비', '부작용', '구토', '구역감', '용량증량']::text[], 2024, 'ZH6ZfRghZmo-2', 'https://youtu.be/ZH6ZfRghZmo?t=345s', null, '2024-11-26 00:00:00+00'::timestamptz, '2024-11-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$위고비 맞을 때 췌장염 위험이 얼마나 있나요?$AAQ$, $AAA$위고비 사용 시 췌장염 위험은 초기 연구에서 우려한 만큼 높지는 않지만 증가하는 것은 사실입니다. 존스홉킨스 사미르 칸 교수는 **췌장염 위험성이 초기 우려보다는 낮지만** 위고비를 쓰면 위험이 증가하는 것은 맞다고 정리했어요.

3,000명 넘는 대상 연구에서는 위고비 그룹의 췌장염 발생이 오히려 더 적었지만, **1,600만 명 대상 다른 연구에서는** 위고비·삭센다 같은 GLP-1 유사체 사용자의 췌장염 발생률이 다른 비만약보다 높게 나왔어요. 발생해도 대부분 저절로 낫거나 치료로 좋아지며, 심각한 경우는 20명 중 1명 정도로 드뭅니다. 다만 췌장염이 의심될 때는 즉시 투약을 중단해야 합니다.$AAA$, array['위고비', '췌장염', 'GLP-1', '삭센다', '안전성']::text[], 2024, 'ZH6ZfRghZmo-3', 'https://youtu.be/ZH6ZfRghZmo?t=242s', null, '2024-11-26 00:00:00+00'::timestamptz, '2024-11-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$위고비를 절대 사용하면 안 되는 경우는 어떤가요?$AAQ$, $AAA$위고비는 **갑상선 수질암 병력이나 가족력이 있는 경우** 절대 사용하면 안 됩니다. 제 2형 다발성 내분비 종양증후군 병력이나 가족력이 있는 경우, 그리고 세마글루타이드에 과민반응이 있는 경우도 금기입니다.

사용 시 주의해야 하는 경우도 있어요. 급성 췌장염 의심 시 즉시 투약 중단, 급성 담낭 질환 의심 시 검사, 당뇨 환자의 저혈당 위험, **급성 신장 손상 가능성 등을 검사해야 합니다**. 제 2형 당뇨병 환자는 당뇨병성 망막병증이 생길 수 있고 심박수 상승도 발생할 수 있어 정기적인 심박수 체크가 필요해요. 자살 행동이나 자살 사고 가능성도 있어 주의가 필요합니다. 적응증은 BMI 30 이상 성인 또는 BMI 27 이상이면서 고혈압·당뇨병 같은 비만 관련 질환이 있는 분이에요.$AAA$, array['위고비', '금기', '갑상선수질암', '적응증', 'BMI']::text[], 2024, 'ZH6ZfRghZmo-4', 'https://youtu.be/ZH6ZfRghZmo?t=414s', null, '2024-11-26 00:00:00+00'::timestamptz, '2024-11-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비수면 호흡마취란 어떤 마취 방법인가요?$AAQ$, $AAA$호흡마취는 아산화질소와 산소를 함께 들이마시며 **의식이 깨어 있는 상태에서** 통증을 거의 못 느끼게 해주는 마취 방법입니다. 소아치과에서 아이들에게 쓰는 웃음가스와 같은 원리예요. 잠드는 것이 아니라 호스로 숨을 들이쉬고 내쉬다 보면 점점 편안해지면서 기분이 좋아져요.

원리는 통증을 직접 차단하는 것이 아니라 **의식을 다른 데로 빼돌려 통증을 못 느끼게 해주는 방식입니다**. 술에 취하면 넘어지거나 부딪혀도 고통을 잘 못 느끼는 것과 비슷해요. 산소통과 아산화질소통 두 개에서 가스가 폐로 동시에 들어오는데, 비수면 호흡마취 시작 시 산소 비율을 낮추면 아산화질소가 더 많이 들어가게 됩니다. 의식과 대화가 가능해 시술 중 환자와 소통할 수 있는 게 장점이에요.$AAA$, array['호흡마취', '아산화질소', '비수면마취', '웃음가스', '마취원리']::text[], 2024, 'piajMmEONTo-1', 'https://youtu.be/piajMmEONTo?t=33s', null, '2024-11-28 00:00:00+00'::timestamptz, '2024-11-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$호흡마취 효과는 사람마다 다른가요?$AAQ$, $AAA$호흡마취 효과는 술에 대한 내성과 비슷하게 사람마다 차이가 있습니다. 술을 잘 못하는 분들은 **거의 기억이 안 날 정도로 통증이 거의 0으로** 줄어들어요. 반면 술이 센 분들은 통증이 10점이었다면 1~2점으로 감소하긴 하지만 기억이 안 나는 정도까지는 아닙니다.

술이 센 분들도 **주변 소리가 다 들리고 상황 인지가 다 되며** 충분히 기억도 다 나는 상태가 돼요. 의식이 있으니 시술 중 대화도 가능하고 본인이 상황을 인지하기 때문에 수면마취가 불안한 분들이 좋아하는 방식입니다. 마취가 잘 되는 비결은 편안한 마음을 갖는 것이에요. 긴장하면 마취가 잘 안 되니, 행복했던 여행지를 다시 간다고 생각하며 편하게 숨을 들이쉬고 내쉬면 훨씬 잘 됩니다.$AAA$, array['호흡마취', '효과차이', '술내성', '통증경감', '의식유지']::text[], 2024, 'piajMmEONTo-2', 'https://youtu.be/piajMmEONTo?t=263s', null, '2024-11-28 00:00:00+00'::timestamptz, '2024-11-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$호흡마취와 수면마취 중 어떤 것이 더 안전한가요?$AAQ$, $AAA$호흡마취가 위험 측면에서 수면마취보다 더 안전한 마취 방법입니다. 수면마취 약은 완전히 의식을 잠재워 **자발 호흡이 없어질 수도 있고** 혀가 뒤로 말려 들어가 기도가 막히는 응급 상황이 올 수도 있어요. 실제 그런 응급상황은 드물지만 위험 가능성 자체가 존재합니다.

반면 호흡마취는 의식이 있어 자발 호흡이 유지되고 시술자도 시술에 더 집중할 수 있어요. 또한 수면마취는 **8시간 금식과 시술 2주 전 감기 조심**, 시술 후 마취 깨는 데 오래 걸려 운전도 불가능한 번거로움이 있습니다. 호흡마취는 이런 제약이 없고 끝나고 산소를 5분간 충분히 들이마시면 어지러움이나 울렁거림도 금방 좋아져요. 다만 무조건 호흡마취가 좋다는 건 아니고 개인 상황에 맞춰 선택하는 게 적합합니다.$AAA$, array['호흡마취', '수면마취', '안전성비교', '금식', '자발호흡']::text[], 2024, 'piajMmEONTo-3', 'https://youtu.be/piajMmEONTo?t=302s', null, '2024-11-28 00:00:00+00'::timestamptz, '2024-11-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$호흡마취 받을 때 어떻게 해야 잘 되나요?$AAQ$, $AAA$호흡마취는 편안한 마음으로 천천히 호흡할수록 효과가 잘 나타납니다. 긴장해서 이상한 행동할까 걱정하는 분들보다 **편안한 마음으로 숨을 들이쉬고 내쉬는 분들이** 훨씬 마취가 잘 돼요. 산소를 충분히 마시는 것이 가장 중요합니다.

팁은 행복했던 여행지를 다시 간다고 상상하는 거예요. **유토피아에 갔다 온다는 생각을 하시면** 좋고, 여행지 중 가장 기억에 남는 순간으로 다시 떠난다고 상상하면 마취가 훨씬 잘 됩니다. 시술이 끝난 뒤에는 산소를 5분간 충분히 들이마셔야 깨고 나서 머리가 아프지 않고 울렁거리지 않아요. 시술 중 의식은 있지만 통증은 거의 못 느끼는 상태가 되며, 구구단을 풀 정도로 맨정신이면서도 아프지 않은 신기한 경험을 할 수 있어요.$AAA$, array['호흡마취', '긴장완화', '마취팁', '산소흡입', '시술준비']::text[], 2024, 'piajMmEONTo-4', 'https://youtu.be/piajMmEONTo?t=386s', null, '2024-11-28 00:00:00+00'::timestamptz, '2024-11-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$쥬브젠은 어떤 주름과 흉터에 사용하나요?$AAQ$, $AAA$쥬브젠은 일반 필러로 치료하기 어려운 **깊은 주름과 패인 흉터에 사용하는** 시술입니다. 이미 피부가 너무 접혀 고랑이 파져버린 주름은 필러를 얕게 넣으면 울퉁불퉁하게 뭉칠 수 있는데, 쥬브젠은 이를 해결하도록 만들어졌어요.

특징은 두 가지입니다. 첫째, 바늘 끝에서 히알루론산이 굉장히 소량씩 나와 손으로 주입할 때 뭉치는 점을 해결합니다. 둘째, **히알루론산 사이사이에 이산화탄소 가스가 함께 나와** 피부 속을 약간 찢어주는 역할을 해요. 이 가스가 필러가 들어갈 공간을 만들어주고 뭉치지 않게 조금씩 주입할 수 있게 합니다. 한 번 치료해도 효과가 오랫동안 지속된다는 것도 특징이에요.$AAA$, array['쥬브젠', '깊은주름', '패인흉터', '이산화탄소', '히알루론산']::text[], 2024, 'mzTZV2c5noU-1', 'https://youtu.be/mzTZV2c5noU?t=119s', null, '2024-11-29 00:00:00+00'::timestamptz, '2024-11-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$포젤란 스킨부스터는 어떤 특징이 있나요?$AAQ$, $AAA$포젤란은 **모공 개선에 특화된** 새로운 스킨부스터입니다. 수분이나 피부결이 좋아지는 효과도 당연히 있지만 모공 개선 효과가 특히 두드러져요. 환자들이 모공이 좋아졌다, 결이 좋아졌다는 후기를 다른 부스터보다 더 많이 말씀하는 편입니다.

핵심 성분은 PCL이라는 성분이에요. **PCL 성분이 피부 속에 잘 침투해** 모공과 피부결을 개선합니다. 보통 유명한 스킨부스터에는 아미노산이나 비타민이 들어있는데, 거기에 PCL이 더해진 형태예요. 분자 크기가 굉장히 작아 모공 속으로 흡수가 잘 됩니다. 액상 형태로 나와 있어 바로 사용하기 좋은 점도 특이합니다. 포젤란은 독일어로 도자기를 뜻해 도자기 같은 피부를 만든다는 의미가 담겨 있어요.$AAA$, array['포젤란', '스킨부스터', 'PCL', '모공개선', '피부결']::text[], 2024, 'mzTZV2c5noU-2', 'https://youtu.be/mzTZV2c5noU?t=189s', null, '2024-11-29 00:00:00+00'::timestamptz, '2024-11-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$온다 리프팅은 울쎄라, 써마지와 어떻게 다른가요?$AAQ$, $AAA$온다는 **극초단파라는 파장을 사용하는** 리프팅 장비로, 초음파를 쓰는 울쎄라나 고주파를 쓰는 써마지와 본질적으로 다른 에너지원을 사용합니다. 전자레인지와 유사한 주파수를 써서 물 분자를 빠르게 진동시키는 원리예요.

전자레인지가 음식 속 물 분자를 진동시켜 빨리 데우듯, **온다는 피부 분자를 빠르게 진동시켜 안쪽을 빨리 데워줍니다**. 표피는 거의 데우지 않고 피부 안쪽만 가열하기 때문에 통증이 굉장히 적다는 장점이 있어요. 핸드피스는 두 가지로, 7mm는 피부 7mm 깊이까지 들어가 빠른 리프팅과 바디 리프팅 효과를 주고, 3mm는 그 깊이로 들어가 피부 타이트닝 효과를 줍니다. 리프팅의 새로운 패러다임으로 평가받는 장비입니다.$AAA$, array['온다', '극초단파', '리프팅비교', '울쎄라', '써마지']::text[], 2024, 'mzTZV2c5noU-3', 'https://youtu.be/mzTZV2c5noU?t=266s', null, '2024-11-29 00:00:00+00'::timestamptz, '2024-11-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$코어스컬프는 어떤 원리로 피부 관리에 쓰이나요?$AAQ$, $AAA$코어스컬프는 자기장을 이용해 **지방층과 근막층을 지나 근육층까지** 깊이 작용하는 새로운 피부 관리 장비입니다. 원래는 배나 엉덩이에 쓰는 바디용 기계였는데 얼굴에도 쓸 수 있게 개발됐어요.

자기장이 피부 깊이 들어가 타이트닝과 리프팅 효과를 주고, **전체적으로 얼굴 붓기를 빼주는 효과와 염증을 줄여주는 효과까지** 여러 가지 작용을 합니다. 누워서 얼굴을 대고 쬐는 방식으로 사용해요. 장비 위에 철가루를 대보면 자기장 때문에 흔들리는 모습이 보일 정도로 강한 에너지가 들어갑니다. 새로 나온 장비여서 아직 알려진 임상 데이터는 많지 않지만, 비침습적이며 다양한 효과를 동시에 기대할 수 있다는 점이 특징입니다.$AAA$, array['코어스컬프', '자기장', '타이트닝', '리프팅', '붓기']::text[], 2024, 'mzTZV2c5noU-4', 'https://youtu.be/mzTZV2c5noU?t=63s', null, '2024-11-29 00:00:00+00'::timestamptz, '2024-11-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈가 보톡스를 맞으면 표정이 어색해지나요?$AAQ$, $AAA$눈가 보톡스를 꼼꼼히 맞으면 **주름은 쫙 펴지지만 웃을 때 표정이 어색해질 수** 있습니다. 눈 주변에 팬더처럼 동그랗게 있는 근육이 안 움직이게 해야 눈 주름이 안 생기기 때문에, 주름을 잘 펴려고 꼼꼼히 많이 놓을수록 웃을 때 근육이 움직이지 않아 어색해질 수밖에 없어요.

그래서 시술 전에 우선순위를 정하는 게 중요합니다. **주름이 잘 펴지는 것과 표정이 자연스러운 것 중** 무엇이 더 중요한지 미리 생각해야 해요. 적당히 펴지고 적당히 어색하지 않게 맞으면 가장 좋지만, 적당함의 기준이 사람마다 다릅니다. 시술 전 의료진과 충분히 상담해 본인이 원하는 방향을 정확히 전달하면 도움이 됩니다.$AAA$, array['눈가보톡스', '주름', '표정자연스러움', '안륜근', '시술상담']::text[], 2024, 'o8EincXgG2A-1', 'https://youtu.be/o8EincXgG2A?t=336s', null, '2024-12-03 00:00:00+00'::timestamptz, '2024-12-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$사람과 동물의 눈은 어떤 차이가 있나요?$AAQ$, $AAA$사람과 동물 눈의 가장 큰 차이는 **흰자의 크기와 눈의 위치입니다**. 동물들은 흰자가 거의 안 보이지만 사람은 흰자가 잘 보여서 시선 방향과 감정을 읽기 쉬워요. 인간과 가장 비슷한 침팬지나 오랑우탄도 흰자가 거의 안 보입니다.

오랑우탄에 비해 **사람의 흰자가 3배나 더 크다고** 알려져 있어요. 눈의 위치도 달라서 인간은 얼굴 정면에 눈이 붙어 있어 마주 보며 대화할 수 있지만, 동물들은 측면에 붙어 있습니다. 이 덕분에 사람은 1초만 봐도 어마어마한 양의 정보를 알아낼 수 있어요. 7개월 된 아기도 다른 사람 눈을 보고 감정 상태를 읽을 수 있을 정도로 진화적으로 생존에 중요한 능력이었습니다.$AAA$, array['눈흰자', '감정인지', '사람동물차이', '진화', '비언어소통']::text[], 2024, 'o8EincXgG2A-2', 'https://youtu.be/o8EincXgG2A?t=98s', null, '2024-12-03 00:00:00+00'::timestamptz, '2024-12-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$안면홍조는 왜 생기고 치료가 가능한가요?$AAQ$, $AAA$안면홍조는 **온도 변화나 작은 감정 변화에도** 얼굴이 쉽게 빨개지는 증상으로 레이저 치료가 가능합니다. 긴장하거나 부끄러울 때 본인 감정이 드러나기 때문에 사회생활에 불편감을 많이 느끼는 분들이 치료를 받으러 옵니다.

사람 얼굴이 붉어지는 현상은 진화적으로 의미가 있어요. **얼굴이 확 붉어지면 부끄럽거나 화가 났다는 신호이고**, 창백해지면 겁을 먹었다는 신호입니다. 인간은 진화하면서 털이 줄어들었는데, 피부 상태가 건강과 나이를 잘 드러내기 때문에 털이 적은 사람이 성적 매력이 높아 털 없는 쪽으로 진화했다는 이론도 있어요. 피부는 감정 표현뿐 아니라 건강 상태도 보여주는 중요한 사회적 신호입니다.$AAA$, array['안면홍조', '레이저치료', '감정표현', '피부역할', '진화']::text[], 2024, 'o8EincXgG2A-3', 'https://youtu.be/o8EincXgG2A?t=410s', null, '2024-12-03 00:00:00+00'::timestamptz, '2024-12-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$진심 어린 미소를 어떻게 알아볼 수 있나요?$AAQ$, $AAA$진심 어린 미소는 **눈가와 입꼬리가 함께 웃을 때** 나타나며 이를 뒤셴 스마일이라고 부릅니다. 보통 미소를 지을 때 입꼬리가 올라가지만, 진짜 행복할 때는 눈 주변 근육도 같이 수축해 눈이 반달처럼 되고 눈가에 주름이 생겨요.

최근 연구에서 **사람들이 이런 표정을 보면 더 진실되고 신뢰할 수 있다고** 느낀다고 합니다. 연습을 통해 어느 정도 의도적으로 만들 수는 있지만, 진짜 행복해서 짓는 미소와 의도적 미소는 미세하게 달라요. 사진으로 포착하기 어려울 만큼 작은 차이지만 사람들은 무의식적으로 그 차이를 알아냅니다. 사람 얼굴 근육은 정교해서 이론상 만 가지 표정을 지을 수 있고, 기쁨이라는 감정 하나만으로도 17가지 다른 표정으로 표현할 수 있어요.$AAA$, array['뒤셴스마일', '진심미소', '표정', '신뢰감', '얼굴근육']::text[], 2024, 'o8EincXgG2A-4', 'https://youtu.be/o8EincXgG2A?t=240s', null, '2024-12-03 00:00:00+00'::timestamptz, '2024-12-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$대변 미생물 이식술이란 어떤 치료인가요?$AAQ$, $AAA$대변 미생물 이식술은 **건강한 사람의 대변 속 미생물을** 환자의 장에 이식해 장 건강을 회복시키는 치료법입니다. 영어로 Fecal Microbiota Transplantation, 줄여서 FMT라고 불러요. 똥 자체를 이식하는 것이 아니라 대변 속 건강한 미생물을 이식하는 것입니다.

우리 몸속에는 **100조가 넘는 미생물이 살고 있는데** 대부분이 장 속에 있어요. 이 장내 미생물은 단순 소화 기능을 넘어 **면역력의 70~80%를 담당하고** 대사와 신경계 기능에도 핵심 역할을 합니다. 기증자가 대변을 기증하면 특수 시설에서 여러 단계 정제 과정을 거쳐 불순물은 제거하고 유익한 미생물만 분리해요. 환자에게 이식되는 것은 깨끗하게 정제된 미생물입니다.$AAA$, array['대변이식술', 'FMT', '장내미생물', '면역력', '치료원리']::text[], 2024, 'zVRtKm2ORUM-1', 'https://youtu.be/zVRtKm2ORUM?t=80s', null, '2024-12-05 00:00:00+00'::timestamptz, '2024-12-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$대변 이식술이 어떤 병에 효과가 있나요?$AAQ$, $AAA$대변 이식술은 **Clostridium difficile에 의한 중증 장염에서 90% 이상의 치료율을** 보입니다. 항생제로 치료하면 장 속 정상 유익균까지 죽어 재발이 흔하지만, 대변 이식술로 건강한 미생물을 환자 장에 이식하면 장 환경이 회복되어 치료 성공률이 크게 올라가요.

다른 질환에서도 연구가 활발합니다. **자폐 스펙트럼 장애, 우울증 같은 정신과 질환에서도** 효과 연구가 진행 중이고 비만과 당뇨병에서도 효과 연구 결과가 나오고 있어요. 흑색종 면역항암제가 듣지 않던 환자들에게 대변 이식술을 했더니 65%에서 항암제 효과가 좋아진 결과도 보고됐어요. 피부 질환에서는 여드름 환자에게 특별히 선별된 장내 미생물을 이식해 여드름이 40% 개선됐다는 결과도 있습니다.$AAA$, array['대변이식술', '장염치료', '흑색종', '여드름', '면역항암제']::text[], 2024, 'zVRtKm2ORUM-2', 'https://youtu.be/zVRtKm2ORUM?t=261s', null, '2024-12-05 00:00:00+00'::timestamptz, '2024-12-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$대변 이식술은 어떻게 시행하나요?$AAQ$, $AAA$대변 이식술은 **세 가지 방법으로** 시행됩니다. 첫째는 내시경을 통해 항문으로 직접 주입, 둘째는 코에 관을 넣어 장에 주입, 셋째는 캡슐 형태로 만들어 먹는 방법이에요. 환자 상태와 치료 목적에 따라 적합한 방법을 선택합니다.

기증자 선정 과정은 굉장히 까다롭습니다. 기본 건강검진은 당연하고 **여러 감염질환과 자가면역질환이 없는지 철저히 체크하며**, 생활습관·식습관·최근 복용 약물까지 꼼꼼히 확인해요. 부작용은 대체로 안전한 편으로, **가장 흔한 부작용은 일시적 복부 불편감이나 설사이며** 대부분 며칠 안에 해결됩니다. 다만 면역력이 많이 떨어진 환자에게는 신중한 접근이 필요해요. 건강한 사람의 대변을 보관해두는 대변 은행도 생기고 있습니다.$AAA$, array['대변이식술', '투여방법', '기증자선정', '부작용', '대변은행']::text[], 2024, 'zVRtKm2ORUM-3', 'https://youtu.be/zVRtKm2ORUM?t=411s', null, '2024-12-05 00:00:00+00'::timestamptz, '2024-12-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$한국에서도 대변 이식술을 받을 수 있나요?$AAQ$, $AAA$한국에서는 아직 대변 이식술이 **정식 승인되지 않아** 일부 대학병원에서 연구 목적으로 제한적으로 사용되고 있는 단계입니다. 일반 환자가 쉽게 받을 수 있는 치료는 아니에요.

반면 미국에서는 **2023년 11월 FDA가 Rebyota라는 약을** Clostridium difficile 치료제로 승인해 활발히 사용되고 있어요. 이 약은 스위스 제약회사가 대변 추출 유익 미생물을 알약에 담아 개발한 것입니다. 영국, 네덜란드, 호주에서도 사용되고 있어요. 4세기 중국 역사서에 물에 탄 대변을 설사 환자 치료에 썼다는 기록이 있을 정도로 오래된 치료법이지만, 현대의학에서 주목받기 시작한 건 2013년 NEJM에 발표된 연구 이후입니다. 여드름이나 아토피 치료는 아직 연구 초기 단계라 더 많은 임상시험이 필요해요.$AAA$, array['대변이식술', 'FDA승인', 'Rebyota', '국내승인', '임상시험']::text[], 2024, 'zVRtKm2ORUM-4', 'https://youtu.be/zVRtKm2ORUM?t=239s', null, '2024-12-05 00:00:00+00'::timestamptz, '2024-12-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지 효과는 언제부터 느낄 수 있나요?$AAQ$, $AAA$써마지는 **시술 직후가 아니라 2~3개월 뒤** 효과를 느끼는 시술입니다. 콜라겐이 재생되는 시술이라 시술 후 콜라겐이 새로 만들어지려면 시간이 필요해요. 받자마자 즉시 변화를 기대하기는 어렵습니다.

다만 피부 상태에 따라 차이가 있어요. 피부가 많이 얇거나 푸석한 분들은 받고 나서 바로 쫀쫀해졌다는 후기를 말씀하기도 합니다. 반면 **피부 컨디션이 원래 좋은 경우 단기적인 변화를 확 느끼지는 않을 수도** 있어요. 써마지는 즉각적 변화보다 **피부 노화 방지를 위한 보험 같은 시술이라** 5년, 10년 꾸준히 쌓이면 시술 받은 사람과 안 받은 사람의 차이가 크게 벌어집니다. 매년 한 번 꾸준히 받는 게 핵심이에요.$AAA$, array['써마지', '효과시점', '콜라겐재생', '노화방지', '꾸준함']::text[], 2024, '2z-zBNyzkqs-1', 'https://youtu.be/2z-zBNyzkqs?t=176s', null, '2024-12-10 00:00:00+00'::timestamptz, '2024-12-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지는 어떤 원리로 피부를 탄력있게 만드나요?$AAQ$, $AAA$써마지는 **피부 속에 열을 넣어 콜라겐을 재생시키는** 고주파 시술입니다. 젊을 때는 콜라겐이 많아 피부가 탱탱하지만 나이가 들면 콜라겐이 줄어 피부가 처지는데, 피부 속에 열을 넣어주면 이 열이 콜라겐 재생을 자극해 피부가 다시 탱탱해져요.

핵심 기술은 **피부 겉에 화상을 입히지 않으면서 속에는 열을 전달하는 것입니다**. 겉이 너무 뜨거워지면 화상을 입겠지만 써마지는 표피를 보호하면서 진피층에만 열을 전달하는 기술 덕분에 유명해졌어요. 다만 써마지는 **처진 피부를 끌어올려주는 시술은 아니고** 피부 탄력을 주는 시술입니다. 이미 많이 처진 경우에는 써마지 말고 다른 시술이 필요할 수 있어요. 좀 아픈 편이라 마취크림이나 수면마취, 호흡마취를 함께 진행하기도 합니다.$AAA$, array['써마지', '고주파', '콜라겐재생', '피부탄력', '원리']::text[], 2024, '2z-zBNyzkqs-2', 'https://youtu.be/2z-zBNyzkqs?t=120s', null, '2024-12-10 00:00:00+00'::timestamptz, '2024-12-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지와 비슷한 국산 고주파 장비도 효과가 있나요?$AAQ$, $AAA$써마지와 비슷한 국산 단극성 고주파 장비들도 좋은 옵션이 될 수 있습니다. **올리지오, 세르프, 볼류머, 덴서티, 텐서마 등이** 국내 회사에서 만들어진 비슷한 고주파 장비예요. 기본 단극성 고주파 원리는 써마지와 똑같고 각자 자랑하는 특성이 조금씩 있습니다.

써마지가 가장 오래된 장비이고 이 장비로 진행된 연구가 가장 많아 신뢰도가 높습니다. 스타벅스가 어디 매장을 가든 일정한 품질을 보장하는 것처럼 **써마지는 검증된 브랜드를 원할 때 좋은 선택입니다**. 반면 국산 장비들도 기술이 계속 발전하고 있어 **예산에 무리되지 않는 선에서 꾸준히 관리하고 싶다면** 합리적인 옵션이 됩니다. 고민하다 아무것도 안 하는 것보다 본인 사정에 맞게 선택해 꾸준히 유지하는 것이 가장 중요해요.$AAA$, array['써마지', '올리지오', '고주파장비', '국산장비', '가성비']::text[], 2024, '2z-zBNyzkqs-3', 'https://youtu.be/2z-zBNyzkqs?t=363s', null, '2024-12-10 00:00:00+00'::timestamptz, '2024-12-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지 시술은 어떤 사람에게 적합한가요?$AAQ$, $AAA$써마지는 **피부 노화를 예방하고 꾸준히 관리하고 싶은 분들에게** 적합한 시술입니다. 30대 후반에는 시술 받은 사람과 안 받은 사람 차이가 크지 않지만, 5년에서 10년 누적되면 차이가 크게 벌어져 동창회에서 '왜 안 늙었냐' 소리를 들을 수 있어요.

특히 피부가 건조하고 푸석한 분들은 시술 효과를 확 느낄 수 있어요. **피부가 얇고 잔주름이 신경 쓰이는 분들에게도 좋습니다**. 매년 한 번 정도 꾸준히 받으면 건조증이 줄고 피부 탄력 유지에 도움이 됩니다. 다만 이미 많이 처진 피부에는 적합하지 않아요. 써마지는 탄력을 주는 시술이지 처진 살을 끌어올려주는 시술은 아니기 때문에 그런 경우엔 다른 시술이 필요합니다. 통증이 있어 마취크림이나 비수면 호흡마취를 함께 진행할 수 있어요.$AAA$, array['써마지', '적합대상', '노화예방', '건조피부', '꾸준한관리']::text[], 2024, '2z-zBNyzkqs-4', 'https://youtu.be/2z-zBNyzkqs?t=240s', null, '2024-12-10 00:00:00+00'::timestamptz, '2024-12-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지와 세르프는 어떻게 다른가요?$AAQ$, $AAA$써마지는 리프팅의 대명사로 가장 오랫동안 증명된 장비이고, 세르프는 팁이 더 크고 통증이 덜한 장비입니다. 써마지는 피부가 얇고 살이 많지 않으면서 탄력을 원하시는 분께 적합한 오리지널 고주파 시술이에요. 반면 세르프는 팁이 1.5배 정도 더 커서 더 깊고 많은 에너지를 전달할 수 있는데도 통증은 거의 없습니다.

세르프의 가장 큰 특징은 **깊은 층, 중간 층, 얕은 층의 깊이 조절**이 가능하다는 점입니다. 어느 깊이에 몇 샷을 어떤 레벨로 쏠지 선택할 수 있어 환자별 맞춤형 조합이 가능해요. 살집 있는 분이나 땅콩형 얼굴로 굴곡이 진 분들에게는 세르프가 볼륨을 이동시켜 달걀형 얼굴에 가깝게 만들어 줍니다. 써마지는 만족도 1위로 보장된 장비이고, **세르프는 그 사이를 메우는 맞춤형 옵션**으로 보시면 좋습니다.$AAA$, array['써마지', '세르프', '고주파리프팅', '팁사이즈', '맞춤형리프팅']::text[], 2024, '8KUbNkEHaQo-1', 'https://youtu.be/8KUbNkEHaQo?t=27s', null, '2024-12-12 00:00:00+00'::timestamptz, '2024-12-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$고주파 리프팅 효과를 높이는 방법이 있나요?$AAQ$, $AAA$고주파 리프팅 효과를 높이는 핵심은 한 번에 최대한 많은 유효샷을 받는 것입니다. 컵라면을 끓일 때 물을 100도까지 끓여야 면이 익듯이, 리프팅도 피부를 일정 온도까지 올린 다음 그 온도를 유지해야 콜라겐이 새로 만들어져요. 온도를 올리는 데 쓰는 샷은 사실상 버려지므로, **샷을 많이 받을수록 유효샷 비율이 높아집니다**.

써마지 300샷 중 100샷이 온도를 올리는 데 쓰이면 실제 유효샷은 200샷뿐입니다. 600샷을 받으면 그만큼 유효샷이 늘어 효과가 비선형으로 크게 올라가요. 두 번째 팁은 이마보다 환자분들이 가장 고민하는 **중안면과 하안면에 샷을 집중하는 것**입니다. 마지막으로 티타늄·오푸스 같은 레이저나 리쥬란·쥬베룩 스킨부스터를 함께 받으면 얼굴 온도를 올리는 데 도움이 되어 써마지의 유효샷을 더 늘릴 수 있어요. 시술은 보통 1년에 한 번에서 두 번 정도 권해드립니다.$AAA$, array['유효샷', '써마지샷수', '리프팅조합', '고주파시술팁', '중안면집중']::text[], 2024, '8KUbNkEHaQo-2', 'https://youtu.be/8KUbNkEHaQo?t=1399s', null, '2024-12-12 00:00:00+00'::timestamptz, '2024-12-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$덴서티 하이팁은 어떤 분에게 잘 맞나요?$AAQ$, $AAA$덴서티 하이팁은 피부가 얇고 얕은 층의 잔주름·모공·피부결을 개선하고 싶은 분께 잘 맞는 고주파 시술입니다. 써마지의 네모 팁과 달리 덴서티는 11자 모양 팁을 사용해 섬세한 작업이 가능하고, 에너지 침투 깊이는 상대적으로 얕은 편이에요. 깊은 층에 별 관심이 없고 얕은 층 문제를 해결하고 싶은 분께 특히 권해드립니다.

얕은 층에 작용한다는 점이 단점만은 아닙니다. **눈가·입가의 자글자글한 잔주름, 모공, 피부결, 홍조** 같은 피부 표면 가까이 있는 문제들에 효과적이에요. 만약 덴서티 효과에 더해 깊은 층까지 동시에 잡고 싶다면 티타늄 리프팅을 함께 조합하면 됩니다. 그러면 **라인 관리와 주름 개선을 동시에 기대할 수 있어요**. 본인의 피부 두께와 고민 부위에 따라 장비를 골라야 하므로 진단 후 결정하시는 게 좋습니다.$AAA$, array['덴서티', '하이팁', '얕은층리프팅', '잔주름개선', '피부결관리']::text[], 2024, '8KUbNkEHaQo-3', 'https://youtu.be/8KUbNkEHaQo?t=1727s', null, '2024-12-12 00:00:00+00'::timestamptz, '2024-12-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$텐써마는 어떤 시술이고 누구에게 추천되나요?$AAQ$, $AAA$텐써마는 써마지의 대체 시술로 인기 있는 가성비형 고주파 리프팅입니다. 효과는 써마지와 비슷하면서도 비용 부담이 덜해, 써마지 비용이 부담스러운 분들이 받기 좋은 시술이에요. 팁이 커서 에너지가 깊게 들어가고 시술 시간도 써마지보다 빠른 편입니다.

써마지가 가장 오랫동안 만족도 1위로 보장된 오리지널 장비라면, **텐써마는 가성비의 끝판왕 포지션**입니다. 다만 본인의 얼굴형, 피부 두께, 처짐 정도에 따라 적합한 장비가 달라지므로 텐써마가 모두에게 정답은 아니에요. 진료실에서는 피부 진단기로 촬영을 먼저 하고, 얼굴을 보면서 어떤 시술이 가장 좋을지 또 어떤 조합이 좋을지 고민해 추천하는 편입니다. 시술은 보통 1년에 한 번에서 두 번 정도 받으시는 게 권장됩니다.$AAA$, array['텐써마', '가성비리프팅', '써마지대체', '고주파시술', '맞춤형추천']::text[], 2024, '8KUbNkEHaQo-4', 'https://youtu.be/8KUbNkEHaQo?t=379s', null, '2024-12-12 00:00:00+00'::timestamptz, '2024-12-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$세르프 시술의 가장 큰 특징은 무엇인가요?$AAQ$, $AAA$세르프의 가장 큰 특징은 통증이 거의 없는데도 효과가 좋다는 점입니다. 깊은 층·중간층·얕은 층까지 깊이 조절이 가능하고, 보통 쓰는 써마지 팁보다 1.5배 정도 큰 팁을 사용해요. 팁이 크면 피부 깊게 들어가고 에너지가 많이 전달되는데도 신기하게 안 아픈 게 세르프의 매력입니다.

실제로 6주 전 데모로 치료해드린 남자 환자분을 어제 다시 만났는데, **얼굴에서 광이 나고 모공도 개선**되어 깜짝 놀랐다고 해요. 손을 붙잡으며 너무 좋다고 감사 인사를 하셨습니다. 시술자가 어느 깊이에 얼마나 많은 에너지를 타겟할지 선택할 수 있어 환자 개개인에 맞는 조합이 가능해요. 통증에 예민한 분이나 입 근처처럼 아픈 부위까지 시술받아야 하는 분들에게 특히 권해 드릴 만한 시술입니다.$AAA$, array['세르프', '통증없는리프팅', '팁사이즈', '깊이조절', '모공개선']::text[], 2024, 'tOdt2ddTlYs-1', 'https://youtu.be/tOdt2ddTlYs?t=340s', null, '2024-12-13 00:00:00+00'::timestamptz, '2024-12-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지는 1년에 몇 번 받는 게 좋은가요?$AAQ$, $AAA$써마지는 1년에 최소 한 번에서 두 번 받는 게 권장되는 꾸준한 관리형 시술입니다. 적금이나 보험을 드는 것과 똑같다고 비유하는데, 한 번 받았다고 당장 엄청난 차이를 느끼지는 못할 수 있어요. 그러나 5년, 10년이 지나면 확실한 차이가 나타나는 시술입니다.

예컨대 김성령 씨처럼 미모가 유지되는 분들은 옛날부터 써마지를 꾸준히 받아왔을 가능성이 높습니다. **꾸준한 고주파 시술이 장기적인 탄력 유지의 핵심**이라고 보시면 돼요. 단발성 효과를 기대하기보다는 노화를 미루는 보험을 드는 개념으로 접근하시는 게 좋습니다. 본인 일정과 컨디션에 맞춰 1년에 한두 번씩 정기적으로 받으시면, 시간이 지났을 때 받지 않은 분들과 분명한 차이를 체감하실 수 있어요.$AAA$, array['써마지주기', '1년1회', '고주파꾸준관리', '장기효과', '노화방지']::text[], 2024, 'tOdt2ddTlYs-2', 'https://youtu.be/tOdt2ddTlYs?t=418s', null, '2024-12-13 00:00:00+00'::timestamptz, '2024-12-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$포젤란은 어떤 시술이고 어디에 효과적인가요?$AAQ$, $AAA$포젤란은 모공 개선과 피부결 향상에 강점을 보이는 스킨부스터입니다. 시술 후 피부가 반짝반짝 도자기처럼 된다는 표현이 자주 나올 만큼, 모공이 개선되고 결이 좋아졌다는 후기 빈도가 다른 스킨부스터에 비해 더 많은 편이에요. 광이 나는 피부를 원하는 분께 잘 맞는 선택지입니다.

특히 남성분들도 피부가 반짝거리는 느낌으로 변하는 경우가 많아, **모공·결 개선에 특화된 스킨부스터**라고 보시면 좋습니다. 광고나 협찬이 아니라 실제 임상에서 환자 만족도가 높아 권해 드리는 시술이에요. 다만 어떤 시술이든 개인의 피부 상태에 따라 반응이 달라질 수 있으므로, 본인의 모공·피부결 고민 정도를 진료실에서 확인한 뒤 결정하시는 게 좋습니다.$AAA$, array['포젤란', '스킨부스터', '모공개선', '피부결', '도자기피부']::text[], 2024, 'tOdt2ddTlYs-3', 'https://youtu.be/tOdt2ddTlYs?t=380s', null, '2024-12-13 00:00:00+00'::timestamptz, '2024-12-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지와 울쎄라는 어떻게 다른가요?$AAQ$, $AAA$써마지는 진피층의 콜라겐을 자극해 탄력을 높이는 시술이고, 울쎄라는 더 깊은 근막층까지 들어가는 리프팅 시술입니다. 써마지는 피부 속 콜라겐을 자극해 탄력을 올려주는 역할을 하고요, 울쎄라는 그것보다 더 깊이 들어가 근막층을 자극해 피부를 찰싹 달라붙게 해주는 리프팅 효과를 냅니다.

두 시술은 작용 깊이가 달라 **번갈아 시술하면 피부 각 층마다 탄력**을 줄 수 있어 시너지가 납니다. 최화정 씨가 대표적인 사례로, 1년에 한 번씩 울쎄라와 써마지를 꾸준히 받으면서 과도하지 않게 자연스러운 슬로우 에이징을 추구하는 분이에요. 시술 후 다운타임은 써마지는 거의 티가 안 나지만 **울쎄라는 며칠 정도 부을 수 있어요**. 본인 일정과 노화 단계를 고려해 두 시술을 조합하시면 효과적입니다.$AAA$, array['써마지', '울쎄라', '진피층', '근막층', '시너지효과']::text[], 2024, 'Ah3eRV4U784-1', 'https://youtu.be/Ah3eRV4U784?t=84s', null, '2024-12-17 00:00:00+00'::timestamptz, '2024-12-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$브이빔과 IPL은 어떻게 다른가요?$AAQ$, $AAA$브이빔은 피부 속 혈관을 줄여 홍조에 특화된 시술이고, IPL은 여러 파장의 빛이 한꺼번에 나와 다양한 효과를 두루두루 내주는 시술입니다. 브이빔은 혈관을 타겟해 홍조 개선에 효과가 좋고, IPL은 주근깨와 잡티 제거, 피부 톤 환하게 만들기, 홍조 개선까지 폭넓게 작용해요.

강민경 씨처럼 피부가 하얗고 조명이 센 무대에서 일하는 직업이라면 이 두 시술을 함께 활용하기 좋습니다. **잡티 관리에는 레이저 토닝, 홍조에는 브이빔과 IPL**을 꾸준히 받는 식이에요. 두 시술 모두 시술 후 거의 티가 안 나서 바로 화장도 가능하고, 위클리 케어로 부담 없이 받을 수 있습니다. 본인 고민이 혈관 위주인지, 색소까지 함께 가지고 있는지에 따라 선택하시면 좋습니다.$AAA$, array['브이빔', 'IPL', '홍조치료', '잡티제거', '혈관레이저']::text[], 2024, 'Ah3eRV4U784-2', 'https://youtu.be/Ah3eRV4U784?t=141s', null, '2024-12-17 00:00:00+00'::timestamptz, '2024-12-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$엑소좀과 더모톡신은 어떤 시술인가요?$AAQ$, $AAA$더모톡신은 스킨보톡스와 같은 시술로 피부결을 좋게 하고, 엑소좀은 피부 재생에 좋은 영양분을 공급하는 시술입니다. 더모톡신은 잔주름을 없애주고 모공을 줄여주며 피지가 많은 분의 피지도 줄여서 피부를 전반적으로 맨들맨들하게 만들어줘요. 엑소좀은 피부에 좋은 영양분을 공급해 재생 효과를 내주는 역할을 합니다.

한예슬 씨가 매년 초에 울쎄라·더모톡신·엑소좀을 함께 받고, 써마지는 6개월에 한 번씩 받는다고 알려져 있어요. **세 시술 모두 통증이 있어서 한꺼번에 받기는 어려우므로 수면마취를 하는 경우가 많습니다**. 마취크림만 바르고 받기엔 무리일 정도예요. 수면마취가 부담스러우면 비수면호흡마취로도 가능하니, 통증 민감도에 맞춰 마취 방식을 선택하시면 됩니다.$AAA$, array['엑소좀', '더모톡신', '스킨보톡스', '피부재생', '수면마취']::text[], 2024, 'Ah3eRV4U784-3', 'https://youtu.be/Ah3eRV4U784?t=181s', null, '2024-12-17 00:00:00+00'::timestamptz, '2024-12-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$LDM과 코레지 셀핏 같은 스킨케어는 효과가 있나요?$AAQ$, $AAA$LDM과 코레지 셀핏은 시술이 아닌 스킨케어 관리로, 꾸준히 받으면 피부 보습·재생과 미세한 리프팅 효과가 있습니다. 안소희 씨가 본인 유튜브에서 1-2주에 한 번씩 꾸준히 받는다고 소개한 관리인데요, 시술이 아니어서 아픈 게 하나도 없고 편안하게 마사지 받는 느낌으로 받을 수 있는 케어입니다.

울쎄라나 써마지처럼 한 번에 확 효과가 나타나거나 극적인 변화가 있는 건 아니에요. 다만 **꾸준히 받으면 차근차근 피부가 좋아진다**고 합니다. 피부가 빨개지거나 붓는 현상이 없어서 위클리 케어로 부담 없이 받을 수 있는 게 장점이에요. 큰 시술이 부담스럽거나 부담 없이 꾸준히 관리하고 싶은 분께 적합한 선택지입니다. 시술과 스킨케어를 본인 일정과 예산에 맞게 조합하시면 좋습니다.$AAA$, array['LDM', '코레지셀핏', '위클리케어', '스킨케어', '꾸준한관리']::text[], 2024, 'Ah3eRV4U784-4', 'https://youtu.be/Ah3eRV4U784?t=375s', null, '2024-12-17 00:00:00+00'::timestamptz, '2024-12-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$침샘 보톡스는 이중턱에 어떻게 효과가 있나요?$AAQ$, $AAA$침샘 보톡스는 비대된 침샘 크기를 줄여서 이중턱처럼 보이는 부위를 개선해주는 시술입니다. 얼굴에는 침을 만드는 침샘이 턱 밑과 귀 앞 등 여러 군데 있는데, 이 침샘이 커지면 이중턱처럼 보일 수 있어요. 턱 밑 침샘에 보톡스를 주사하면 크기를 효과적으로 줄일 수 있습니다.

과식·야식·흡연·음주 등으로 침샘이 과도하게 자극받으면 비대해질 수 있어요. 침샘인지 확인하는 방법은 혀로 입천장 끝을 댔을 때 튀어나오는 부분을 만져 보는 것입니다. **시술 후 2-3일부터 효과가 나타나기 시작해 2주째에 확실한 변화**를 느낄 수 있고, 처음에는 4-6개월 간격으로 맞다가 꾸준히 받으면 점점 시술 간격을 늘릴 수 있어요. 시술 시간이 짧고 가성비가 좋은 이중턱 시술이며, 침샘을 줄여도 다른 침샘이 있어 일상생활에 영향은 없습니다.$AAA$, array['침샘보톡스', '침샘비대증', '이중턱시술', '턱밑개선', '보톡스주기']::text[], 2024, '1wtAvzoqHbw-1', 'https://youtu.be/1wtAvzoqHbw?t=298s', null, '2024-12-19 00:00:00+00'::timestamptz, '2024-12-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$브이올렛은 일반 지방분해주사와 어떻게 다른가요?$AAQ$, $AAA$브이올렛은 정식 허가를 받은 단일 성분 데옥시콜산으로, 일반 지방분해주사보다 효과와 안정성이 검증된 시술입니다. 일반 지방분해주사는 병원마다 조제 방식이 다르고 표준화되어 있지 않은 반면, 브이올렛은 단일 성분으로 통일되어 있어 효과와 안정성 면에서 믿을 수 있어요. 데옥시콜산은 우리 체내에서도 지방을 분해시키는 성분으로 자연스럽게 작용합니다.

주사를 맞는 순간 부어오르기 시작해 통증이 있고, **지방을 파괴하면서 생기는 염증 반응으로 약 2주 동안 붓기**가 지속될 수 있어요. 이는 당연한 반응으로, 지방세포가 실제로 파괴되고 있다는 신호이기도 합니다. 지방이 많았던 부위에 여러 번 맞으면 꽤 효과를 볼 수 있어요. 다만 살이 늘어진 경우라면 브이올렛만으로 해결되지 않으므로 울쎄라 같은 리프팅을 함께 받으시는 게 좋습니다.$AAA$, array['브이올렛', '데옥시콜산', '지방분해', '이중턱지방', '붓기']::text[], 2024, '1wtAvzoqHbw-2', 'https://youtu.be/1wtAvzoqHbw?t=165s', null, '2024-12-19 00:00:00+00'::timestamptz, '2024-12-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$이중턱 원인별로 어떤 시술을 받는 게 좋나요?$AAQ$, $AAA$이중턱은 원인이 다양하므로 원인에 맞는 시술을 선택해야 효과가 좋습니다. 가볍게 쁘띠시술 정도만 받고 싶다면 윤곽주사가, 지방이 너무 많아서 파괴하고 싶다면 브이올렛이, 살이 처져 이중턱이 된 경우라면 울쎄라가, 살은 많지 않은데 턱 밑이 울룩불룩하다면 침샘 보톡스가 적합해요.

실제 본인이 10년 이상 이중턱을 달고 살면서 다양한 시술을 시도한 경험에 따르면, 윤곽주사는 큰 효과를 보지 못했고 턱 필러로 턱을 만들어주니 이중턱이 덜 보이긴 했지만 근본 해결은 안 됐어요. 그 뒤 브이올렛으로 지방을 줄이고, 살 처짐은 울쎄라로 잡고, **마지막에 침샘 보톡스가 가성비·효과 모두 가장 좋았다**고 합니다. 본인 턱 밑이 지방인지, 침샘인지, 처짐인지 진단을 받고 결정하시는 게 가장 효율적입니다.$AAA$, array['이중턱원인', '맞춤형시술', '윤곽주사', '턱필러', '이중턱진단']::text[], 2024, '1wtAvzoqHbw-3', 'https://youtu.be/1wtAvzoqHbw?t=2611s', null, '2024-12-19 00:00:00+00'::timestamptz, '2024-12-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$침샘 보톡스를 맞으면 침이 부족해지지 않나요?$AAQ$, $AAA$침샘 보톡스로 일부 침샘을 줄여도 침이 말라 일상생활에 영향을 주지는 않습니다. 우리 몸 곳곳에 침샘이 분산되어 있기 때문에, 턱 밑 침샘 일부의 크기만 줄인다고 해서 침이 마르거나 음식을 먹는 데 지장이 생기지는 않아요. 안전성이 검증된 흔한 시술 중 하나입니다.

시술 후에는 부작용보다 효과 측면에서 만족도가 높은 편이에요. 시술 시간이 짧고 가성비가 좋으면서도 깔끔하게 정돈되는 효과가 있어, **이중턱을 위해 받은 시술 중 가장 가성비와 효과가 좋았다**고 평가됩니다. 효과는 개인차가 있지만 보통 4-6개월 간격으로 권장되고, 꾸준히 정기적으로 맞다 보면 침샘 크기가 줄어 시술 간격을 늘릴 수 있어요. 정기적으로 6개월 간격까지 늘려가는 분도 있습니다.$AAA$, array['침샘보톡스부작용', '침마름', '안전성', '시술주기', '이중턱가성비']::text[], 2024, '1wtAvzoqHbw-4', 'https://youtu.be/1wtAvzoqHbw?t=420s', null, '2024-12-19 00:00:00+00'::timestamptz, '2024-12-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$건성 피부와 건조증, 건선은 어떻게 다른가요?$AAQ$, $AAA$건성 피부는 쉽게 건조해지는 피부 타입을, 건조증은 날씨 때문에 피부가 건조해져 생기는 불편한 증상을, 건선은 면역체계 이상으로 생기는 만성 염증성 피부 질환을 가리킵니다. 건성 피부와 건조증은 보습제를 잘 바르는 것으로 관리할 수 있지만, 건선은 100명 중 한두 명에게 생기는 별개의 질환이에요.

건선은 면역체계 이상 때문에 피부가 두꺼워지고 붉어지며 각질이 생기는 만성 질환입니다. **연고 도포가 기본 치료**이고, 추가로 자외선 치료나 엑시머 레이저로 병변만 타겟해 치료하기도 해요. 전신 증상이 심한 경우에는 먹는 약이나 한 달에 한 번, 두 달에 한 번 맞는 생물학적 제제 주사로 치료합니다. **건선은 평생 가는 질환이고 심하면 관절염이나 내부 장기 이상**으로 이어질 수 있어, 피부과에 가서 건선 같다고 말씀하시는 분 중 대부분은 사실 건조증이나 건성 피부인 경우가 많습니다.$AAA$, array['건성피부', '건조증', '건선', '만성염증성질환', '생물학적제재']::text[], 2024, 'n1dSF5i9pGc-1', 'https://youtu.be/n1dSF5i9pGc?t=153s', null, '2024-12-23 00:00:00+00'::timestamptz, '2024-12-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$건조한 겨울철 피부 보습은 어떻게 해야 하나요?$AAQ$, $AAA$건조한 겨울철 피부 관리는 세안·샤워 후 물기가 마르기 전에 빠르게 보습을 해주는 것이 가장 중요합니다. 겨울에는 습도 자체가 낮아 팔다리에 하얗게 각질이 올라오는 분들이 많고, 얼굴이 건조하면서 탄력까지 떨어져 보이게 돼요. 세수 후에 누구나 피부가 건조해지므로, 물기가 남아 있을 때 보습제를 발라 수분을 가두는 게 핵심입니다.

또 한 가지 중요한 점은 **얇게 여러 번 자주 바르는 것**이 한꺼번에 듬뿍 바르는 것보다 효과적이에요. 겨울에 자외선이 약하다고 생각하기 쉽지만, 눈이나 아스팔트에 반사되는 자외선도 피부에 자극을 주므로 자외선 차단제는 반드시 챙기셔야 합니다. 또 얼굴이 달아오를 때 얼음찜질은 피해야 해요. **차가움과 뜨거움이 반복되면 피부 자극이 늘어 안면 홍조가 더 심해질** 수 있습니다.$AAA$, array['겨울보습', '세안후보습', '얇게여러번', '자외선차단', '얼음찜질금지']::text[], 2024, 'n1dSF5i9pGc-2', 'https://youtu.be/n1dSF5i9pGc?t=118s', null, '2024-12-23 00:00:00+00'::timestamptz, '2024-12-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$안면 홍조는 어떻게 치료하나요?$AAQ$, $AAA$안면 홍조 치료는 혈관 자체를 줄이는 레이저와 피부 장벽을 튼튼하게 만드는 치료를 함께 병행하는 것이 핵심입니다. 첫 번째는 젠틀맥스·브이빔·M22 같은 혈관 레이저로 혈관 자체를 잡아주는 치료, 두 번째는 피부 장벽 자체를 튼튼하게 만드는 치료예요. 두 가지를 함께 받는 것이 가장 도움이 됩니다.

피부 장벽 강화 시술로는 고주파 치료, 리쥬란·쥬베룩 같은 주사제, 시크릿·더블 타이트 같은 바늘 고주파, LDM·더미오케어 같은 관리들이 있어요. **피부 장벽이 무너진 분과 혈관이 확장된 분, 둘 다 가진 분**으로 상태가 다르므로 정확한 진단이 우선입니다. 한 가지 시술이 만능 해결책은 아니에요. 또한 얼음찜질, 술, 매운 음식 같은 자극 요인을 피하고 겨울 자외선 차단까지 함께 챙기시는 게 중요합니다.$AAA$, array['안면홍조', '혈관레이저', '브이빔', '피부장벽강화', '리쥬란']::text[], 2024, 'n1dSF5i9pGc-3', 'https://youtu.be/n1dSF5i9pGc?t=356s', null, '2024-12-23 00:00:00+00'::timestamptz, '2024-12-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$건선이 있을 때 일상생활에서 어떻게 관리해야 하나요?$AAQ$, $AAA$건선이 있는 분들은 보습제 사용·미온수 목욕·자극 회피·스트레스 관리가 일상 관리의 핵심입니다. 건선이 있어도 건성 피부처럼 보습제를 발라주는 것은 기본이고요, 목욕은 42도 이하의 미온수로 가볍게 씻어주시는 게 좋습니다. 너무 뜨거운 물은 피부 자극이 심해 건선을 악화시킬 수 있어요.

또 피부를 과도하게 문지르는 자극이나 상처가 생기지 않게 주의해야 합니다. **스트레스가 건선과 밀접한 관련**이 있어 스트레스 관리도 매우 중요해요. 건선은 평생 가는 질환이고 심한 경우 관절염이나 내부 장기 이상까지 동반할 수 있으므로, 대학병원에서 진료를 계속 받아야 하는 경우도 있습니다. 건선과 단순 건조증은 다른 병이므로, 본인이 건선인지 건조증인지 확신이 안 든다면 전문의 진단을 먼저 받아보시는 것이 가장 안전합니다.$AAA$, array['건선관리', '미온수목욕', '스트레스관리', '보습제', '건선악화요인']::text[], 2024, 'n1dSF5i9pGc-4', 'https://youtu.be/n1dSF5i9pGc?t=254s', null, '2024-12-23 00:00:00+00'::timestamptz, '2024-12-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미를 한 번에 없앨 수 있다는 광고는 믿어도 되나요?$AAQ$, $AAA$기미를 한 번에 없앨 수 있다는 광고는 거짓말이고, 무리하게 시도하면 오히려 더 진해질 수 있어 위험합니다. 기미라고 진단되는 순간 완전히 없앤다는 목표가 아니라 많이 연해지게 한다는 목표로 치료해야 해요. 치료를 중단하면 몇 개월 뒤 다시 생길 수 있어 유지치료가 필수입니다.

기미는 호르몬이나 자외선에 의해서도 계속 진해질 수 있어, 아무리 치료를 잘해도 재발이 가능해요. **피부과에서 기미는 당뇨나 고혈압처럼 평생 관리하는 만성 질환**으로 다룹니다. 통계적으로 한국 사람들이 미용 목적으로 피부과를 찾는 전체 상담의 60-70%가 색소 때문이라고 할 만큼 흔한 고민이에요. 그래서 "한 번에 다 없애드린다"는 곳은 거르시고, 정확한 진단과 맞춤형 치료 계획을 제시하는 곳을 선택하는 것이 가장 안전합니다.$AAA$, array['기미한번에', '기미재발', '유지치료', '만성질환관리', '광고주의']::text[], 2024, 'bA7b_xLi3_U-1', 'https://youtu.be/bA7b_xLi3_U?t=14s', null, '2024-12-24 00:00:00+00'::timestamptz, '2024-12-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미와 주근깨, 흑자는 어떻게 다르게 치료하나요?$AAQ$, $AAA$겉으로 보이는 갈색 반점도 실제 진단은 기미·주근깨·흑자로 다양하며, 각각 치료 목표와 방법이 다릅니다. 주근깨는 한두 번만 치료해도 충분히 좋아질 수 있는 방법이 있어 2-30대 분들이 주근깨로 오시면 한 번에 없애드린다고 쿨하게 말씀드릴 수 있어요. 반면 기미는 양측 광대의 대칭적인 색소가 특징으로 완전히 없애는 것이 목표가 아닙니다.

이 모든 것을 다 가진 환자분들도 많아서 진단을 정확히 못하고 치료하면 오히려 색소가 더 진해질 수 있어요. **푸른색 UV 모드가 있는 피부 진단기나 우두등**으로 진단하는 곳을 확인하시는 게 좋습니다. 동양인은 얼굴에서 어두운 영역과 밝은 영역을 나누는 선이 있는데, **이 선을 기준으로 어두운 영역은 햇빛에 노출돼도 잡티가 더 잘 생기고 치료도 어려워요**. 같은 갈색 반점이라도 진단에 따라 레이저 종류와 횟수가 완전히 달라집니다.$AAA$, array['기미주근깨흑자', '색소진단', '피부진단기', '색소선', '맞춤형치료']::text[], 2024, 'bA7b_xLi3_U-2', 'https://youtu.be/bA7b_xLi3_U?t=137s', null, '2024-12-24 00:00:00+00'::timestamptz, '2024-12-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미 잡티 치료받기 전에 확인해야 할 것은 무엇인가요?$AAQ$, $AAA$피부과에 가기 전 확인해야 할 세 가지는 피부 진단기 보유 여부, 색소 레이저 장비의 다양성, 그리고 전반적 케어 가능 여부입니다. 첫 번째로 푸른색 UV 모드가 있는 피부 진단기나 우두등으로 색소를 진단하는 곳인지 확인하세요. 진단 없이는 정확한 치료 방향이 나올 수 없어요.

두 번째로 색소 치료 레이저 장비를 고루고루 갖추고 있는지 보는 것도 중요합니다. **아무리 신선한 재료라도 맛없는 요리가 될 수 있듯이** 장비가 다는 아니지만 다양한 옵션이 있어야 환자별 맞춤 치료가 가능해요. 세 번째로 단순히 레이저만 권유하는 곳이 아니라 **피부 장벽 관리, 먹는 약 처방, 홈케어 방법까지 설명**해주는 곳이 좋습니다. 또 "한 번에 다 없애드립니다" 식의 마케팅을 하는 병원은 거르시는 게 안전합니다.$AAA$, array['병원선택기준', '피부진단기', '색소레이저', '홈케어상담', '전문의진단']::text[], 2024, 'bA7b_xLi3_U-3', 'https://youtu.be/bA7b_xLi3_U?t=325s', null, '2024-12-24 00:00:00+00'::timestamptz, '2024-12-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$색소 치료 기간은 얼마나 걸리나요?$AAQ$, $AAA$색소 치료는 보통 1-2주 간격으로 10회 정도, 총 3-4개월의 기간이 필요합니다. 2-30대 분들이 주근깨로 방문하시면 그날 한 번에 없애드린다고 말씀드리는 경우도 있지만, 보통은 딱지를 만들거나 물리적으로 깎아내는 방식으로 한 번에 끝나는 색소만 가지신 분이 거의 없어요. 그래서 단계적인 치료가 필요합니다.

저는 보통 **1-2주 간격으로 10회 정도** 치료를 먼저 받아 보시고, 그렇게 약 3-4개월이 지난 시점에 색소가 얼마나 개선되었는지 체크해 보시라고 안내드립니다. 색소치료는 너무 서두르지 말고 정확한 진단과 개선 목표치를 피부과 전문의와 충분히 상담한 뒤 시작해야 해요. **빠른 치료가 최선이 아니라 정확하고 확실한 치료가 최선**입니다. 기미인 경우라면 중단 후 재발 가능성이 있어 이후 유지치료까지 함께 고려하셔야 합니다.$AAA$, array['색소치료기간', '10회치료', '치료주기', '유지치료', '단계적치료']::text[], 2024, 'bA7b_xLi3_U-4', 'https://youtu.be/bA7b_xLi3_U?t=433s', null, '2024-12-24 00:00:00+00'::timestamptz, '2024-12-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$쥬베룩은 어떻게 효과가 나타나나요?$AAQ$, $AAA$쥬베룩은 피부에 콜라겐이 스스로 생성될 수 있도록 자극하는 가루 형태의 스킨부스터입니다. 피부 진피에 있는 콜라겐과 엘라스틴이 늙고 병들면 푸석푸석해지고 처지며 볼륨이 꺼지게 되는데, 쥬베룩은 콜라겐 씨앗을 피부 속에 심어 스스로 강한 힘을 갖게 해주는 시술이에요.

**콜라겐 생성 자체가 3주 뒤부터 효과가 나타나기 시작하고**, 1회만으로는 눈에 띄는 변화를 보기 어렵습니다. 그래서 4주 간격으로 3회 정도 먼저 받아 보면서 효과를 느껴 보시고, 그 뒤에는 18-24개월 후 꾸준히 받으시는 게 권장돼요. 푸석푸석함·잔주름·모공·여드름 흉터·기미까지 폭넓게 활용되는 시술이라 항노화의 끝판왕으로 불리기도 합니다. 노화는 계속 진행되므로 **콜라겐이 없어질 만하면 다시 자극시켜주는 꾸준한 관리**가 핵심입니다.$AAA$, array['쥬베룩', '콜라겐생성', '스킨부스터', '항노화', 'PDLLA']::text[], 2024, '9y9A7DHVrFc-1', 'https://youtu.be/9y9A7DHVrFc?t=130s', null, '2024-12-26 00:00:00+00'::timestamptz, '2024-12-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$쥬베룩과 쥬베룩 볼륨, 스컬트라는 어떻게 다른가요?$AAQ$, $AAA$셋 다 콜라겐 생성을 촉진하는 점은 같지만 입자 모양과 크기, 용도가 다릅니다. 스컬트라는 입자가 뾰족뾰족해 자극이 더 강하고 콜라겐 생성 유도가 잘 되는데, 그만큼 결절 이슈가 있어 입자를 동그랗게 만든 쥬베룩과 쥬베룩 볼륨이 만들어졌어요. 입자 크기는 쥬베룩 볼륨이 쥬베룩보다 더 크고 콜라겐 생성에도 더 유리합니다.

자연스러운 볼류마이징 목적일 때는 크기가 큰 **스컬트라나 쥬베룩 볼륨을 주로 쓰는 편**이에요. 다만 입자가 커서 바늘로 주입하기 어렵습니다. 반면 여드름 흉터나 모공 축소는 피부 얕은 층에 직접 콜라겐 씨앗을 뿌려야 효과가 좋아, 이럴 때는 **작은 입자의 쥬베룩을 바늘로 직접 주사하는 게 더 적합합니다**. 잔주름·흉터·모공 같은 리쥬비네이션 목적엔 쥬베룩, 전체 볼륨 회복엔 스컬트라·쥬베룩 볼륨으로 구분하시면 됩니다.$AAA$, array['쥬베룩볼륨', '스컬트라', '입자크기', '볼류마이징', '리쥬비네이션']::text[], 2024, '9y9A7DHVrFc-2', 'https://youtu.be/9y9A7DHVrFc?t=270s', null, '2024-12-26 00:00:00+00'::timestamptz, '2024-12-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$쥬베룩 결절 부작용은 얼마나 위험한가요?$AAQ$, $AAA$쥬베룩의 결절 부작용은 표준화된 프로토콜이 도입된 지금은 거의 드뭅니다. 결절은 쥬베룩 가루를 생리식염수에 녹일 때 희석 비율과 균일성이 안 맞으면 생길 수 있는데, 예전에는 시술자마다 희석 비율이 제각각이라 빈도가 있었어요. 요즘은 표준화 프로토콜이 정착돼 거의 발생하지 않는 수준입니다.

또 **쥬베룩과 쥬베룩 볼륨은 동그란 입자 안이 스펀지처럼 텅 비어 있는 구조**라 결절 위험이 원래 적고, 만약 생기더라도 쉽게 해결할 수 있어요. 다만 표준 프로토콜만으로 충분한 건 아니고 **시술자가 원하는 위치에 소량을 정확하게 넣는 술기**도 중요합니다. 일상에서 느낄 만한 부작용은 멍이 들거나 3일 정도 불편함이 있는 수준이에요. 통증이 무서우신 분은 호흡마취로 거의 통증 없이 받을 수도 있습니다.$AAA$, array['쥬베룩결절', '표준화프로토콜', '희석비율', '스펀지구조', '부작용']::text[], 2024, '9y9A7DHVrFc-3', 'https://youtu.be/9y9A7DHVrFc?t=395s', null, '2024-12-26 00:00:00+00'::timestamptz, '2024-12-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$민감성 피부도 쥬베룩 시술이 가능한가요?$AAQ$, $AAA$쥬베룩은 오히려 민감한 피부와 피부 장벽이 무너진 분께 더 적합한 시술입니다. 민감한 분들은 레이저 시술 후 더 자극을 받는 경우가 있는데, 쥬베룩은 콜라겐 씨앗 자체를 피부 속에 심어 안에서부터 변화가 시작되기 때문에 자극이 적어요. 피부과에서 예뻐지는 시술을 하고 싶지만 너무 예민한 분들이 가장 먼저 시도해 볼 수 있는 시술입니다.

다만 **콜라겐 생성에 시간이 걸리는 시술**이므로 주사 직후 즉각적인 효과가 필요한 분들에겐 권해드리지 않아요. 통증은 주입 방식에 따라 달라집니다. 손주사나 더마샤인·하이쿡스 같은 기계로 직접 넣을 때는 아프지만, 얼굴에 뿌려두고 바늘 고주파나 강한 압력으로 밀어 넣으면 효과는 다소 떨어져도 통증이 훨씬 덜해요. 통증이 정말 무서우면 호흡마취로 거의 통증 없이 받을 수 있습니다.$AAA$, array['민감성피부', '쥬베룩적합성', '피부장벽', '주입방식', '호흡마취']::text[], 2024, '9y9A7DHVrFc-4', 'https://youtu.be/9y9A7DHVrFc?t=449s', null, '2024-12-26 00:00:00+00'::timestamptz, '2024-12-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$주근깨와 흑자, 기미는 어떻게 다른가요?$AAQ$, $AAA$주근깨, 흑자, 기미는 색소 종류와 치료 난이도가 모두 다른 별개의 질환입니다. 주근깨는 햇빛 노출이 많은 부위에 생기는 동그란 갈색 반점으로 **치료 난이도 별 1개**이며, 1~2회 시술만으로도 충분히 개선될 수 있어요. 흑자는 주근깨보다 크기가 크고 경계가 뚜렷하며 40대 분들에게 흔하고, 치료 난이도는 별 3개입니다.

기미는 가장 어려운 색소 질환으로 치료 난이도가 별 5개에 해당합니다. 주근깨와 흑자는 색소 기계가 일시적으로 자극받아 생긴 반면, 기미는 멜라닌 색소를 만드는 기계가 계속 색소를 만들어내는 상태예요. 흑자는 처음에 딱지를 만드는 방식으로 치료하지만, **염증 후 색소침착을 빼는 작업이 추가로 필요한 경우가 많아** 난이도가 올라갑니다. 따라서 같은 갈색 반점처럼 보여도 정확한 진단이 가장 먼저입니다.$AAA$, array['주근깨', '흑자', '기미', '색소치료', '치료난이도']::text[], 2024, 'yzruxX_RvEk-1', 'https://youtu.be/yzruxX_RvEk?t=64s', null, '2024-12-30 00:00:00+00'::timestamptz, '2024-12-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미는 왜 레이저만으로 치료가 안 되나요?$AAQ$, $AAA$기미는 멜라닌을 만드는 색소 기계 자체가 과민해진 상태이기 때문에, 레이저만으로는 근본 해결이 어렵습니다. 정상 피부에서 색소 기계가 일시적으로 한 번 색소를 만드는 것과 달리, **기미는 이 기계들이 계속 색소를 만들고 있는 상태**예요. 게다가 피부 장벽이 무너지면 외부 자극이 들어오기 훨씬 쉬워져 더 민감하게 반응합니다.

그래서 기미는 더운 날 땀을 흘리거나 화장품을 잘못 발라도 쉽게 자극되고 쉽게 색소로 이어집니다. 치료할 때는 피부 장벽을 튼튼하게 하고 **과민해진 기계를 진정시키는 치료들도 꼭 같이 해야 해요**. 피부 재생 관리인 LDM이나 콜라겐 재생 부스터, 고주파 치료 같은 것들을 함께 합니다. 또한 옅게 만들어 놓아도 치료를 중단하면 재발하는 경우가 많아, 기미 치료는 유지 치료가 꼭 필요한 마라톤 같은 과정입니다.$AAA$, array['기미', '레이저토닝', '피부장벽', '복합치료', '유지치료']::text[], 2024, 'yzruxX_RvEk-2', 'https://youtu.be/yzruxX_RvEk?t=155s', null, '2024-12-30 00:00:00+00'::timestamptz, '2024-12-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$애브넘과 기미는 어떻게 구분하나요?$AAQ$, $AAA$애브넘과 기미는 색깔과 분포 형태로 구분하며, 치료 방법이 완전히 달라 정확한 감별이 중요합니다. 기미는 얼굴에 **넓게 펼쳐져 있고 갈색**을 띠는 반면, 애브넘(후천성 양측성 오타모반)은 특히 광대 부위에 동글동글하게 모여 있고 갈색이 아니라 약간 회색빛이나 푸른빛을 띱니다. 콧망울에 생기는 경우도 있어요.

애브넘은 특히 동양인 여자들에게 많이 생기고 환자들의 잡티 사이에 끼어 있는 경우도 꽤 있습니다. 기미라고 생각하고 치료하면 애브넘은 사라지지 않는데, **애브넘은 색소 덩이가 굉장히 커서 강력한 에너지로 깨부숴야 하기 때문**입니다. 그래서 피코 레이저나 피코 토닝으로 따로 치료하고, 일반 레이저 토닝으로 치료할 때는 10번으로 부족하고 최소 2~30회는 치료해야 해요. 비유하자면 기미는 물고기들이 연못에 넓게 퍼져 있고, 애브넘은 깊은 곳에 동글동글하게 모여 있는 형태입니다.$AAA$, array['애브넘', '기미', '오타모반', '피코토닝', '감별진단']::text[], 2024, 'yzruxX_RvEk-3', 'https://youtu.be/yzruxX_RvEk?t=270s', null, '2024-12-30 00:00:00+00'::timestamptz, '2024-12-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$병원마다 색소 치료 가격이 왜 이렇게 차이 나나요?$AAQ$, $AAA$색소 치료 가격은 환자의 색소 종류와 필요한 복합 치료 구성에 따라 달라지기 때문에 병원마다, 또 같은 병원 내에서도 차이가 납니다. 의사가 잡티를 얼마만큼 없애줄 수 있는지에 대한 자신감이나 노하우 같은 가치가 가격에 묻어 있다고 볼 수 있어요. 또한 단순히 색소만 없애는 치료가 아니라, **피부 장벽을 튼튼히 하는 관리나 콜라겐을 채워주는 복합 치료가 추가되면** 가격은 올라갑니다.

예를 들어 다른 병원에서 레이저 토닝 10번을 받았는데 효과가 없다고 오시는 분들이 있어요. 그런 경우는 피부 장벽 치료나 콜라겐 치료 같은 복합적인 치료가 필요한 환자인데, 그걸 안 하고 토닝만 했기 때문에 효과가 없는 거예요. 비싼 걸 일부러 권하는 게 아니라 필요하기 때문에 권하는 겁니다. 피부는 한 번에 생긴 게 아니듯 한 번에 없앨 수 없으니, **색소치료는 100m 달리기가 아니라 마라톤이라는 마음**으로 접근해야 합니다.$AAA$, array['색소치료가격', '레이저토닝', '복합치료', '병원선택', '피부장벽']::text[], 2024, 'yzruxX_RvEk-4', 'https://youtu.be/yzruxX_RvEk?t=433s', null, '2024-12-30 00:00:00+00'::timestamptz, '2024-12-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$다이소 레티놀 세럼 처음 사용해도 괜찮을까요?$AAQ$, $AAA$다이소에서 판매하는 본셉 레티놀 500 IU 세럼은 농도 0.05%로 입문용에 적합한 제품입니다. 토니모리와 다이소가 콜라보로 만든 제품으로, **처음 레티놀을 시작하는 분들에게 괜찮은 농도**예요. 레티놀 외에도 세라마이드, 히알루론산, 병풀추출물 같은 진정·보습 성분이 들어 있어 자극을 최소화하면서 피부 재생을 시킬 수 있습니다.

다만 레티놀은 자극감이 있을 수 있어 낮은 농도에서 서서히 올려가야 합니다. 얼굴에 바르기 전 팔 안쪽이나 귀 뒤에 소량 발라보고 하루 지난 후 확인하세요. 낮에 바르면 자외선에 의해 분해될 수 있으니 자기 전에 완두콩 하나만큼만 발라야 하고, **처음에는 일주일에 두세 번 정도로 시작해 적응되면 매일 사용으로 바꾸는 것이 좋습니다**. 레티놀 바른 피부는 자외선에 더 민감해지므로 낮에 선크림은 꼭 챙겨 바르세요.$AAA$, array['레티놀세럼', '다이소', '입문용레티놀', '사용법', '자외선차단']::text[], 2025, 'bZqrA80ESnE-1', 'https://youtu.be/bZqrA80ESnE?t=38s', null, '2025-01-02 00:00:00+00'::timestamptz, '2025-01-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$어성초 칼라민 진정콕 스팟은 어떻게 발라야 하나요?$AAQ$, $AAA$어성초 칼라민 진정콕 스팟은 트러블이 1~2개씩 올라올 때 자기 전에 면봉으로 톡 바르고 아침에 세안하는 방식으로 사용하는 제품입니다. 주성분으로 **칼라민 9%, 어성초 0.01%**가 들어 있어요. 칼라민은 가려운 것을 진정시키고 염증 반응을 줄여주기 위해 피부과에서 오래 전부터 사용해온 성분이고, 어성초는 피부를 진정시키고 염증을 가라앉히는 작용을 합니다.

제품을 보면 층이 나누어져 있는데, 1층 칼라민은 항염 효과로 트러블을 가라앉히고 2층 앰플에는 각질 제거 성분이 들어 있습니다. 흔들지 말고 그대로 사용해야 해요. 논코메도제닉 테스트와 피부 자극 테스트를 거쳐 여드름이 있는 분들도 안전하게 쓸 수 있지만, **각질 제거 성분으로 BHA가 들어 있어 화한 느낌이 들 수 있어요**. 천연 오일이 포함되어 평소 오일 알러지가 있는 분들은 조심해서 사용해야 합니다.$AAA$, array['칼라민스팟', '어성초', '트러블케어', '여드름관리', '사용법']::text[], 2025, 'bZqrA80ESnE-2', 'https://youtu.be/bZqrA80ESnE?t=120s', null, '2025-01-02 00:00:00+00'::timestamptz, '2025-01-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$겨울에 손이 자주 트는데 어떻게 관리해야 하나요?$AAQ$, $AAA$손이 잘 트는 분들은 핸드크림을 가지고 다니면서 손을 씻을 때마다 보습을 해주셔야 합니다. 손은 물에 닿았다가 마를 때 건조해지기 때문이에요. 설거지를 **10분 동안 한 번 하는 것보다 1분 동안 10번 하는 것이 훨씬 더 안 좋습니다**. 물에 닿는 횟수가 많을수록 건조해지는 정도가 심해지기 때문이에요.

니베아 크림은 글리세린이 들어 있어 수분감을 주고 피부에 막을 잘 씌워 속 수분이 날아가지 않게 보호해줍니다. 5천 원 정도로 큰 용량이라 손뿐만 아니라 몸에도 아끼지 않고 바르기 좋아요. 아트릭스 핸드크림은 실리콘 성분이 들어 있어 끈적임이 덜해 휴대폰 액정에 자국이 적게 남습니다. **다만 페녹시에탄올이나 파라벤이 들어 있어 예민하신 분들은 주의가 필요하고**, 향료 알러지가 있는 분들은 무향·무색 제품을 선택하세요.$AAA$, array['핸드크림', '손건조', '주부습진', '겨울보습', '니베아']::text[], 2025, 'bZqrA80ESnE-3', 'https://youtu.be/bZqrA80ESnE?t=290s', null, '2025-01-02 00:00:00+00'::timestamptz, '2025-01-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$발꿈치 각질이 심할 때 어떤 크림이 좋은가요?$AAQ$, $AAA$각질이 두꺼워지기 쉬운 발에는 우레아 성분이 들어 있는 발 전용 크림이 효과적입니다. 우레아는 피부 각질을 분해해주고 피부 속 단백질과 결합해 수분을 잡아주는 역할을 해 피부를 더 촉촉하게 만들어줘요. **우레아가 20% 들어간 것은 약국에서 의약품으로 살 수 있고**, 화장품에서는 10%까지가 최대입니다.

다이소에 우레아 10%가 들어간 제품이 있고 글리세린이나 시아버터 같은 보습 성분도 함께 포함되어 있어요. 발은 체중을 지탱하느라 각질이 두꺼워지기 쉽고, 히터 트는 건조한 실내에서 양말을 벗고 있으면 더 건조해집니다. 다만 **발 냄새 제거를 위해 티트리잎오일, 페퍼민트잎추출물, 향료 등이 들어 있어** 알러지가 있는 분들은 주의해야 합니다. 건조함이 심해 갈라져 피가 날 정도라면 의약품 등급의 고농도 제품도 고려해보세요.$AAA$, array['발크림', '우레아', '각질제거', '발꿈치갈라짐', '보습제']::text[], 2025, 'bZqrA80ESnE-4', 'https://youtu.be/bZqrA80ESnE?t=362s', null, '2025-01-02 00:00:00+00'::timestamptz, '2025-01-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레디어스는 다른 콜라겐 부스터와 어떻게 다른가요?$AAQ$, $AAA$레디어스는 피부를 구성하는 다섯 가지 성분을 모두 만들어내는 점이 다른 콜라겐 부스터와 가장 큰 차이입니다. 다른 시술들이 피부 구성 성분의 일부만 만들어내는 것과 달리, 레디어스는 1형 콜라겐, 3형 콜라겐, **엘라스틴, 프로테오글리칸, 신생혈관**까지 모두 자극합니다. 칼슘 하이드록시아파타이트라는 우리 몸에 원래 있는 성분을 사용해 친화력이 높고 부작용이 적은 편이에요.

기존의 필러나 쥬베룩 볼륨, 스컬트라 같은 시술들은 앞 볼, 옆 볼, 관자, 팔자주름 같은 특정한 꺼진 부위에 볼륨을 세워주는 데 포커스가 맞춰져 있었습니다. 반면 레디어스는 **전반적으로 피부 자체를 살짝 두껍게 만들어주는 시술**이에요. 그래서 피부가 종잇장처럼 얇아 푸석해지고 잔주름이 많은 피부에 가장 효과가 좋습니다. FDA 승인을 받은 지 20년이 지났고 전 세계 1,500만 케이스 이상 시술이 진행되었어요.$AAA$, array['레디어스', '콜라겐부스터', '칼슘하이드록시아파타이트', '다섯가지성분', '스컬트라비교']::text[], 2025, '5u9kLL_PZ7M-1', 'https://youtu.be/5u9kLL_PZ7M?t=140s', null, '2025-01-03 00:00:00+00'::timestamptz, '2025-01-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레디어스 효과는 얼마나 오래가나요?$AAQ$, $AAA$레디어스 효과는 보통 **6개월에서 1년 정도** 지속되며, 사람에 따라서는 1년에서 2년까지 가시는 분들도 있습니다. 시술 직후부터 볼륨감이 생기고, 시간이 지나면서 콜라겐이 생성되며 자연스럽게 차오르면서 6개월에서 1년까지는 지속적으로 좋아져요. 보통 한 달 간격으로 두 번 정도 시술하는 것을 권하는데, 그 이후가 레디어스의 진짜 매력이 시작되는 시기입니다.

시술 권장 주기는 1년에 한 번 정도지만, **사람에 따라 2~3년 충분히 놔두고 더 불편해지면 다시 오시라고 안내**하는 경우도 있어요. 효과를 잘 유지하기 위해서는 시술 후 자외선 차단과 보습 관리를 기본적으로 해주시는 게 좋습니다. 4주 뒤 사진을 보면 붓기가 다 빠진 상태에서도 볼륨감은 그대로 유지되고, 팔자주름과 피부결까지 좋아진 결과를 확인할 수 있어요.$AAA$, array['레디어스효과', '지속기간', '재시술주기', '콜라겐생성', '유지관리']::text[], 2025, '5u9kLL_PZ7M-2', 'https://youtu.be/5u9kLL_PZ7M?t=315s', null, '2025-01-03 00:00:00+00'::timestamptz, '2025-01-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레디어스는 누구에게 잘 맞는 시술인가요?$AAQ$, $AAA$레디어스는 피부가 전반적으로 얇고 잔주름이 많은 분들에게 가장 잘 맞는 시술입니다. **종잇장처럼 얇아서 쉽게 푸석해지고** 잔주름이 많이 생기는 피부에 가장 효과가 좋아요. 기존 필러나 스컬트라처럼 특정 위치의 꺼진 부위를 보완하는 시술과 달리, 레디어스는 피부 자체를 살짝 두껍게 만들어주는 특성이 있습니다.

두 번째로는 팔자주름과 아랫볼, 입가 주변처럼 **피부가 쪼글쪼글해지고 얇아 주름이 많이 생기는 위치에 전반적으로 볼륨을 채워주는 데 효과가 좋아요**. 마지막으로 리프팅 시술을 받으러 오시는 분들 중 전반적으로 피부 탄력이 너무 떨어진 분들에게도 권합니다. 써마지나 울쎄라 같은 시술을 해도 탄력 회복이 어려운 분들에게 레디어스가 탄력을 채워주는 데 도움이 됩니다. 특히 40대 이후부터는 콜라겐이 급격히 감소하면서 노화가 가속적으로 진행되는 시기예요.$AAA$, array['레디어스적응증', '얇은피부', '팔자주름', '탄력저하', '안티에이징']::text[], 2025, '5u9kLL_PZ7M-3', 'https://youtu.be/5u9kLL_PZ7M?t=345s', null, '2025-01-03 00:00:00+00'::timestamptz, '2025-01-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레디어스 시술 후 주의할 점은 무엇인가요?$AAQ$, $AAA$레디어스 시술 후에는 일반적인 시술 주의사항과 비슷하게 피부 자극을 줄이는 것이 중요합니다. **너무 피부를 자극하는 세안, 과한 운동, 사우나** 같은 붓기를 유발할 수 있는 행동은 줄이는 게 좋아요. 대부분 일주일 이내에 좋아지지만, 아스피린 같은 혈전제를 드시는 경우 멍이나 붓기가 오래 갈 수 있습니다.

그래서 시술 일주일 전부터는 아스피린이나 혈전제를 끊을 수 있으면 끊고 시술받는 것이 좋고, 시술 전후 음주도 붓기·멍을 길게 만들 수 있어 피하셔야 해요. 일반 필러와 달리 **특별히 어디를 누르면 안 된다는 주의사항은 별로 없습니다**. 전반적으로 영양분을 공급해 피부가 자라나오게 만드는 시술이기 때문이에요. 보톡스, 울쎄라, 써마지 같은 안티에이징 시술과 같은 날 진행하는 경우도 많지만, 레디어스를 먼저 받았다면 1~2주 정도 회복 시간을 두고 다음 시술을 받는 게 좋습니다.$AAA$, array['레디어스주의사항', '아스피린', '음주', '시술병행', '회복기간']::text[], 2025, '5u9kLL_PZ7M-4', 'https://youtu.be/5u9kLL_PZ7M?t=445s', null, '2025-01-03 00:00:00+00'::timestamptz, '2025-01-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$대상포진과 입술 단순포진은 같은 병인가요?$AAQ$, $AAA$대상포진과 단순포진은 원인 바이러스부터 다른 완전히 별개의 질환입니다. 대상포진은 **수두 바이러스가 원인**이고, 단순포진은 헤르페스 심플렉스 바이러스가 원인이에요. 대상포진은 어린 시절 걸렸던 수두 바이러스가 신경절에 숨어 있다가 면역력이 떨어지면 다시 나타나는 것으로, 몸의 중심에서 한쪽으로만 띠 모양의 물집이 발생합니다.

대상포진의 가장 큰 특징은 극심한 통증이고, 보통 통증은 수포가 발생하기 며칠 전에 나타나요. 옷깃만 스쳐도 너무 아프다거나 칼로 찌르는 것 같다고 표현합니다. 반면 단순포진은 따끔거리고 간지러운 증상이 대부분이고, 띠 모양이 아니라 **주로 입술 주변에 작게 물집이 여러 개 모여 생깁니다**. 대상포진은 한 사람이 살면서 보통 한 번만 발생하고 6% 미만만 재발하는 반면, 입술포진은 피곤할 때마다 자주 재발해요. 대상포진은 예방접종이 있지만 단순포진은 컨디션 관리만이 발생을 줄일 수 있습니다.$AAA$, array['대상포진', '단순포진', '수두바이러스', '헤르페스', '감별']::text[], 2025, 'wRTdq73ZEEY-1', 'https://youtu.be/wRTdq73ZEEY?t=54s', null, '2025-01-08 00:00:00+00'::timestamptz, '2025-01-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$대상포진은 왜 72시간 안에 치료해야 하나요?$AAQ$, $AAA$대상포진은 피부 병변 발생 후 **72시간 이내에 항바이러스제를 복용해야** 통증 발생 빈도와 대상포진 후 신경통 발생을 줄일 수 있기 때문입니다. 치료가 늦어지면 처음처럼 심한 통증이 수개월에서 수년 이상도 지속되는 대상포진 후 신경통이 합병증으로 생길 수 있어요. 고령이거나 대상포진 초기 통증과 수포가 심한 경우 발생 위험이 높습니다.

대상포진 바이러스가 얼굴 신경을 공격하면 람세이헌트 증후군이 생길 수 있는데, 귀 주변 물집과 얼굴 근육 마비, 심한 경우 청력 저하까지 나타납니다. 얼굴이 마비된 후 **3일 안에 치료를 시작하면 거의 다 완치되지만, 7일이 지난 후 시작하면 22%만 완치**되었다는 연구 결과가 있어요. 또한 치료 시기를 놓치면 치매 위험이 1.3배 높아지고, 항바이러스제로 잘 치료받은 분들은 치매 위험이 25% 낮아졌다는 연구도 있습니다.$AAA$, array['대상포진치료', '72시간', '항바이러스제', '신경통', '람세이헌트']::text[], 2025, 'wRTdq73ZEEY-2', 'https://youtu.be/wRTdq73ZEEY?t=183s', null, '2025-01-08 00:00:00+00'::timestamptz, '2025-01-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$대상포진 예방접종은 효과가 얼마나 있나요?$AAQ$, $AAA$대상포진 예방접종은 50세 이상에서 권장되며, 백신을 맞으면 대상포진에 걸릴 확률을 확실히 줄일 수 있습니다. **2~6개월 간격으로 2회 접종하는 사백신**은 90% 이상의 예방 효과를 보이고, 접종 10년 후에도 80% 이상으로 예방 효과가 유지돼요. 다만 두 번 맞아야 하고 가격이 다소 비싸다는 단점이 있습니다.

예전 생백신은 1회 접종만으로 끝나 편하긴 했지만, 백신을 맞아도 10명 중 4명 정도는 대상포진에 걸렸어요. 접종 후 7년 정도 지나면 30% 정도로 예방 효과가 떨어졌습니다. 또한 **대상포진 백신이 치매 예방에도 효과가 있다는 논문**도 있어요. 그리고 백신을 맞으면 혹시 대상포진에 걸리더라도 가볍게 지나갈 수 있습니다. 젊은 층에서도 스트레스나 과로로 대상포진이 발생하므로, 50세 이상이라면 꼭 예방접종을 고려하고 평소에 충분한 영양 섭취와 규칙적인 수면이 중요합니다.$AAA$, array['대상포진백신', '사백신', '예방효과', '50세이상', '치매예방']::text[], 2025, 'wRTdq73ZEEY-3', 'https://youtu.be/wRTdq73ZEEY?t=287s', null, '2025-01-08 00:00:00+00'::timestamptz, '2025-01-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아침에도 폼클렌징으로 세안해야 하나요?$AAQ$, $AAA$아침에도 물 세안만 하기보다 폼클렌징을 사용하는 것이 좋습니다. 잠을 잘 때 베개나 이불에 묻어 있던 먼지나 노폐물이 피부에 닿고, **자는 동안 피부에서도 피지나 땀이 배출되기** 때문이에요. 이런 성분들은 기름 성분이 있어서 물만으로는 씻겨 나가지 않습니다.

다만 너무 세정력이 강한 클렌저를 반복적으로 쓰면 피부 장벽에 손상을 줄 수 있으니 아침에는 강한 제품을 쓸 필요가 없어요. **약산성 클렌저 정도면 충분**합니다. 추천된 제품은 주닥의 프로폴리스 젠틀 클렌징 폼인데, 약산성에 거품기가 달려 있어 짜면 거품이 그대로 나옵니다. 아침에 정신없을 때 거품을 따로 내지 않고 바로 씻을 수 있고 세정력이 적당하면서 사용감이 촉촉합니다. 피부 상태에 따라 클렌저를 바꿔주는 것만으로도 피부 컨디션이 많이 좋아질 수 있어요.$AAA$, array['아침세안', '폼클렌징', '약산성', '물세안', '피부장벽']::text[], 2025, '9xAhofPhJ7E-1', 'https://youtu.be/9xAhofPhJ7E?t=99s', null, '2025-01-09 00:00:00+00'::timestamptz, '2025-01-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$입술에도 자외선 차단이 필요한가요?$AAQ$, $AAA$입술도 피부이고 멜라닌 색소가 있기 때문에 자외선 차단이 꼭 필요합니다. 여름에 휴가 가서 햇빛을 많이 받으면 **입술에 잡티가 생기고 나이 들어 보일 수 있어요**. 특히 입술은 피부가 얇기 때문에 신경을 더 써줘야 합니다. 시중에 SPF 들어간 립밤이 많지 않고 있어도 5~15 정도 수치인 경우가 대부분이에요.

추천된 포레덤 비건 립 프로텍션 립밤은 **SPF 50+, PA++++로 UVB와 UVA까지 모두 차단**해 아침에 바르기 좋습니다. 유리아쥬 스틱레브르 오리지널 제품과 비교하면 포레덤 제품이 더 부드러워서 바르기가 편해요. 피부과 선생님이 만든 브랜드이기 때문에 믿고 쓸 수 있는 성분들이 들어 있습니다. 입술 라인의 색소침착이 점점 칙칙해 보이는 분들이라면 자외선 차단 성분이 들어간 립밤을 챙기시는 것이 좋아요.$AAA$, array['립밤', 'SPF립밤', '입술색소침착', '자외선차단', '입술관리']::text[], 2025, '9xAhofPhJ7E-2', 'https://youtu.be/9xAhofPhJ7E?t=259s', null, '2025-01-09 00:00:00+00'::timestamptz, '2025-01-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티날 크림은 얼마나 자주 발라야 하나요?$AAQ$, $AAA$레티날 크림은 자극감이 있기 때문에 **2~3일에 한 번 정도** 바르는 것이 좋습니다. 매일 바르면 각질이 너무 많이 올라오고 붉어지거나 따가울 수 있어요. 레티날은 레티놀의 활성 성분으로 피부 노화를 막아주고 이미 진행된 노화를 되돌려주는 효과가 있습니다.

농도는 두 가지로 나눠 쓰는 방법이 좋아요. **0.05% 같은 약한 제품은 눈가와 입가**처럼 각질이 잘 올라오는 부위에, 0.15% 같은 강한 제품은 얼굴 전체와 목에 바르는 식입니다. 0.15%를 눈가에 쓰면 각질이 많이 올라와 지저분해 보일 수 있어요. 레티날 바르고 피부가 뒤집어지면서 각질이 올라왔을 때는 마스크팩을 가끔 활용하는 것도 좋습니다. 이온토코메드 아쿠아 바이오 셀룰로오스 마스크처럼 바이오셀룰로스 소재에 진정 성분이 들어간 제품이 도움이 됩니다.$AAA$, array['레티날', '사용빈도', '농도별사용', '각질', '안티에이징']::text[], 2025, '9xAhofPhJ7E-3', 'https://youtu.be/9xAhofPhJ7E?t=506s', null, '2025-01-09 00:00:00+00'::timestamptz, '2025-01-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$메이크업 지울 때 클렌징 워터로 충분한가요?$AAQ$, $AAA$데일리 메이크업이라면 클렌징 워터로 충분히 지울 수 있지만 화장솜의 역할도 함께 작용합니다. 클렌징 워터 안에는 계면활성제가 들어 있고, 그것을 화장솜에 적셔 **물리적으로 닦아내는 과정이 함께 이루어지기** 때문이에요. 너무 두껍지 않은 데일리 화장은 가볍게 쓱쓱 잘 지워집니다.

다만 예민한 피부, 홍조 있는 피부, 민감성 피부는 닦아내는 것 자체가 자극이 될 수 있어 주의가 필요해요. 추천된 바이오더마 센시비오 H2O는 화장솜에 축축하게 적셔 닦아내면 빨리 지워지지만, 건조한 피부나 각질이 올라와 있을 때는 클렌징 밀크가 더 좋습니다. **클렌징 밀크는 예민하고 건조한 피부에 무난하게 좋은 제형**이라 클렌징 후에도 건조함 없이 촉촉해요. 피지가 많고 답답한 느낌이 들 때는 약알칼리성 클렌저가, 평소에는 약산성 클렌저가 적합하니 피부 상태에 맞춰 바꿔 쓰는 것이 효과적입니다.$AAA$, array['클렌징워터', '메이크업제거', '클렌징밀크', '피부타입별', '이중세안']::text[], 2025, '9xAhofPhJ7E-4', 'https://youtu.be/9xAhofPhJ7E?t=350s', null, '2025-01-09 00:00:00+00'::timestamptz, '2025-01-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$장벽크림에는 어떤 성분이 꼭 들어있어야 하나요?$AAQ$, $AAA$장벽크림에는 **세라마이드, 콜레스테롤, 지방산** 세 가지 성분이 모두 들어 있어야 합니다. 앞글자를 따서 '세콜지'라고 부르는데, 1970년대 피터 엘리아스 교수의 연구에서 건강한 피부와 아토피 환자 피부를 비교했을 때 아토피 환자에게 이 시멘트 성분들이 현저히 부족했고 특히 세라마이드가 부족하다는 사실이 밝혀졌어요.

중요한 건 세라마이드만 넣어서는 효과가 충분하지 않다는 점입니다. **세라마이드, 콜레스테롤, 지방산 세 가지가 조화를 이뤄야 제대로 효과**가 나옵니다. 또한 황금 비율이 있는데, 세 가지 중 하나가 다른 것보다 3배 많을 때 피부 회복 효과가 가장 좋았어요. 세라마이드 3, 콜레스테롤 1, 지방산 1처럼 어느 한 가지가 3배가 되는 비율입니다. 그리고 이 성분들이 피부 속으로 잘 전달될 수 있는 기술도 필요합니다.$AAA$, array['세라마이드', '콜레스테롤', '지방산', '장벽크림', '세콜지']::text[], 2025, 'cT3mvmpLiVY-1', 'https://youtu.be/cT3mvmpLiVY?t=108s', null, '2025-01-14 00:00:00+00'::timestamptz, '2025-01-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부 타입별로 장벽크림은 어떻게 골라야 하나요?$AAQ$, $AAA$피부 타입에 따라 세콜지의 비율을 다르게 선택하는 것이 효과적입니다. **민감성 피부에는 세라마이드가 가장 많은 제품**이 좋아 닥터디퍼런트 311 크림이나 MLE 크림, 세라마이드 아토 집중 크림이 적합해요. 311은 세라마이드 3 : 콜레스테롤 1 : 지방산 1의 비율로 피부장벽 개선 효과가 가장 좋습니다.

지성이거나 여름철에 되직한 제형이 부담스러운 분들은 **지방산이 가장 많은 113 크림이 적합**한데, 지방산 중 리놀렌산이 부족하면 모공 입구가 막혀 블랙헤드가 잘 끼기 때문이에요. 113에는 피지 조절에 도움이 되는 나이아신아마이드도 함께 들어 있습니다. 나이가 들수록 건조해지면서 탄력이 신경 쓰이는 분들은 콜레스테롤이 많은 131 크림이나 스킨수티컬즈 트리플리피드 2:4:2 크림이 좋아요. 노화된 피부에서는 콜레스테롤 합성이 현저히 감소하므로 콜레스테롤이 많을 때 장벽 개선이 잘 됩니다.$AAA$, array['피부타입별', '장벽크림선택', '민감성피부', '지성피부', '노화피부']::text[], 2025, 'cT3mvmpLiVY-2', 'https://youtu.be/cT3mvmpLiVY?t=212s', null, '2025-01-14 00:00:00+00'::timestamptz, '2025-01-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$장벽크림은 얼마나 발라야 효과가 나타나나요?$AAQ$, $AAA$장벽크림은 **최소 2주 정도** 꾸준히 발라야 차이를 느낄 수 있습니다. 하루 이틀 만에 효과가 바로 나타나지 않기 때문에 꾸준함이 가장 중요해요. 발랐을 때 피부가 더 심해지지 않고 좀 편한 느낌이 든다면 그 제품을 계속 사용해보시는 게 좋습니다.

또한 시중에 나와 있는 대부분의 보습제 중 피부 장벽에 도움이 된다고 하는 제품들을 보면 **대부분 세콜지 성분을 포함하고 있는 경우가 많아요**. 집에 갖고 있는 제품들도 검색해서 상세페이지를 확인하면 이런 성분들이 포함되어 있는 경우가 많으니 활용하셔도 됩니다. 가성비 좋은 일리윤 세라마이드 아토 집중 크림은 150ML에 1만 원대로 얼굴뿐 아니라 목, 손등, 몸 여기저기 건조하고 장벽이 깨졌을 때 듬뿍 바를 수 있어요. 본인의 피부 타입과 상태에 맞게 골라서 꾸준히 바르는 것이 핵심입니다.$AAA$, array['장벽크림효과', '꾸준한사용', '2주', '보습', '세라마이드제품']::text[], 2025, 'cT3mvmpLiVY-3', 'https://youtu.be/cT3mvmpLiVY?t=575s', null, '2025-01-14 00:00:00+00'::timestamptz, '2025-01-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리쥬란은 어떤 사람에게 효과가 좋나요?$AAQ$, $AAA$리쥬란은 **속건조가 심한 분들**에게 가장 효과가 좋습니다. 아무리 비싼 크림을 발라도 흡수가 안 되고 속당김이 계속될 때 리쥬란을 맞으면 큰 도움이 돼요. 두 번째로는 피부가 푸석푸석하고 생기가 없어 매끈매끈 좋아 보이게 하고 싶을 때 좋고, 세 번째로는 잔주름이 신경 쓰일 때입니다. 특히 눈가나 입가는 보톡스로도 잔주름 해결이 안 되는데, 그럴 때 리쥬란이 효과적이에요.

마지막으로 소개팅이나 면접처럼 중요한 일이 있어 **피부가 반짝반짝 빛났으면 좋겠을 때** 적합합니다. 실제로 강의가 잡히면 한 달 전에 리쥬란을 맞으러 오는 분들도 있어요. 반대로 피부가 극도로 예민할 때는 오히려 도움이 안 될 수 있는데, 주사 자체가 자극이 되고 마취크림 때문에 피부가 뒤집어질 수 있기 때문입니다. 이미 피부가 너무 좋은 사람이 받으면 효과를 크게 못 느낄 수 있어 돈 낭비가 될 수 있어요.$AAA$, array['리쥬란', '속건조', '잔주름', '적응증', '피부재생']::text[], 2025, 'PDU8BZCLFSs-1', 'https://youtu.be/PDU8BZCLFSs?t=150s', null, '2025-01-16 00:00:00+00'::timestamptz, '2025-01-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리쥬란은 왜 그렇게 효과가 좋은 건가요?$AAQ$, $AAA$리쥬란은 **연어 DNA에서 추출한 폴리뉴클레오타이드 성분**이 피부 재생을 촉진하기 때문에 효과가 좋습니다. 피부 재생과 회복을 시켜주는 영양 주사 같은 역할이에요. 피부가 손상되고 컨디션이 안 좋을 때 회복하려면 새로운 세포가 만들어져야 하는데, 폴리뉴클레오타이드 성분이 이 과정을 촉진시킵니다.

그것뿐만 아니라 콜라겐 재생도 시켜주고 피부 염증도 줄여주며, 히알루론산이 들어 있어 피부 속 수분 공급 역할도 해요. 이 성분을 그냥 바르면 흡수가 되지 않는데, **사이즈가 너무 커서 피부에 발라도 속으로 흡수가 하나도 안 되기 때문**입니다. 그래서 주사로 맞을 수밖에 없어요. 또한 모공이나 홍조 개선 후기가 많은 이유는 직접 개선이 아니라, 리쥬란을 맞으면 피부가 재생되며 전반적으로 건강해지니까 덤으로 얻게 되는 효과입니다. 모공이나 홍조가 주 고민이라면 그 증상에 맞는 레이저 시술이 더 효과적이에요.$AAA$, array['폴리뉴클레오타이드', '연어DNA', '피부재생', '리쥬란기전', '콜라겐']::text[], 2025, 'PDU8BZCLFSs-2', 'https://youtu.be/PDU8BZCLFSs?t=133s', null, '2025-01-16 00:00:00+00'::timestamptz, '2025-01-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리쥬란과 아이리쥬란은 어떻게 다른가요?$AAQ$, $AAA$아이리쥬란은 **눈가 전용으로 점성이 묽게 만든** 리쥬란입니다. 일반 리쥬란은 점성이 꽤 있어서 눈가에 맞으면 올록볼록한 자국이 오래 가는데, 아이리쥬란은 일반 리쥬란보다 점성이 묽어 눈가처럼 얇고 예민한 피부에 적합해요. 훨씬 더 빨리 흡수되고 붓기도 금방 빠집니다.

그래서 눈가 잔주름이나 눈 밑 피부 탄력 관리에 아이리쥬란이 효과가 좋아요. 많은 분들이 다른 얼굴 부위에는 일반 리쥬란을, **눈가에는 아이리쥬란을 함께 맞는 방식**으로 진행합니다. 통증을 줄이고 싶다면 리쥬란 HB도 선택할 수 있는데, 주사제 안에 마취 성분이 섞여 있어 통증이 덜하도록 개발된 제품이에요. 리쥬란 통증은 주사 찌를 때와 약이 끈적하게 밀고 들어갈 때 모두 강한데, 리쥬란 HB는 마취크림만 바르고도 받을 수 있을 정도로 훨씬 덜 아픕니다. 시술 주기는 보통 한 달에 1번씩 3~4번 정도가 권장됩니다.$AAA$, array['아이리쥬란', '리쥬란HB', '눈가시술', '통증감소', '점성']::text[], 2025, 'PDU8BZCLFSs-3', 'https://youtu.be/PDU8BZCLFSs?t=334s', null, '2025-01-16 00:00:00+00'::timestamptz, '2025-01-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리쥬란 시술 후 자국은 얼마나 가나요?$AAQ$, $AAA$리쥬란 시술 후 주사 자국은 **보통 일주일 정도** 티가 나며, 빠른 분은 3일 만에 괜찮아지기도 합니다. 주사 놓는 시술이라 어쩔 수 없이 자국이 남기 때문에 소개팅이나 면접처럼 중요한 일정이 있다면 시기를 잘 조절해야 해요. 일정이 임박했다면 다른 시술을 고려하는 것이 좋습니다.

시술 주기는 보통 **한 달에 1번씩 3~4번 정도** 받는 것이 권장됩니다. 피부 컨디션에 따라 그때그때 필요할 때 맞기도 해요. 시술 후 일주일 정도는 주사 자국이나 붓기가 있을 수 있으니 주의가 필요합니다. 또 여드름이나 홍조 때문에 레이저 치료를 받는 분들 중 피부 상태가 리쥬란 시술이 필요한 상태일 때는 함께 진행하면 시너지가 날 수 있어요. 헷갈리면 피부과 전문의와 상담해 지금 내 피부 상태가 리쥬란을 맞으면 효과를 볼 수 있는 상태인지 확인하는 것이 가장 좋습니다.$AAA$, array['리쥬란자국', '다운타임', '시술주기', '회복기간', '일정조절']::text[], 2025, 'PDU8BZCLFSs-4', 'https://youtu.be/PDU8BZCLFSs?t=63s', null, '2025-01-16 00:00:00+00'::timestamptz, '2025-01-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$얼굴 윤곽을 줄이는 보톡스 꿀자리는 어디인가요?$AAQ$, $AAA$얼굴 윤곽을 줄이는 보톡스 꿀자리는 침샘, 입꼬리, 자갈턱 **세 군데가 핵심**입니다. 이마, 미간, 사각턱 외에도 윤곽 라인을 깔끔하게 정리해 주는 부위가 따로 있어, 한 번 받으시면 100이면 100 다 효과를 본다고 합니다.

첫째 침샘 보톡스는 턱밑샘에 주사해 두꺼비처럼 볼록한 턱밑 라인을 정리해 줍니다. 둘째 입꼬리 보톡스는 입꼬리를 내리는 근육에 놓아 무표정일 때도 자연스럽게 살짝 올라간 미소를 만들어 줘요. 셋째 자갈턱 보톡스는 턱끝근의 과한 수축을 풀어 **필러 맞은 것처럼 턱이 앞으로 자연스럽게 나오게** 합니다. 자갈턱 보톡스는 한 번도 안 맞은 분은 있어도 한 번만 맞은 분은 없을 정도라고 합니다.$AAA$, array['보톡스꿀자리', '침샘보톡스', '입꼬리보톡스', '자갈턱보톡스', '얼굴윤곽']::text[], 2025, 'L0pu2ZMf76I-1', 'https://youtu.be/L0pu2ZMf76I?t=51s', null, '2025-01-20 00:00:00+00'::timestamptz, '2025-01-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$침샘 보톡스 맞으면 입이 마르지 않나요?$AAQ$, $AAA$침샘 보톡스 후 일상 기능에는 거의 지장이 없지만, 입마름이 생길 수 있어 물을 자주 마시면 됩니다. 우리 몸에는 침샘이 굉장히 많아 일부에 보톡스를 놓아도 다른 침샘이 침 분비를 이어가기 때문이에요.

귀밑샘은 주로 음식을 먹을 때 침을 분비하고, **턱밑샘은 쉬고 있을 때의 침 분비를 담당**해요. 그래서 턱밑샘을 과하게 건들면 입마름이나 구강건조증이 생길 수 있어 충분한 수분 섭취가 필요합니다. 침샘에 보톡스가 들어가면 침샘이 줄어들면서 튀어나온 부분도 함께 줄어, 라인이 자연스럽게 개선됩니다. 술을 좋아해서 침샘이 커진 분들도 침샘 보톡스로 얼굴이 갸름해지는 효과를 볼 수 있어요.$AAA$, array['침샘보톡스', '턱밑샘', '구강건조증', '입마름', '얼굴라인']::text[], 2025, 'L0pu2ZMf76I-2', 'https://youtu.be/L0pu2ZMf76I?t=102s', null, '2025-01-20 00:00:00+00'::timestamptz, '2025-01-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스 효과는 얼마나 지속되나요?$AAQ$, $AAA$보톡스 효과는 **4개월에서 6개월 정도** 지속되며, 6개월까지는 잘 가지 않는 편입니다. 시술 후 3~4일째 서서히 효과가 나타나기 시작해 1~2주 정도 지나면 완전히 자리를 잡습니다.

재밌는 점은 보톡스로 근육을 덜 쓰게 되면 근육이 자연스럽게 작아져 **시간이 지날수록 재시술 간격이 길어지는 경우가 많다**는 점이에요. 특히 사각턱에서 이런 변화가 흔하게 나타납니다. 효과 지속 기간은 시술 부위와 개인 근육 상태에 따라 차이가 있고, 부위마다 회복 속도가 조금씩 다르다는 점도 알아두시면 좋아요. 너무 자주 맞기보다 효과가 떨어질 때쯤 다시 맞는 패턴이 자연스럽습니다.$AAA$, array['보톡스지속기간', '재시술간격', '보톡스효과', '근육위축', '사각턱']::text[], 2025, 'L0pu2ZMf76I-3', 'https://youtu.be/L0pu2ZMf76I?t=358s', null, '2025-01-20 00:00:00+00'::timestamptz, '2025-01-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$미간 보톡스 맞고 안검하수 생기면 어떻게 해결하나요?$AAQ$, $AAA$미간 보톡스 후 안검하수가 생기면 **알파간피라는 안약**으로 일시적으로 호전시킬 수 있어요. 안약 몇 방울을 넣으면 바로 눈이 번쩍 뜨이고 약 4시간 정도 지속됩니다.

안검하수는 미간 보톡스가 안와 부위로 새어 들어가 눈꺼풀을 올리는 근육이 마비되어 생기는 부작용이에요. 시술자가 시술하지 않는 손으로 강하게 눌러 막으면서 시술하면 예방할 수 있지만, 나이가 들어 피부와 조직이 약한 분들은 조심해도 흘러 들어갈 수 있습니다. 일부러 넣은 게 아니라 흘러 들어간 것이라 **대부분은 몇 주 내로 증상이 사라져요**. 엠페이스나 조비나 같은 근육 수축 장비로 회복을 도울 수도 있습니다.$AAA$, array['미간보톡스', '안검하수', '알파간피', '보톡스부작용', '눈꺼풀처짐']::text[], 2025, 'L0pu2ZMf76I-4', 'https://youtu.be/L0pu2ZMf76I?t=458s', null, '2025-01-20 00:00:00+00'::timestamptz, '2025-01-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스 내성 걱정되면 어떤 제품을 선택해야 하나요?$AAQ$, $AAA$보톡스 내성이 걱정되면 **제오민이나 코어톡스 같은 신제품**을 선택하시는 게 좋습니다. 이 제품들은 톡신 주변에 있는 단백질을 제거하고 순수한 톡신 성분만 사용하기 때문에 내성이 덜 생깁니다.

일반적인 보툴리눔 톡신은 톡신 기능을 하는 부분과 별 기능이 없는 주변부 단백질로 구성되어 있어요. 주변 단백질에 항체가 생기면서 내성이 발생하는 경우가 많고, 내성이 생기더라도 미용적으로 효과가 없을 뿐 큰 걱정 사항은 아닙니다. 시간이 지나면서 항체가 줄어들면 다시 효과가 나타날 수도 있어요. **스킨보톡스, 사각턱, 침샘, 승모근, 종아리처럼 고용량을 맞는 부위**라면 내성이 덜 생기는 제품으로 받는 게 안전합니다.$AAA$, array['보톡스내성', '제오민', '코어톡스', '보툴리눔톡신', '신제품']::text[], 2025, 'L0pu2ZMf76I-5', 'https://youtu.be/L0pu2ZMf76I?t=587s', null, '2025-01-20 00:00:00+00'::timestamptz, '2025-01-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$단순포진(헤르페스)은 한 번 걸리면 평생 가나요?$AAQ$, $AAA$단순포진은 한 번 감염되면 바이러스가 **몸의 신경절에 평생 잠복**합니다. 피곤하거나 스트레스를 받고 면역이 저하될 때 다시 활동해 입술 수포 같은 증상을 일으키게 되는 병이에요.

헤르페스 심플렉스 바이러스가 피부와 점막에 감염을 일으켜 주로 수포가 발생하는데, 입술이 가장 흔하지만 몸 어디에라도 발생할 수 있습니다. 입술 문신 같은 미용 시술 후 재발하는 경우도 많아요. 특히 **수포가 입술 주변으로 번지면 딱지가 떨어진 뒤에도 흉터나 색소침착 가능성이 높습니다**. 전 세계적으로 성인 헤르페스 감염률은 90%에 달한다고 보고된 자료도 있고, 무증상 감염자까지 고려하면 실제 감염률은 더 높을 수 있어요.$AAA$, array['단순포진', '헤르페스', '신경절잠복', '입술수포', '색소침착']::text[], 2025, 'HmNviBaQSnU-1', 'https://youtu.be/HmNviBaQSnU?t=56s', null, '2025-01-21 00:00:00+00'::timestamptz, '2025-01-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$단순포진 치료의 골든타임은 언제인가요?$AAQ$, $AAA$단순포진 치료의 골든타임은 **수포가 올라오기 전 따끔거리는 24시간 이내**입니다. 이 시기에 병원에서 먹는 항바이러스제를 처방받으면 치료 기간과 흉터 발생 가능성을 크게 줄일 수 있어요.

수포가 생기기 전 몸 컨디션이 나빠지면서 입술이 간질간질하고 따끔거리는 전조 증상이 동반됩니다. 이미 물집이 생긴 후에는 바르는 항바이러스 연고는 효과가 거의 없고, 먹는 약도 효과가 떨어져요. 보통 물집이 생긴 뒤 딱지가 돼서 좋아지기까지 2주 정도 걸립니다. **수포가 입술 주변으로 번지면 흉터나 색소침착이 남을 가능성이 높기 때문에** 초기 24시간 대응이 정말 중요합니다.$AAA$, array['단순포진치료', '골든타임', '항바이러스제', '전조증상', '흉터예방']::text[], 2025, 'HmNviBaQSnU-2', 'https://youtu.be/HmNviBaQSnU?t=180s', null, '2025-01-21 00:00:00+00'::timestamptz, '2025-01-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$립스틱 테스터를 사용해도 안전한가요?$AAQ$, $AAA$립스틱 테스터를 입술에 직접 사용하는 것은 **헤르페스 바이러스 감염 위험**이 있어 피하시는 게 좋습니다. 화장품 매장 테스터 립스틱에서 헤르페스 바이러스 DNA가 발견됐고, 이 바이러스가 립스틱 안에서 최대 일주일까지 살아있었다는 연구도 있어요.

2017년 미국의 한 여성은 테스터 제품을 입술에 사용한 뒤 2,800만 원 소송을 걸기도 했습니다. 손등 테스트는 입술 점막보다는 낫지만 그것도 추천하지 않아요. **한국 주요 화장품 매장 조사에서 대장균, 폐렴균, 황색포도상구균까지 발견된 사례**가 있기 때문입니다. 발색을 확인하고 싶다면 피부보다는 매장에 비치된 티슈나 면봉에 발라 색을 보는 방식이 안전합니다.$AAA$, array['립스틱테스터', '헤르페스감염', '화장품위생', '황색포도상구균', '면봉테스트']::text[], 2025, 'HmNviBaQSnU-3', 'https://youtu.be/HmNviBaQSnU?t=263s', null, '2025-01-21 00:00:00+00'::timestamptz, '2025-01-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아토피 환자가 단순포진에 걸리면 더 위험한가요?$AAQ$, $AAA$아토피처럼 **피부 장벽이 손상된 분은 단순포진이 전신 증상으로 번질 수 있어** 특히 주의해야 합니다. 이를 포진상 습진이라고 하며, 일반적인 국소 감염을 넘어 넓은 부위로 퍼지는 형태로 나타나요.

수포, 농포, 딱지가 넓게 퍼지면서 발열, 가려움, 설사, 임파선 비대 등이 동반될 수 있고, **눈에 감염되면 각막염이나 결막염이 발생하고 심하면 시력 저하까지** 올 수 있습니다. 아토피나 습진이 있다면 더욱 조심하고 눈 주변에 증상이 나타나면 바로 안과를 방문하셔야 해요. 입술에 수포가 생겼을 땐 음식은 개인 접시에 덜어 먹고 수건도 따로 쓰며 뽀뽀는 잠시 참는 것이 가족 내 전염을 막는 기본 수칙입니다.$AAA$, array['포진상습진', '아토피헤르페스', '전신감염', '각막염', '시력저하']::text[], 2025, 'HmNviBaQSnU-4', 'https://youtu.be/HmNviBaQSnU?t=143s', null, '2025-01-21 00:00:00+00'::timestamptz, '2025-01-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$내 피부 타입은 어떻게 알 수 있나요?$AAQ$, $AAA$피부 타입은 **세안 후 2시간 동안 아무것도 바르지 않고 관찰**하면 스스로 판단할 수 있습니다. 피부과 진료실에서 일방적으로 알려주는 게 아니라 본인이 평소 피부 상태를 잘 관찰해야 정확하게 알 수 있어요.

2시간 후 굉장히 당기고 각질이 일어나면 건성이며, 건성은 2시간을 못 버티고 씻자마자 바로 건조해지기 시작합니다. 얼굴 전체가 기름지고 번들거리면 지성, 볼은 괜찮은데 T존만 기름이 돌면 복합성이에요. 전체적으로 당기지만 기름도 도는 경우는 흔히 말하는 **수분 부족형 지성 피부**입니다. 여기에 화장품을 바꾸거나 환경이 변할 때 잘 뒤집어진다면 민감성을 더해 판단하면 되고, 계절이나 컨디션에 따라 피부 타입은 변할 수 있다는 점도 알아두세요.$AAA$, array['피부타입', '건성지성', '복합성피부', '민감성피부', '수분부족형지성']::text[], 2025, 'jDiAZpv8jg4-1', 'https://youtu.be/jDiAZpv8jg4?t=51s', null, '2025-01-23 00:00:00+00'::timestamptz, '2025-01-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스킨케어 바르는 순서가 정해져 있나요?$AAQ$, $AAA$스킨케어는 **가장 묽은 제형부터 되직한 제형 순으로** 바르는 게 기본 규칙입니다. 보통 토너 → 세럼·에센스 → 로션 → 크림 → 밤 순으로 바르며, 이는 특정 성분 종류가 아닌 제형의 점도 기준이에요.

되직한 제품을 먼저 바르면 피부에 막이 형성되어 다음 제품의 흡수가 잘 안 되기 때문입니다. 다만 **꼭 5~6가지를 다 챙겨 바를 필요는 없고**, 본인 피부에 맞게 최소한의 가짓수로 조절하면 됩니다. 토너 하나만 발라도 편안하면 그것만 써도 되고, 로션만으로 부족하면 크림을 추가하는 식으로 본인 상태에 맞추세요. 너무 많은 가짓수를 챙기기보다 발랐을 때 피부가 편안하고 트러블이 나지 않는 조합을 찾는 게 더 중요합니다.$AAA$, array['스킨케어순서', '제형순서', '토너세럼', '보습제', '레이어링']::text[], 2025, 'jDiAZpv8jg4-2', 'https://youtu.be/jDiAZpv8jg4?t=189s', null, '2025-01-23 00:00:00+00'::timestamptz, '2025-01-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C랑 레티놀 같이 발라도 되나요?$AAQ$, $AAA$비타민C와 레티놀은 **상극은 아니지만 자극이 합쳐져 따가울 수 있어** 주의가 필요합니다. 화장품은 약품이 아니라서 절대 같이 쓰면 안 되는 조합은 없지만, 단독으로도 자극을 줄 수 있는 성분끼리 겹치면 자극감이 심해질 수 있어요.

비타민C, 레티놀, 레티날, AHA, BHA 같은 산 성분은 모두 단독으로도 자극을 줄 수 있는 성분입니다. 피부 컨디션이 좋고 익숙해진 분은 같이 발라도 문제없지만, **건조하거나 컨디션이 떨어지면 둘 중 하나만 발라도 따가울 수 있어요**. 민감하거나 예민한 피부가 두 가지 모두 발랐을 때 뒤집어지면 시간을 띄워 바르는 게 좋습니다. 하나는 아침 하나는 저녁, 또는 월·수·금과 화·목·토로 나눠 격일로 사용하는 방식이 안전해요.$AAA$, array['비타민C레티놀', '성분조합', 'AHABHA', '자극화장품', '교차사용']::text[], 2025, 'jDiAZpv8jg4-3', 'https://youtu.be/jDiAZpv8jg4?t=357s', null, '2025-01-23 00:00:00+00'::timestamptz, '2025-01-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$화장품이 때처럼 밀리는 이유는 무엇인가요?$AAQ$, $AAA$화장품이 때처럼 밀리는 건 **제품 간 성분이 맞지 않거나 흡수 시간이 부족할 때** 주로 발생합니다. 피부에 해를 주는 건 아니지만 좋은 성분이 잘 흡수되지 않는 신호이므로 원인을 찾아 해결하는 게 좋아요.

첫째, 실리콘 베이스와 수분 베이스처럼 성분이 안 맞는 제품을 연달아 바르면 두 제품이 반응해 뭉칠 수 있어요. 둘째, 레이어링할 때 흡수 시간이 짧으면 뭉침이 생기므로 **처음 바르고 1~2분 정도 잘 흡수시킨 다음 다음 제품을 발라 보세요**. 셋째, 한 번에 너무 많은 양을 바르면 뭉칠 수 있어 양 조절이 필요합니다. 넷째, 피부에 각질이 많으면 각질이 같이 밀리면서 때처럼 보일 수 있어 각질 상태도 점검해 보세요.$AAA$, array['화장품뭉침', '때처럼밀림', '흡수시간', '레이어링', '각질']::text[], 2025, 'jDiAZpv8jg4-4', 'https://youtu.be/jDiAZpv8jg4?t=455s', null, '2025-01-23 00:00:00+00'::timestamptz, '2025-01-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부 다크닝 개선에 가장 효과 좋았던 화장품은 무엇인가요?$AAQ$, $AAA$피부 다크닝 개선에 가장 효과가 좋았던 건 **비타민C 제품**이라고 합니다. 임신 후 칙칙해진 피부에 여러 가지를 시도해 본 결과, 두껍고 모공 넓은 지성 피부에서도 유일하게 톤을 화사하게 바꿔준 제품이었어요.

다른 기능성 화장품은 오히려 번들거리고 트러블이 올라와 피부가 더 안 좋아 보이게 했지만, 비타민C 제품과 보습제만 발랐더니 **피부톤이 화사해지고 피부결이 매끈해지는 효과**를 느꼈다고 합니다. 다만 처음에는 따가울 수 있어 소량으로 발라보거나 보습제와 섞어 발라 자극을 줄여 시작하는 게 좋아요. 적응되면 제대로 양을 늘려가는 방식을 권합니다. 한 두 번으로 타고난 피부색을 바꿀 수는 없고 꾸준한 사용이 핵심이에요.$AAA$, array['비타민C', '피부다크닝', '피부톤개선', '화이트닝', '지성피부']::text[], 2025, 'HFZyhJjGGT4-1', 'https://youtu.be/HFZyhJjGGT4?t=72s', null, '2025-01-24 00:00:00+00'::timestamptz, '2025-01-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$미백 주사는 어떻게 피부를 맑게 해주나요?$AAQ$, $AAA$미백 주사는 **글루타치온과 비타민C의 항산화 작용**으로 피부를 맑게 해줍니다. 백옥 주사, 신데렐라 주사 같은 다양한 이름의 미백 주사가 있지만, 주성분은 공통적으로 글루타치온과 비타민C예요.

이 두 성분은 항산화물질로, 체내로 주입했을 때 **멜라닌 색소 생성을 억제하고 나쁜 활성산소와 노폐물 제거를 도와 피부를 맑게** 만들어 줍니다. 즉 색소를 직접 없애는 것이 아니라 색소 생성 자체를 줄이고 항산화로 피부 환경을 개선하는 방식이에요. 미백 주사에 어떤 추가 성분을 섞느냐에 따라 세부 이름과 효과 강조점이 달라집니다. 한 번에 효과를 보긴 어렵고 꾸준히 받아 피부 환경을 누적적으로 개선해야 톤이 점차 밝아져요.$AAA$, array['미백주사', '글루타치온', '비타민C', '항산화', '멜라닌억제']::text[], 2025, 'HFZyhJjGGT4-2', 'https://youtu.be/HFZyhJjGGT4?t=284s', null, '2025-01-24 00:00:00+00'::timestamptz, '2025-01-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$선크림은 얼마나 자주 덧발라야 하나요?$AAQ$, $AAA$선크림은 보통 바르고 **2~3시간이 지나면 다 지워져** 효과가 사라지므로 자주 덧발라야 합니다. 야외 활동 시에는 한 번 바르고 끝내는 것이 아니라 꾸준히 덧바르는 게 정말 중요해요.

얼굴 한 면을 제대로 보호하려면 **손가락 한 마디를 가득 채워서 바르는 양**이 필요하고, 이 정도는 발라야 표시된 차단 효과를 볼 수 있습니다. 실내라면 크게 상관없지만 여름철 야외 활동을 한다면 계속 덧발라 주시고, 물놀이 때는 워터프루프 선크림을 지속적으로 덧발라야 해요. 미백 시술이나 화장품을 아무리 사용해도 자외선을 차단하지 못하면 결국 효과가 무력화됩니다. 미백 관리의 기본은 자외선 차단이라는 점을 꼭 기억해 주세요.$AAA$, array['선크림', '자외선차단', '덧바르기', '워터프루프', '손가락한마디']::text[], 2025, 'HFZyhJjGGT4-3', 'https://youtu.be/HFZyhJjGGT4?t=475s', null, '2025-01-24 00:00:00+00'::timestamptz, '2025-01-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성 피부 미백 관리에 압출 스케일링이 효과적인가요?$AAQ$, $AAA$지성 피부 미백 관리에는 **압출 스케일링이 가성비와 효과 모두 뛰어난 시술**입니다. 울쎄라, 써마지, 리쥬란 같은 비싼 시술도 좋지만, 가격과 시간을 절약하면서도 피부톤 개선에 효과 좋은 관리가 압출 스케일링이에요.

모공 속 피지를 빼주고 묵은 각질을 걷어주는 것만으로도 피부톤이 밝아지고 피부결이 매끄러워집니다. 피부가 하얀 것도 중요하지만 **피부의 붉은기와 어두운기를 걷어주는 것도 톤 개선에 꽤 중요한 역할**을 해요. 여기에 비타민A 성분인 레티날 크림이나 디페린 연고를 병행하면 피부톤 균일화에 도움이 됩니다. 한 달 정도 디페린을 발라본 결과 아침 세안 시 피부가 보들보들해지고 유분이 잡히는 느낌이 들었다고 해요.$AAA$, array['압출스케일링', '지성피부관리', '피지각질', '레티날', '디페린']::text[], 2025, 'HFZyhJjGGT4-4', 'https://youtu.be/HFZyhJjGGT4?t=200s', null, '2025-01-24 00:00:00+00'::timestamptz, '2025-01-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아침 세안은 물세안만 해도 충분한가요?$AAQ$, $AAA$아침에도 클렌저를 사용한 세안이 필요합니다. 잠자는 동안 베개와 이불에 묻은 먼지·노폐물이 얼굴에 닿고, **피부에서도 피지와 땀이 배출**되기 때문에 물로만 씻어내기는 어려워요.

이런 분비물들은 기름 성분이라 물로만 헹궈서는 깨끗하게 씻기지 않습니다. 그래서 적당한 클렌저를 써서 세안하는 게 좋아요. 다만 아침에는 너무 강한 세안제까지 쓸 필요는 없고 **순한 약산성 폼클렌저 정도면 충분합니다**. 강한 세정력 클렌저는 오히려 피부 장벽을 약하게 만들 수 있어 본인 피부 타입을 고려해 골라야 합니다. 민감하거나 건조한 분이 너무 세정력이 강한 제품을 쓰면 장벽 손상으로 이어질 수 있어요.$AAA$, array['아침세안', '약산성폼클렌저', '물세안', '피지노폐물', '피부장벽']::text[], 2025, 'WN957NjRQ8I-1', 'https://youtu.be/WN957NjRQ8I?t=44s', null, '2025-01-27 00:00:00+00'::timestamptz, '2025-01-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$선크림 바른 날 이중세안을 꼭 해야 하나요?$AAQ$, $AAA$선크림 이중세안 필요 여부는 **본인이 쓰는 자외선 차단제 타입에 따라 달라집니다**. 모든 선크림이 이중세안을 요구하지는 않으므로 한 번씩 테스트해 보고 결정하시면 돼요.

바르고 있는 선크림을 손등에 발라본 뒤 사용 중인 폼클렌저로 클렌징해 보세요. 겉으로는 잘 씻긴 것 같아도 **자세히 보면 주름 사이사이로 선크림이 남아 있는 게 보이면** 폼클렌저만으로는 부족한 상태입니다. 이때는 클렌징 오일이나 밀크로 1차 세안을 한 다음 폼클렌저로 2차 세안을 해야 해요. 반대로 이지워시 타입이거나 물리적 차단제가 없고 오일리하지 않은 선크림이라면 폼클렌저 한 번만으로도 충분히 깨끗하게 씻길 수 있습니다.$AAA$, array['이중세안', '선크림클렌징', '클렌징오일', '이지워시선크림', '1차세안']::text[], 2025, 'WN957NjRQ8I-2', 'https://youtu.be/WN957NjRQ8I?t=107s', null, '2025-01-27 00:00:00+00'::timestamptz, '2025-01-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$코 모공 속 흰색 피지는 어떻게 관리해야 하나요?$AAQ$, $AAA$코 모공 속 흰색 피지는 정상적인 현상이며 **무조건 빼주는 게 답은 아닙니다**. T존 부위는 피지샘이 발달해 배출되는 피지가 많고, 그 통로인 모공도 자연스럽게 넓어질 수밖에 없어요.

코팩이나 모공 브러쉬를 쓰면 일시적으로 깨끗하고 매끈해진 느낌이 들지만 **시간이 지나면 다시 피지가 분비되어 모공에 차게 됩니다**. 반복적으로 강하게 빼내면 피부 자극으로 이어져 오히려 안 좋을 수 있어요. 모공이 너무 크거나 피지가 정말 보기 싫을 정도라면 피지를 줄여주는 화장품을 쓰거나, 그래도 해결이 안 되면 코쪽 피지샘 크기를 줄여주는 레이저 시술을 고려할 수 있습니다. 과도하게 씻어내는 건 좋지 않다는 점이 핵심이에요.$AAA$, array['코모공', '피지관리', 'T존피지샘', '코팩', '피지샘레이저']::text[], 2025, 'WN957NjRQ8I-3', 'https://youtu.be/WN957NjRQ8I?t=239s', null, '2025-01-27 00:00:00+00'::timestamptz, '2025-01-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$약알칼리성 클렌저 사용 후 토너를 꼭 발라야 하나요?$AAQ$, $AAA$약알칼리성 클렌저 후 토너를 반드시 바를 필요는 없습니다. **사용 후에도 피부는 약 15분이면 원래의 약산성 pH로 회복**되기 때문에, pH 보정용으로 토너를 바를 필요는 없어요.

우리 피부에는 pH를 회복하는 능력이 있고, 요즘 클렌징 제품들은 피부 자극을 최소화하도록 잘 만들어져 있어 일시적인 알칼리화는 큰 문제가 되지 않아요. 다만 클렌징폼 선택은 중요한데, 민감하거나 건조한 피부가 너무 세정력이 강한 클렌저를 쓰면 피부 장벽이 약해질 수 있습니다. 토너도 pH에 너무 연연하기보다 **피부 고민에 맞는 제품을 골라 쓰면 됩니다**. 건조하면 수분 토너를, 지성이고 피지 고민이면 피지 조절 토너를 선택하면 되고 필요 없다면 안 발라도 됩니다.$AAA$, array['약알칼리성클렌저', '토너', '피부pH', '약산성회복', '클렌징폼선택']::text[], 2025, 'WN957NjRQ8I-4', 'https://youtu.be/WN957NjRQ8I?t=335s', null, '2025-01-27 00:00:00+00'::timestamptz, '2025-01-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스컬트라와 필러는 어떻게 다른가요?$AAQ$, $AAA$스컬트라와 필러는 **볼륨을 만드는 원리 자체가 전혀 다른 시술**입니다. 필러는 젤리 같은 덩어리를 직접 넣어 즉시 볼륨을 만들지만, 스컬트라는 우리 몸이 스스로 콜라겐을 만들어 볼륨을 채우도록 유도해요.

쉽게 말하면 스컬트라는 콜라겐 씨앗을 피부에 심는 개념입니다. 필러는 다이나믹하게 볼륨이 바로 생기길 원하거나, 사고 등으로 국소적으로 패인 부분을 정확한 양으로 채워 모양을 만드는 데 적합해요. 반면 **스컬트라는 앞볼·뒷볼처럼 넓은 부위를 자연스럽게 채우거나 이물감 거부감이 있는 분에게 적합**합니다. 콜라겐 생성을 통해 자연스럽게 볼륨이 차오르면서 피부 자체에도 윤기와 생기가 도는 부가 효과까지 함께 얻을 수 있어요.$AAA$, array['스컬트라', '필러', '콜라겐생성', '볼륨시술', 'PLLA']::text[], 2025, 'ohLthnwZ4XQ-1', 'https://youtu.be/ohLthnwZ4XQ?t=67s', null, '2025-01-31 00:00:00+00'::timestamptz, '2025-01-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스컬트라 결절 부작용은 왜 생기나요?$AAQ$, $AAA$스컬트라 결절은 **가루를 생리식염수로 녹이는 수화 과정에서 가루가 한쪽에 뭉치면서** 과한 염증 반응이 일어나 생깁니다. 초반에는 희석 비율과 골고루 녹이는 방법이 표준화되지 않아 결절 사례가 있었지만, 요즘은 거의 발생하지 않아요.

스컬트라는 가루 형태이며 우리 몸 성분과 비슷한 생리식염수에 녹여 주사하는데 이 과정이 수화입니다. 현재는 **희석 비율이 표준화되어 안전성이 크게 높아졌고** 결절 부작용은 거의 없다고 봐도 됩니다. 다만 희석만 잘 시킨다고 끝이 아니라, 시술자가 한 군데에 많이 넣지 않고 여러 층과 여러 방면으로 소량씩 나눠 주입하는 게 중요해요. 환자도 5-5-5 룰, 즉 5일 동안 하루 5번 5분씩 마사지해 주면 결절 예방에 도움이 됩니다.$AAA$, array['스컬트라결절', '수화과정', '희석비율', '5-5-5룰', 'PLLA안전성']::text[], 2025, 'ohLthnwZ4XQ-2', 'https://youtu.be/ohLthnwZ4XQ?t=222s', null, '2025-01-31 00:00:00+00'::timestamptz, '2025-01-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스컬트라 효과는 언제부터 느낄 수 있나요?$AAQ$, $AAA$스컬트라 효과는 **2~3주부터 콜라겐이 생성되기 시작해 2~3개월 뒤에 확연히** 느낄 수 있습니다. 필러처럼 즉시 볼륨이 생기는 시술이 아니라 시간이 필요한 시술이에요.

시술 직후에는 수화 과정에 사용된 생리식염수 때문에 일시적으로 볼륨이 보이지만 **2~3일이면 식염수가 흡수되며 볼륨이 다 꺼져버려요**. 일주일 뒤에는 원래대로 돌아온 느낌이 들 수 있지만 이는 자연스러운 과정입니다. 보통 4주 간격으로 3회 시행하며, 시술이 누적되면서 콜라겐 생성이 점점 늘어 최종적으로 6개월 정도 뒤에 자연스러운 볼륨감을 완성하게 됩니다. 한 번 채워진 볼륨은 우리 몸이 직접 만든 콜라겐이라 보통 2~3년 정도 효과가 지속돼요.$AAA$, array['스컬트라효과시점', '콜라겐생성기간', '지속기간', '3회시술', '수화']::text[], 2025, 'ohLthnwZ4XQ-3', 'https://youtu.be/ohLthnwZ4XQ?t=347s', null, '2025-01-31 00:00:00+00'::timestamptz, '2025-01-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스컬트라 시술의 통증과 회복 기간은 어떤가요?$AAQ$, $AAA$스컬트라 시술 통증은 **국소마취 주사를 놓을 때 한 번 따끔한 정도**이며 이후로는 거의 통증이 없습니다. 바늘로 콕콕 찔러 넣는 게 아니라 끝이 뭉뚝하고 긴 캐뉼라를 통해 한 포인트에서 넓은 범위로 뿌리는 방식이에요.

볼륨을 채우려는 부위 양쪽으로 한 포인트씩 구멍을 뚫는 국소마취가 따끔한 한 순간이고, 그 후 캐뉼라가 들어가 스컬트라를 주입할 때는 다소 불편한 느낌은 있어도 통증이 계속되진 않습니다. **시술 후 한두 군데 멍이 살짝 들 수 있지만 2~3일이면 거의 없어져** 일상생활에 지장이 없어요. 다만 스컬트라는 수화에 2~3일이 걸리므로 시술 당일 바로 받을 수 없고, 미리 상담 후 예약을 잡아야 합니다.$AAA$, array['스컬트라통증', '캐뉼라', '국소마취', '다운타임', '수화기간']::text[], 2025, 'ohLthnwZ4XQ-4', 'https://youtu.be/ohLthnwZ4XQ?t=432s', null, '2025-01-31 00:00:00+00'::timestamptz, '2025-01-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리프팅을 받다가 안 받으면 더 처지나요?$AAQ$, $AAA$리프팅을 받다가 안 받으면 더 처진다는 건 **오해이며 실제로는 자연스러운 노화 과정**입니다. 리프팅 시술의 효과가 영원히 유지되는 것이 아니라, 시술 후에도 피부는 천천히 노화가 진행되기 때문이에요.

리프팅 후 시간이 흘러 처짐이 보이면 받기 전보다 더 늙은 느낌이 들 수 있지만, **그거라도 안 했으면 더 가속 노화를 했을 것**이라는 의미로 받아들여야 합니다. 피부과 기계 리프팅들은 세월을 10년·20년 거스르는 게 아니라 지금 모습에서 좀 더 천천히 늙도록 도와주는 시술이에요. 그래서 한 번으로 끝내는 것이 아니라 꾸준한 치료와 홈케어가 함께 가야 효과가 누적적으로 유지됩니다. 시술 후에도 노화가 멈추는 것은 아니라는 점을 이해해 주세요.$AAA$, array['리프팅중단', '급노화오해', '꾸준한관리', '안티에이징', '홈케어']::text[], 2025, '7ZAB6oEn6s8-1', 'https://youtu.be/7ZAB6oEn6s8?t=38s', null, '2025-02-04 00:00:00+00'::timestamptz, '2025-02-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스 내성이 생기면 어떻게 해야 하나요?$AAQ$, $AAA$보톡스 내성이 진짜로 생겼다면 **현재로서는 내성이 사라지길 기다리는 것 외에는 방법이 없습니다**. 다만 효과 없음을 내성으로 오해하는 경우가 많아 먼저 용량이 부족하지 않은지 점검해야 해요.

보톡스 내성은 실제로는 굉장히 드물고, 효과가 없는 것 같은 분 대부분은 **용량이 부족한 경우**가 가장 많습니다. 리터치를 해주거나 충분한 용량을 놔주면 다시 효과를 보는 경우가 많아요. 외국에서는 보툴리눔 톡신 타입 B를 사용해 볼 수 있지만, 우리나라에는 타입 B가 유통되지 않아 선택지가 없습니다. 내성 예방을 위해 시술 간격을 너무 좁히지 말고, **제오민이나 코어톡스처럼 내성을 줄여주는 제품**을 선택하는 것이 도움이 됩니다.$AAA$, array['보톡스내성', '용량부족', '타입B', '제오민코어톡스', '시술간격']::text[], 2025, '7ZAB6oEn6s8-2', 'https://youtu.be/7ZAB6oEn6s8?t=196s', null, '2025-02-04 00:00:00+00'::timestamptz, '2025-02-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지는 600샷이 600샷보다 효과가 좋나요?$AAQ$, $AAA$써마지 샷수는 **나눠서 여러 번 하는 것보다 한 번에 충분한 에너지를 주는 게 효과 면에서 더 낫다**고 봅니다. 다만 뚜렷한 논문 근거가 있는 건 아니라 선생님마다 의견은 다를 수 있어요.

써마지는 진피층에 열을 줘 효과를 내는데, 마치 물을 끓일 때 3분 동안 계속 끓이는 것과 **1분 끓이고 쉬고 1분 끓이는 것의 차이처럼 누적 에너지가 같아도 결과가 달라질 수 있다**는 원리입니다. 우리나라에서는 600샷이 가장 유명하지만 외국에서는 900샷이 더 선호된다고 들었다고 해요. 다만 사람 얼굴 크기, 처진 정도, 사용 장비에 따라 적정 샷수가 달라지므로 일률적인 정답은 없고 개인차가 있는 부분이라 정설로 받아들이지는 마세요.$AAA$, array['써마지샷수', '300샷600샷', '고주파리프팅', '에너지누적', '리프팅효과']::text[], 2025, '7ZAB6oEn6s8-3', 'https://youtu.be/7ZAB6oEn6s8?t=291s', null, '2025-02-04 00:00:00+00'::timestamptz, '2025-02-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리프팅 시술 후 케어는 어떤 게 가장 중요한가요?$AAQ$, $AAA$리프팅 시술 후 케어에서 **가장 중요한 것은 자외선 차단**입니다. 시술 후 햇빛을 가리지 않으면 효과가 무의미해질 정도로 중요해, 환자분들에게도 강조하는 부분이에요.

첫째 자외선 차단은 시술 받은 효과를 지키는 기본이고, **시술 받고 햇빛을 안 가리면 돈을 다 버리는 셈**입니다. 둘째로 안티에이징 효과를 더 오래 유지하고 싶다면 도움이 되는 화장품을 발라주는 게 좋아요. 꾸준히 비타민C, 레티놀, 레티날 같은 성분을 발라주면 효과 유지에 도움이 되고, 항산화 효과가 있는 비타민을 챙겨 먹는 것도 함께 권합니다. 시술 자체만큼이나 시술 후 일상에서 자외선과 안티에이징 성분 관리를 챙기는 것이 효과를 오래 가져가는 비결입니다.$AAA$, array['리프팅후관리', '자외선차단', '안티에이징화장품', '비타민C레티놀', '항산화']::text[], 2025, '7ZAB6oEn6s8-4', 'https://youtu.be/7ZAB6oEn6s8?t=384s', null, '2025-02-04 00:00:00+00'::timestamptz, '2025-02-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$팔자주름은 보톡스로 펴지나요?$AAQ$, $AAA$**일반적인 깊은 팔자주름은 보톡스로 펴지지 않습니다**. 보톡스는 근육이 움직일 때 생기는 표정 주름을 풀어주는 시술인데, 팔자주름은 표정 근육이 아닌 다른 원인으로 생기기 때문이에요.

팔자주름의 원인은 두 가지입니다. 첫째는 주름이 깊어지는 것, 둘째는 그 부위 살이 내려오는 처짐이에요. **꺼짐 때문에 팔자주름이 깊어진 분은 필러, 스컬트라, 쥬베룩 같은 볼륨 시술로 채워야** 하고, 볼살 처짐으로 생긴 팔자주름은 울쎄라, 슈링크, 실리프팅으로 처진 부분을 올려야 옅어집니다. 다만 얇은 잔주름 정도라면 스킨보톡스를 살짝 놓을 수는 있지만, 깊은 팔자주름에는 효과가 없으므로 원인에 맞는 시술을 선택해야 해요.$AAA$, array['팔자주름', '보톡스한계', '볼륨시술', '처짐리프팅', '스킨보톡스']::text[], 2025, '7ZAB6oEn6s8-5', 'https://youtu.be/7ZAB6oEn6s8?t=521s', null, '2025-02-04 00:00:00+00'::timestamptz, '2025-02-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$넘어져서 상처났을 때 빨간약은 계속 발라도 되나요?$AAQ$, $AAA$포비돈 빨간약은 다친 후 **최초 1회만** 소독용으로 쓰는 것이 좋습니다. 포비돈은 세균을 잘 죽이는 강력한 소독약이라 수술 전이나 길에서 넘어져 감염 위험이 있는 첫 처치에는 유용하지만, 매일 밴드를 갈 때마다 계속 발라주면 안 됩니다.

빨간약을 반복해서 바르면 **세균만 죽이는 게 아니라 피부를 재생시키려 일하는 피부 세포까지 파괴해, 오히려 아무는 시간이 더 길어집니다**. 또 포비돈은 피부에 갈색으로 착색되어 염증이나 이물질 확인이 어려워지므로, 바른 다음에는 생리식염수로 한 번 닦아 주는 편이 좋아요. 과산화수소수 역시 처음 피를 닦아낼 때만 쓰고, 이후 계속 사용하면 회복이 늦어질 수 있습니다. 소독약이 없으면 흐르는 수돗물에 충분히 씻어 주시면 됩니다.$AAA$, array['포비돈소독', '빨간약상처관리', '상처소독법', '피부재생', '생리식염수세척']::text[], 2025, 'BZ4T5UM-EFY-1', 'https://youtu.be/BZ4T5UM-EFY?t=99s', null, '2025-02-06 00:00:00+00'::timestamptz, '2025-02-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$마데카솔과 에스로반은 어떻게 다른가요?$AAQ$, $AAA$에스로반은 항생제 단독 연고이고 마데카솔은 항생제와 병풀추출물이 함께 든 복합제재라는 점에서 본질적으로 다른 연고입니다. 균을 죽이는 효과는 항생제만 든 연고가 더 강력해서 **소독 직후 감염이 우려되는 상처에는 에스로반이 우선**입니다. 후시딘도 같은 항생제 단독 연고지만 내성균이 많아 잘 듣지 않는 경우가 있어 에스로반이 더 권유됩니다.

반면 마데카솔에 든 병풀추출물은 콜라겐 합성을 촉진해 피부 재생을 돕기 때문에 **감염 위험이 없는 살짝 베이거나 까진 깊지 않은 상처에 적합한 재생 연고에 가깝습니다**. 사용 빈도도 달라요. 에스로반 같은 항생제 연고는 하루 2~3회, 마데카솔 같은 재생 연고는 하루 3~4회로 좀 더 자주 발라 주시면 됩니다. 무피로신 성분의 같은 계열로는 박테로신, 베아로반, 박트로반, 닥터로반 등이 있습니다.$AAA$, array['에스로반', '마데카솔', '항생제연고', '병풀추출물', '무피로신']::text[], 2025, 'BZ4T5UM-EFY-2', 'https://youtu.be/BZ4T5UM-EFY?t=189s', null, '2025-02-06 00:00:00+00'::timestamptz, '2025-02-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$상처에 딱지가 생기면 빨리 낫나요?$AAQ$, $AAA$상처에 딱지가 생기면 오히려 치료가 더 느려지고 흉터도 더 잘 남습니다. 딱지는 상처에서 나오는 진물이나 피가 마르면서 생기는 껍질인데, **진물 안에 있는 상처 치유 물질들이 딱딱하게 굳어 회복을 방해**해요. 또 딱지가 있으면 그 아래로 새살이 올라오는 게 더뎌서, 잘 안 낫는 상처는 병원에서 일부러 딱지를 뜯어내기도 합니다.

딱지를 막으려면 상처가 마르지 않게 위를 덮어 주는 드레싱이 필요합니다. **드레싱으로 습윤한 상태를 유지하면 세포 성장이 원활해져 상처가 빠르게 아뭅니다**. 많이 쓰이는 드레싱은 세 가지로, 거즈는 팔목이나 손가락 같이 움직임이 많은 부위에, 메디폼은 진물이 많이 나올 때, 듀오덤은 작은 상처나 진물이 줄어드는 단계에 적합해요. 거즈와 메디폼은 하루 한 번, 듀오덤은 하얗게 변하면 갈아 주시면 됩니다.$AAA$, array['딱지', '습윤드레싱', '거즈', '메디폼', '듀오덤']::text[], 2025, 'BZ4T5UM-EFY-3', 'https://youtu.be/BZ4T5UM-EFY?t=278s', null, '2025-02-06 00:00:00+00'::timestamptz, '2025-02-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$흉터 연고는 양파추출물과 실리콘 중 무엇을 골라야 하나요?$AAQ$, $AAA$패이거나 붉은기가 심한 흉터에는 양파추출물 연고, 튀어나오는 봉합·켈로이드 흉터에는 실리콘 연고가 적합합니다. 양파추출물과 해파린이 든 콘투락투벡스겔, 노스카나겔 같은 제품은 **흉터를 부드럽게 만들고 붉은기를 빼주는 효과**가 있어요. 노스카나겔은 양파추출물 양이 좀 더 적은 대신 판테놀이 들어 있어 상처 초기에 좋습니다.

실리콘 연고는 흉터 부위를 보호하면서 편평하게 만들어 주는 역할을 합니다. 한 연구에서 **두 달간 실리콘 젤을 바른 부위가 바르지 않은 곳보다 흉터가 훨씬 연해진 결과**가 확인되었습니다. 두 가지를 같이 바르셔도 좋고, 양파추출물 연고는 하루 3~4회 마사지하듯 흡수시키고 실리콘 연고는 하루 3~4회 덧바르듯 도포하면 됩니다. 흉터 치료는 상처가 생기고 2개월 이내가 골든타임이고, 최소 2~3개월은 꾸준히 발라 주셔야 합니다.$AAA$, array['양파추출물연고', '실리콘젤', '콘투락투벡스겔', '켈로이드흉터', '흉터골든타임']::text[], 2025, 'BZ4T5UM-EFY-4', 'https://youtu.be/BZ4T5UM-EFY?t=482s', null, '2025-02-06 00:00:00+00'::timestamptz, '2025-02-06 00:00:00+00'::timestamptz);
